export const collection_BaseCollectionSource = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/collection/base-collection-source.json",
  "title": "Base Collection Source",
  "description": "A source of collections for a collection list. Supports three selection patterns: distribution identifiers (cross-publisher), publisher-specific collection IDs, or publisher-specific genres.",
  "discriminator": {
    "propertyName": "selection_type"
  },
  "oneOf": [
    {
      "type": "object",
      "title": "Distribution IDs Source",
      "description": "Select collections by platform-independent distribution identifiers. The primary mechanism for cross-publisher collection matching.",
      "properties": {
        "selection_type": {
          "type": "string",
          "const": "distribution_ids",
          "description": "Discriminator indicating selection by platform-independent distribution identifiers"
        },
        "identifiers": {
          "type": "array",
          "description": "Platform-independent identifiers (imdb_id, gracenote_id, eidr_id, etc.). Each identifier uniquely identifies a collection across all publishers.",
          "items": {
            "type": "object",
            "properties": {
              "type": {
                "$ref": "/schemas/3.1.0/enums/distribution-identifier-type.json",
                "description": "Type of distribution identifier"
              },
              "value": {
                "type": "string",
                "description": "The identifier value"
              }
            },
            "required": [
              "type",
              "value"
            ],
            "additionalProperties": false
          },
          "minItems": 1
        }
      },
      "required": [
        "selection_type",
        "identifiers"
      ],
      "additionalProperties": false
    },
    {
      "type": "object",
      "title": "Publisher Collections Source",
      "description": "Select specific collections within a publisher's adagents.json by collection ID",
      "properties": {
        "selection_type": {
          "type": "string",
          "const": "publisher_collections",
          "description": "Discriminator indicating selection by specific collection IDs within a publisher"
        },
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "collection_ids": {
          "type": "array",
          "description": "Specific collection IDs from the publisher's adagents.json",
          "items": {
            "type": "string"
          },
          "minItems": 1
        }
      },
      "required": [
        "selection_type",
        "publisher_domain",
        "collection_ids"
      ],
      "additionalProperties": false
    },
    {
      "type": "object",
      "title": "Publisher Genres Source",
      "description": "Select all collections from a publisher matching genre criteria. Use when excluding entire content categories from a specific publisher.",
      "properties": {
        "selection_type": {
          "type": "string",
          "const": "publisher_genres",
          "description": "Discriminator indicating selection by genre within a publisher"
        },
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "genres": {
          "type": "array",
          "description": "Genre values to match against the publisher's collections",
          "items": {
            "type": "string"
          },
          "minItems": 1
        },
        "genre_taxonomy": {
          "$ref": "/schemas/3.1.0/enums/genre-taxonomy.json",
          "description": "Taxonomy for the genre values. Required so sellers can interpret genre strings unambiguously. Use 'custom' for free-form values negotiated out of band."
        }
      },
      "required": [
        "selection_type",
        "publisher_domain",
        "genres",
        "genre_taxonomy"
      ],
      "additionalProperties": false
    }
  ]
} as const;

export const collection_CollectionListChangedWebhook = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/collection/collection-list-changed-webhook.json",
  "title": "Collection List Changed Webhook",
  "description": "Webhook notification sent when a collection list's resolved collections change. Contains a summary only — recipients must call get_collection_list to retrieve the updated collections.",
  "type": "object",
  "properties": {
    "idempotency_key": {
      "type": "string",
      "description": "Sender-generated key stable across retries of the same webhook event. Governance agents MUST generate a cryptographically random value (UUID v4 recommended) per distinct list-change event and reuse the same key on every retry. Recipients MUST dedupe by this key, scoped to the authenticated sender identity (HMAC secret or Bearer credential) — keys from different governance agents are independent.",
      "minLength": 16,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{16,255}$"
    },
    "event": {
      "type": "string",
      "const": "collection_list_changed",
      "description": "The event type"
    },
    "list_id": {
      "type": "string",
      "description": "ID of the collection list that changed",
      "x-entity": "collection_list"
    },
    "list_name": {
      "type": "string",
      "description": "Name of the collection list"
    },
    "change_summary": {
      "type": "object",
      "description": "Summary of changes to the resolved list",
      "properties": {
        "collections_added": {
          "type": "integer",
          "description": "Number of collections added since last resolution"
        },
        "collections_removed": {
          "type": "integer",
          "description": "Number of collections removed since last resolution"
        },
        "total_collections": {
          "type": "integer",
          "description": "Total collections in the resolved list"
        }
      },
      "additionalProperties": false
    },
    "resolved_at": {
      "type": "string",
      "format": "date-time",
      "description": "When the list was re-resolved"
    },
    "cache_valid_until": {
      "type": "string",
      "format": "date-time",
      "description": "When the consumer should refresh from the governance agent"
    },
    "signature": {
      "type": "string",
      "description": "HMAC-SHA256 webhook signature over {unix_timestamp}.{raw_http_body_bytes} using the secret exchanged out-of-band when the seller registered with the governance agent. Recipients MUST verify against the X-ADCP-Signature and X-ADCP-Timestamp headers using timing-safe comparison and MUST reject requests where |now - timestamp| > 300 seconds. The body copy of this field is a convenience only — the headers are authoritative. See docs/building/implementation/security#webhook-security."
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "idempotency_key",
    "event",
    "list_id",
    "resolved_at",
    "signature"
  ],
  "additionalProperties": false
} as const;

export const collection_CollectionListFilters = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/collection/collection-list-filters.json",
  "title": "Collection List Filters",
  "description": "Filters that dynamically modify a collection list when resolved. Include filters are allowlists (only matching collections pass). Exclude filters are blocklists (matching collections are removed). When both are present for the same dimension, include is applied first, then exclude narrows further.",
  "type": "object",
  "properties": {
    "content_ratings_exclude": {
      "type": "array",
      "description": "Exclude collections with any of these content ratings (OR logic). This is a metadata filter on the collection's declared content_rating field — it does not evaluate episode content.",
      "items": {
        "$ref": "/schemas/3.1.0/core/content-rating.json"
      },
      "minItems": 1
    },
    "content_ratings_include": {
      "type": "array",
      "description": "Include only collections with any of these content ratings (OR logic). Collections without a declared content_rating are excluded.",
      "items": {
        "$ref": "/schemas/3.1.0/core/content-rating.json"
      },
      "minItems": 1
    },
    "genres_exclude": {
      "type": "array",
      "description": "Exclude collections tagged with any of these genres (OR logic). Values are interpreted against genre_taxonomy when present.",
      "items": {
        "type": "string"
      },
      "minItems": 1
    },
    "genres_include": {
      "type": "array",
      "description": "Include only collections with any of these genres (OR logic). Collections without genre metadata are excluded. Values are interpreted against genre_taxonomy when present.",
      "items": {
        "type": "string"
      },
      "minItems": 1
    },
    "genre_taxonomy": {
      "$ref": "/schemas/3.1.0/enums/genre-taxonomy.json",
      "description": "Taxonomy for genre filter values. When present, genres_include and genres_exclude values are interpreted as taxonomy IDs."
    },
    "kinds": {
      "type": "array",
      "description": "Filter to these collection kinds",
      "items": {
        "$ref": "/schemas/3.1.0/enums/collection-kind.json"
      },
      "minItems": 1
    },
    "exclude_distribution_ids": {
      "type": "array",
      "description": "Always exclude collections with these distribution identifiers",
      "items": {
        "type": "object",
        "properties": {
          "type": {
            "$ref": "/schemas/3.1.0/enums/distribution-identifier-type.json",
            "description": "Type of distribution identifier"
          },
          "value": {
            "type": "string",
            "description": "The identifier value"
          }
        },
        "required": [
          "type",
          "value"
        ],
        "additionalProperties": false
      },
      "minItems": 1
    },
    "production_quality": {
      "type": "array",
      "description": "Filter by production quality tier",
      "items": {
        "$ref": "/schemas/3.1.0/enums/production-quality.json"
      },
      "minItems": 1
    }
  },
  "additionalProperties": false
} as const;

export const collection_CollectionList = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/collection/collection-list.json",
  "title": "Collection List",
  "description": "A managed collection list with optional filters for dynamic evaluation. Lists are resolved at setup time and cached by orchestrators/sellers for real-time use. Collections represent programs, shows, and other content entities independent of which properties carry them.",
  "type": "object",
  "properties": {
    "list_id": {
      "type": "string",
      "description": "Unique identifier for this collection list",
      "x-entity": "collection_list"
    },
    "name": {
      "type": "string",
      "description": "Human-readable name for the list"
    },
    "description": {
      "type": "string",
      "description": "Description of the list's purpose"
    },
    "account": {
      "$ref": "/schemas/3.1.0/core/account-ref.json",
      "description": "Account that owns this list. Returned as account_id form (seller-assigned identifier)."
    },
    "base_collections": {
      "type": "array",
      "description": "Array of collection sources to evaluate. Each entry is a discriminated union: distribution_ids (platform-independent identifiers), publisher_collections (publisher_domain + collection_ids), or publisher_genres (publisher_domain + genres). If omitted, queries the agent's entire collection database.",
      "items": {
        "$ref": "/schemas/3.1.0/collection/base-collection-source.json"
      }
    },
    "filters": {
      "$ref": "/schemas/3.1.0/collection/collection-list-filters.json",
      "description": "Dynamic filters applied when resolving the list"
    },
    "brand": {
      "$ref": "/schemas/3.1.0/core/brand-ref.json",
      "description": "Brand reference used to automatically apply appropriate rules. Resolved to full brand identity at execution time."
    },
    "webhook_url": {
      "type": "string",
      "format": "uri",
      "description": "URL to receive notifications when the resolved list changes"
    },
    "cache_duration_hours": {
      "type": "integer",
      "description": "Recommended cache duration for resolved list. Consumers should re-fetch after this period. Defaults to 168 (one week) because collection metadata changes less frequently than property metadata.",
      "minimum": 1,
      "default": 168
    },
    "created_at": {
      "type": "string",
      "format": "date-time",
      "description": "When the list was created"
    },
    "updated_at": {
      "type": "string",
      "format": "date-time",
      "description": "When the list was last modified"
    },
    "collection_count": {
      "type": "integer",
      "description": "Number of collections in the resolved list (at time of last resolution)"
    }
  },
  "required": [
    "list_id",
    "name"
  ],
  "additionalProperties": false
} as const;

export const collection_CreateCollectionListRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/collection/create-collection-list-request.json",
  "title": "Create Collection List Request",
  "description": "Request parameters for creating a new collection list",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    }
  ],
  "x-mutates-state": true,
  "properties": {
    "account": {
      "$ref": "/schemas/3.1.0/core/account-ref.json",
      "description": "Account that will own the list. Pass a natural key (brand, operator, optional sandbox) or a seller-assigned account_id from list_accounts. When omitted, this task applies its task-local single-account shortcut: if exactly one account is accessible to the authenticated caller, the seller may assign the list to that account; otherwise it MUST return an account-required or ambiguous-account error. Omission MUST NOT mean an undocumented credential-local default account."
    },
    "name": {
      "type": "string",
      "description": "Human-readable name for the list"
    },
    "description": {
      "type": "string",
      "description": "Description of the list's purpose"
    },
    "base_collections": {
      "type": "array",
      "description": "Array of collection sources to evaluate. Each entry is a discriminated union: distribution_ids (platform-independent identifiers), publisher_collections (publisher_domain + collection_ids), or publisher_genres (publisher_domain + genres). If omitted, queries the agent's entire collection database.",
      "items": {
        "$ref": "/schemas/3.1.0/collection/base-collection-source.json"
      },
      "minItems": 1
    },
    "filters": {
      "$ref": "/schemas/3.1.0/collection/collection-list-filters.json",
      "description": "Dynamic filters to apply when resolving the list"
    },
    "brand": {
      "$ref": "/schemas/3.1.0/core/brand-ref.json",
      "description": "Brand reference. When provided, the agent automatically applies appropriate rules based on brand characteristics (industry, target_audience, etc.). Resolved at execution time."
    },
    "idempotency_key": {
      "type": "string",
      "description": "Client-generated unique key for this request. Prevents duplicate collection list creation on retries. MUST be unique per (seller, request) pair to prevent cross-seller correlation. Use a fresh UUID v4 for each request.",
      "minLength": 16,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{16,255}$"
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "idempotency_key",
    "name"
  ],
  "additionalProperties": true
} as const;

export const collection_CreateCollectionListResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/collection/create-collection-list-response.json",
  "title": "Create Collection List Response",
  "description": "Response payload for create_collection_list task",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    },
    {
      "$ref": "/schemas/3.1.0/core/protocol-envelope.json"
    }
  ],
  "properties": {
    "list": {
      "$ref": "/schemas/3.1.0/collection/collection-list.json",
      "description": "The created collection list"
    },
    "auth_token": {
      "type": "string",
      "description": "Token that authorizes sellers to fetch this list via get_collection_list. Only returned at creation time — buyers MUST store it in a secret manager. Scoped to this one list_id; MUST NOT be reused across lists. Governance agents MUST issue a distinct token per seller so per-relationship revocation is possible. Tokens MUST NOT be logged, appear in cache keys, or echo in error responses. delete_collection_list MUST revoke the token immediately; compromise-driven revocation MUST also signal cache invalidation to sellers (reduced cache_valid_until or a list-changed webhook). See Security considerations in docs/governance/collection/tasks/collection_lists."
    },
    "replayed": {
      "type": "boolean",
      "description": "Set to true when this response was returned from the idempotency cache rather than from a fresh execution. Set to false (or omitted) when the request was executed fresh. Buyers use this to distinguish cached replays from new executions — matters for billing reconciliation, audit logs, state-machine routing (cached state-tracking fields are historical snapshots, not current state — re-read via the resource's read endpoint), and any downstream system that assumes exactly-once event semantics. From 3.1 onward, `replayed` MAY appear on responses to any request that resolved via the idempotency cache, including read tools — universal `idempotency_key` (see security.mdx §Idempotency) means the cache holds read responses too.",
      "default": false
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "list",
    "auth_token"
  ],
  "additionalProperties": true
} as const;

