export const core_Error = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/error.json",
  "title": "Error",
  "description": "Standard error structure for task-specific errors and warnings",
  "type": "object",
  "properties": {
    "code": {
      "type": "string",
      "minLength": 1,
      "maxLength": 64,
      "description": "Error code for programmatic handling. The error-code vocabulary is open: `error.code` is wire-typed `string` (not a closed enum), the standard codes published in `enums/error-code.json` are documentary, and senders MAY emit codes outside that set (platform-specific codes, or codes introduced in a later AdCP version). Receivers MUST decode unknown codes — treat the response as well-formed, read `error.recovery` for the recovery classification, and fall back to `transient` when `recovery` is absent. See `error-handling.mdx#forward-compatible-decoding-normative` for the full forward-compat contract — this rule is what lets future maintenance lines ship new codes additively."
    },
    "message": {
      "type": "string",
      "description": "Human-readable error message"
    },
    "field": {
      "type": "string",
      "description": "Field path associated with the error in JSONPath-lite format (e.g., 'packages[0].targeting'). When `issues[]` is also present, sellers MUST set this to `issues[0].pointer` translated from RFC 6901 to JSONPath-lite (e.g., '/packages/0/targeting' → 'packages[0].targeting') so pre-3.1 consumers reading `field` only get deterministic behavior. Will be deprecated in a future major version in favor of `issues[].pointer`."
    },
    "suggestion": {
      "type": "string",
      "description": "Suggested fix for the error"
    },
    "retry_after": {
      "type": "number",
      "description": "Seconds to wait before retrying the operation. Sellers MUST return values between 1 and 3600. Clients MUST clamp values outside this range.",
      "minimum": 1,
      "maximum": 3600
    },
    "issues": {
      "type": "array",
      "description": "Structured list of validation failures. Primary use is `VALIDATION_ERROR`, where multi-field rejections are common and `field` (singular) cannot carry the full pointer map. MAY appear on other error codes that reject multiple fields at once. When `issues` is present, sellers MUST also populate `field` from `issues[0]` for backward compatibility with pre-3.1 consumers that read `field` only — translating the RFC 6901 `pointer` format to the JSONPath-lite format `field` uses (e.g., `/packages/0/targeting` → `packages[0].targeting`). MUST (not SHOULD) so consumers reading `field` get deterministic behavior across sellers — the cost is one line of dual-write per seller; the cost of SHOULD is a long tail of seller-A-vs-seller-B inconsistency. Future major versions will deprecate `field` in favor of `issues[].pointer`.",
      "items": {
        "type": "object",
        "properties": {
          "pointer": {
            "type": "string",
            "description": "RFC 6901 JSON Pointer to the offending field in the request payload (e.g., '/packages/0/targeting/geo_countries/2'). Format chosen to match Ajv's native validation output (`instancePath`); standardized and unambiguous on keys containing `/` or `~`. NOTE: this differs from the legacy top-level `field` which uses JSONPath-lite (`packages[0].targeting.geo_countries[2]`). When sellers populate `field` from `issues[0].pointer` for backward compatibility (see `field` description), they MUST translate the format — `/packages/0/x` → `packages[0].x`. Future major versions will deprecate `field` in favor of `issues[].pointer`."
          },
          "message": {
            "type": "string",
            "description": "Human-readable description of why this specific field was rejected."
          },
          "keyword": {
            "type": "string",
            "description": "Schema keyword that rejected the payload, drawn from the JSON Schema vocabulary (e.g., 'required', 'type', 'format', 'enum', 'pattern', 'minimum', 'maxLength'). Matches the keyword names emitted by JSON Schema validators (Ajv, jsonschema, etc.) so agents can pattern-match on rejection class without parsing message text. Implementers SHOULD use the validator's native keyword name; do not invent custom values here."
          },
          "schemaPath": {
            "type": "string",
            "description": "Optional. JSON Schema tree path of the rejecting keyword (e.g. '#/properties/packages/items/oneOf/1'). 3.1+ consumers SHOULD prefer `schema_id`; `schemaPath` is retained for 3.0.x compatibility (renamed to `schema_path` in a future major). See error-handling.mdx for the validator-internals production-emit rules."
          },
          "schema_id": {
            "type": "string",
            "description": "Optional. `$id` of the rejecting (sub-)schema (e.g. `/schemas/3.1.0/core/activation-key.json`). MUST resolve to a `$id` published in the spec at the version the seller advertises via `get_adcp_capabilities` — either a deep sub-schema (the typical case) or the response-root `$id` (the bundled-tree fallback for tools served from bundles built before #3868). Sellers MUST NOT emit when the rejection occurred against a private extension, server-only sub-schema, or pre-release element — the public-spec replay rationale only holds when the rejecting element is reachable from the public bundle. Sellers populating `schemaPath` SHOULD also populate `schema_id` when they have it so 3.1+ readers don't get strictly less than 3.0.x readers. See error-handling.mdx for resolution guidance and the bundled-tree caveat."
          },
          "discriminator": {
            "type": "array",
            "description": "Optional. Const-discriminator property/value pair(s) identifying the variant the validator selected from values present in the payload. Sellers MUST populate only when (a) the rejecting schema is a const-discriminated `oneOf` / `anyOf` and (b) the discriminator property is present in the payload — emission on partial-match inference would fingerprint the seller's validator implementation. MUST omit when zero variants survive. Compound discriminators (e.g. `(type, value_type)`) produce multiple entries ordered by declaration in the rejecting schema's `properties` block. Same private-extensions / version-skew carve-out as `schema_id`. See error-handling.mdx.",
            "items": {
              "type": "object",
              "properties": {
                "property_name": {
                  "type": "string",
                  "description": "Discriminator property name (e.g., `type`, `value_type`). Aligns with OpenAPI 3.x `discriminator.propertyName`."
                },
                "value": {
                  "type": [
                    "string",
                    "number",
                    "boolean",
                    "null"
                  ],
                  "description": "Value the caller sent at `property_name`. Typically a string for const-discriminated unions; numeric/boolean/null permitted. Object and array values are forbidden — const discriminators are scalars, and emitting a structured value would conflate 'caller sent a complex shape' with 'validator inferred from a structural match'."
                }
              },
              "required": [
                "property_name",
                "value"
              ],
              "additionalProperties": false
            }
          }
        },
        "required": [
          "pointer",
          "message",
          "keyword"
        ],
        "additionalProperties": true
      }
    },
    "details": {
      "type": "object",
      "description": "Additional task-specific error details. Sellers MAY mirror `issues[]` here as `details.issues` for backward compatibility with pre-3.1 consumers reading from `details`; new consumers SHOULD prefer the top-level `issues` field.\n\n**Canonical rejection-set shape (3.1+).** When the error reports a rejected value against a closed set of accepted values (e.g., enum mismatch, unsupported pricing option, invalid signal id), sellers SHOULD use the canonical key `accepted_values: <array>` under `details` rather than seller-specific variants observed in the wild (`available`, `allowed`, `accepted_values` at the error root, etc.). The canonical shape:\n\n```json\n{\n  \"code\": \"INVALID_PRICING_MODEL\",\n  \"message\": \"Pricing option not found: po_prism_abandoner_cpm\",\n  \"field\": \"pricing_option_id\",\n  \"details\": {\n    \"rejected_value\": \"po_prism_abandoner_cpm\",\n    \"accepted_values\": [\"po_prism_cart_cpm\", \"po_prism_view_cpm\"]\n  }\n}\n```\n\n- `rejected_value` (optional): the offending value the buyer supplied, echoed for buyer-side diagnostic clarity (especially when the offending field is nested or transformed before validation).\n- `accepted_values` (optional): the closed set the seller would have accepted at this field on this call. Sellers MUST NOT enumerate the full ecosystem-wide accepted set if it differs from what's accepted for *this caller in this context* (account, brand, scope) — leaking ecosystem-wide accepted sets to a per-caller rejection turns the error into an enumeration oracle.\n\nThis is **SHOULD-level guidance**, not MUST: `details` remains `additionalProperties: true` and pre-3.1 sellers using `available` / `allowed` / `accepted_values` at the error root remain conformant. The canonical shape lets buyer-side diagnostic tooling (SDK runner hints, dashboards, error classifiers) reliably surface the accepted-set without per-seller pattern matching. SDKs SHOULD accept any of the legacy variants and normalize on read; the canonical shape is what new sellers and 3.1+ adopters should emit going forward.",
      "additionalProperties": true
    },
    "recovery": {
      "type": "string",
      "enum": [
        "transient",
        "correctable",
        "terminal"
      ],
      "description": "Agent recovery classification. transient: retry after delay (rate limit, service unavailable, timeout). correctable: fix the request and resend (invalid field, budget too low, creative rejected). terminal: requires human action (account suspended, payment required, account not found). Senders SHOULD populate `recovery` on every error from 3.1 onward — it is the normative carrier of recovery semantics across version skew. A receiver that does not recognize `error.code` (a newer code, or a platform-specific code) MUST still be able to classify the error from `recovery`. The `enumMetadata.recovery` block in `enums/error-code.json` is the documentary mirror for known codes; `error.recovery` on the wire is authoritative."
    },
    "source": {
      "type": "string",
      "enum": [
        "producer",
        "sdk"
      ],
      "description": "Who emitted this error entry. `producer` (default when absent): emitted by the response's authoring agent (the seller for `get_products`, the creative agent for `build_creative`, etc.). `sdk`: augmented by a consuming SDK that detected a non-fatal advisory condition on consumption (e.g., `FORMAT_PROJECTION_FAILED` when the buyer SDK couldn't project a v1 format to a canonical, or `FORMAT_DECLARATION_DIVERGENT` when the SDK detected a producer bug on read). SDK-augmented entries SHOULD also set `sdk_id` so downstream consumers can identify which intermediate processor inserted the entry.\n\n**Multi-hop propagation (normative).** AdCP is a federated agent network — responses commonly traverse multiple SDKs (e.g., sales agent → interchange → DSP → buyer). When an SDK augments `errors[]` with a consumption-detected entry, the augmented response carries the entry forward to subsequent hops. Each hop that detects the same condition independently SHOULD deduplicate by `(code, field)` rather than re-emit; the existing entry's `sdk_id` identifies which earlier processor saw it first. Producer entries (those without `source: \"sdk\"`) are authoritative for what the response's authoring agent self-detected; SDK entries are observations made on top.\n\n**Replay/audit safety.** Persisted or replayed responses carry `source` and `sdk_id` so the audit trail can distinguish seller-emitted entries from SDK-augmented ones. Without `source`, a downstream consumer can't tell whether a code came from the seller or an intermediate SDK, which corrupts attribution."
    },
    "sdk_id": {
      "type": "string",
      "description": "Optional identifier for the SDK that augmented this error entry. Format: `<sdk_package_name>@<version>` (e.g., `@adcontextprotocol/adcp@7.3.0`, `adcontextprotocol-adcp-python@1.2.0`). MUST be set when `source: \"sdk\"`; MUST be absent when `source: \"producer\"` or absent. Lets downstream consumers identify which intermediate processor inserted the entry, useful for debugging cross-SDK divergence (e.g., one SDK detects a projection failure that another SDK's registry version doesn't)."
    }
  },
  "required": [
    "code",
    "message"
  ],
  "additionalProperties": true
} as const;

export const core_EvaluatorSpec = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/evaluator-spec.json",
  "title": "Evaluator Spec",
  "description": "Advisory buyer-attached pointer (#5280) declaring HOW produced build_creative variants should be evaluated and ranked. The rank-side of the get_creative_features feature oracle: the chosen form is the SOURCE of feature evaluation that yields creative-feature values for each leaf, `feature_requirement` is an optional hard GATE over those values, and `rank_by` is the RANK ordering over the survivors. Informs the agent's best_of_n recommended/rank and, when the agent advertises creative.supports_evaluator, populates a per-leaf `eval` block (creative-feature-result[]) on the response.\n\nGate-then-rank pipeline (per produced leaf in a best_of_n run): the producing agent (1) evaluates the leaf via the chosen form, obtaining creative-feature values; (2) when `feature_requirement` is present, applies those predicates and DROPS any leaf that fails (internal best_of_n pruning) — survivors only; (3) orders survivors by `rank_by`. The gate operates BEFORE return: it prunes which leaves the agent recommends/returns from its own best_of_n exploration, never an AdCP-layer block of an already-produced billable leaf — what is produced and billed is governed by max_variants/max_creatives/max_spend, not by the evaluator. With no `feature_requirement`, evaluation stays advisory: every produced leaf is returned and billed and ranking is a soft preference, so `rank_by` failures rank lower but are never dropped.\n\nWhen the chosen form is `feature_agent` (or `agent_url`), the seller calls an external get_creative_features-capable agent, so the pointer is subject to the seller's `creative_policy.accepted_verifiers[]` allowlist exactly as #5280 established for provenance verify_agent: the buyer REPRESENTS which on-list agent it used, the seller (verifier-of-record) CALLS it. An off-list agent is rejected with `EVALUATOR_AGENT_NOT_ACCEPTED` (mirrors PROVENANCE_VERIFIER_NOT_ACCEPTED) before any outbound call; an on-list agent that is unreachable or unknown degrades to seller-default ranking with an advisory errors[] note (non-terminal), NOT a failure.\n\nEvaluator credentials and caller-supplied trust material are never carried in this object, `context`, `ext`, or the creative payload. The producing creative agent authenticates its outbound call to the evaluator on the transport (RFC 9421 request signing/JWKS, mTLS, or a pre-provisioned Bearer/API-key credential). Credential- or trust-material payload keys (for example `api_key`, `client_secret`, `authorization`, `jwk`, `jwks`, or `jwks_uri`) are non-conforming and should be rejected with `CREDENTIAL_IN_ARGS`.\n\nProvide exactly one of three forms; an optional `feature_requirement` gate, an optional `rank_by` ordering, an optional `feature_agent` allowlisted pointer, and a shared optional eval_budget apply to whichever form is chosen. Feature discovery uses the existing governance.creative_features catalog on get_adcp_capabilities; evaluator outputs reuse creative-feature-result[] and do not mint a parallel verdict/result surface. `evaluator_id` is not discovered from governance.creative_features: it is a pre-provisioned, account-arranged preset whose emitted feature_ids still come from that catalog.\n\nExperimental (x-status: experimental): this whole evaluator surface — the `evaluator` input, the per-leaf `eval` response block, and `creative.supports_evaluator` — is new and not yet field-tested across parties. Sellers that implement it MUST list `creative.evaluator` in `experimental_features`. Reserved 3.x follow-ons that may reshape these fields: a separate `supports_evaluator_gate` capability and a hard MUST-enforce-gate semantic. Per docs/reference/experimental-status, it MAY change between 3.x releases with notice.",
  "x-status": "experimental",
  "type": "object",
  "properties": {
    "feature_requirement": {
      "type": "array",
      "description": "Optional hard GATE over creative-feature values — the predicates a leaf MUST satisfy for the producing agent to recommend/return it. Reuses the feature-requirement shape (min_value/max_value for quantitative features like creative_quality_score, allowed_values for binary/categorical) — the same predicate vocabulary that gates property/audience filters, which its own schema names as an intended creative-gate reuse. A leaf that fails any predicate is DROPPED from the agent's best_of_n survivors before ranking — this is internal pruning of which leaves the agent recommends, not an AdCP-layer block of an already-produced billable leaf (what is produced/billed is governed by max_variants/max_creatives/max_spend). Distinct from `rank_by`: the gate is a pass/fail predicate (drop on fail), `rank_by` is an ordering over survivors. Each predicate's `if_not_covered` (exclude|include, default exclude) is the fail-open knob when the source cannot measure that feature. A pass/warn/fail verdict is expressed as a categorical string feature value gated via `allowed_values` (e.g. [\"pass\"] or [\"pass\",\"warn\"]) — the buyer's predicate decides whether warn passes; the verdict is derived, never stored on creative-feature-result. Omit to leave evaluation advisory (no leaf is dropped).",
      "items": {
        "$ref": "/schemas/3.1.0/core/feature-requirement.json"
      },
      "minItems": 1
    },
    "rank_by": {
      "type": "array",
      "description": "Optional RANK ordering over creative-feature values — an ordered list (most significant first) the agent uses to order the gate survivors into recommended/rank. An explicit {feature_id, direction} ordering rather than the feature-requirement predicate (which has no sort direction): the gate decides pass/fail, rank_by decides better/worse. Soft preference, never a gate: leaves are not dropped by rank_by, they are only ordered. Omit to let the evaluator/seller choose the ordering.",
      "items": {
        "type": "object",
        "properties": {
          "feature_id": {
            "type": "string",
            "description": "Creative feature to order by (discovered via get_adcp_capabilities; the same feature_id space the chosen evaluator form returns in eval.features[])."
          },
          "direction": {
            "type": "string",
            "enum": [
              "maximize",
              "minimize"
            ],
            "default": "maximize",
            "description": "Sort direction for this feature: `maximize` ranks higher feature values first (e.g. creative_quality_score), `minimize` ranks lower values first (e.g. predicted_cpa)."
          }
        },
        "required": [
          "feature_id"
        ],
        "additionalProperties": false
      },
      "minItems": 1
    },
    "feature_agent": {
      "type": "object",
      "description": "Optional buyer-attached pointer to a get_creative_features-capable creative-feature / governance agent the producing agent calls to evaluate each leaf (the gate's SOURCE of feature values). This is the buyer-represents → seller-calls pattern #5280 established for provenance, generalized to the evaluator gate: the buyer REPRESENTS which agent it used, but the seller is the verifier-of-record and decides which agent it actually calls. `agent_url` MUST appear (canonicalized per /docs/reference/url-canonicalization) in the seller's `creative_policy.accepted_verifiers[].agent_url`; an off-list agent is rejected with `EVALUATOR_AGENT_NOT_ACCEPTED` (mirrors PROVENANCE_VERIFIER_NOT_ACCEPTED) before any outbound call. The outbound evaluator call authenticates on the transport; this pointer MUST NOT carry API keys, bearer tokens, client secrets, authorization values, JWKs, JWKS documents, or JWKS URIs. Reuses the same allowlist mechanism — no new allowlist is introduced. Distinct from the `agent_url` oneOf form, which names the evaluator's source directly; `feature_agent` attaches the gate's measurement source alongside any of the three forms.",
      "properties": {
        "agent_url": {
          "type": "string",
          "format": "uri",
          "pattern": "^https://",
          "description": "URL of the get_creative_features-capable agent the producing agent calls to obtain creative-feature values for the gate. MUST use https:// and MUST match an entry in the seller's `creative_policy.accepted_verifiers[].agent_url`; off-list → `EVALUATOR_AGENT_NOT_ACCEPTED`."
        },
        "feature_id": {
          "type": "string",
          "description": "Optional canonical feature_id the producing agent SHOULD request against this agent. When present it SHOULD match the agent's `accepted_verifiers[].feature_id` or be omitted; when absent the seller selects a feature at evaluation time. Resolves selector ambiguity exactly as the provenance verify_agent.feature_id does."
        }
      },
      "required": [
        "agent_url"
      ],
      "additionalProperties": false
    },
    "eval_budget": {
      "type": "object",
      "description": "Optional soft ceiling on evaluation effort. Advisory in v1 with no billing coupling. Well-known soft fields max_calls / max_seconds; open for evaluator-specific knobs.",
      "properties": {
        "max_calls": {
          "type": "integer",
          "minimum": 1,
          "description": "Soft cap on the number of judge calls the evaluator should make."
        },
        "max_seconds": {
          "type": "number",
          "minimum": 0,
          "description": "Soft cap on wall-clock seconds the evaluation should consume."
        }
      },
      "additionalProperties": true
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "oneOf": [
    {
      "type": "object",
      "description": "Exemplar form: inline pass/fail examples that CALIBRATE a single agent-defined prediction feature — conventionally `predicted_performance`, a number in [0,1] — that the evaluator computes per leaf and returns as one creative-feature-result entry in eval.features[]. Exemplars are calibration, not a separate ranking path (mirroring content-standards.json calibration_exemplars): the pass/fail artifacts anchor where the prediction sits between 0 (like the fail set) and 1 (like the pass set). `rank_by` then orders survivors on that one feature_id (e.g. {feature_id: predicted_performance, direction: maximize}). Artifact-based — a creative variant is content to be measured. Like all three forms, this resolves to \"produce a feature value, rank by it.\"",
      "required": [
        "exemplars"
      ],
      "properties": {
        "exemplars": {
          "type": "object",
          "description": "Pass/fail examples that calibrate the single prediction feature (e.g. `predicted_performance` in [0,1]) the evaluator returns in eval.features[]. Artifact-based, mirroring content-standards.json calibration_exemplars.",
          "properties": {
            "pass": {
              "type": "array",
              "items": {
                "$ref": "/schemas/3.1.0/content-standards/artifact.json"
              },
              "description": "Artifacts exemplifying variants the buyer considers good — the high end (≈1) of the calibrated prediction feature."
            },
            "fail": {
              "type": "array",
              "items": {
                "$ref": "/schemas/3.1.0/content-standards/artifact.json"
              },
              "description": "Artifacts exemplifying variants the buyer considers bad — the low end (≈0) of the calibrated prediction feature."
            }
          }
        }
      },
      "additionalProperties": true
    },
    {
      "type": "object",
      "description": "Identifier form: an account-scoped house evaluator preset that produces creative-feature values for each leaf. This is not an on-wire discovery catalog: buyers obtain evaluator_id through account provisioning or bilateral arrangement, while emitted feature_ids MUST be drawn from the agent's get_adcp_capabilities governance.creative_features catalog. The scoring path remains accountable through eval.features[] plus any pinned feature_agent.",
      "required": [
        "evaluator_id"
      ],
      "properties": {
        "evaluator_id": {
          "type": "string",
          "x-entity": "evaluator",
          "description": "Account-scoped house evaluator preset selected by the buyer. This id is pre-provisioned/account-arranged, not discovered from get_adcp_capabilities governance.creative_features. That catalog only discovers the feature vocabulary the preset emits. An unknown id degrades to seller-default ranking (advisory errors[] note), not a failure."
        }
      },
      "additionalProperties": true
    },
    {
      "type": "object",
      "description": "Agent form: an external judge agent the seller calls via the get_creative_features contract (/docs/governance/creative/get_creative_features) to produce creative-feature values for each leaf — the SAME contract and the same results[] (creative-feature-result[]) shape get_creative_features returns. One creative-feature agent contract spans gate, rank, and provenance. Subject to the same `creative_policy.accepted_verifiers[]` allowlist as `feature_agent`: an off-list agent_url is rejected with `EVALUATOR_AGENT_NOT_ACCEPTED` before any outbound call. The producing agent authenticates the outbound evaluator call on the transport (request signing/JWKS, mTLS, or a pre-provisioned static credential); this object only names the evaluator and MUST NOT carry credentials or caller-supplied trust material. eval_budget bounds the calls; sellers SHOULD populate calls_used/seconds_used on the leaf eval block when agent_url was used and eval_budget was supplied (reuse the oracle's vendor_cost/consumption for cost).",
      "required": [
        "agent_url"
      ],
      "properties": {
        "agent_url": {
          "type": "string",
          "format": "uri",
          "pattern": "^https://",
          "description": "URL of an external get_creative_features-capable judge agent the seller calls to score the produced leaves. MUST match an entry in the seller's `creative_policy.accepted_verifiers[].agent_url` (off-list → `EVALUATOR_AGENT_NOT_ACCEPTED`); an on-list agent that is unreachable or rejects the producing agent's transport authentication degrades to seller-default ranking (advisory errors[] note), not a failure. Authentication and trust material for this call belongs on the transport or in account provisioning, not in the evaluator payload."
        }
      },
      "additionalProperties": true
    }
  ],
  "additionalProperties": true
} as const;

export const core_EventCustomData = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/event-custom-data.json",
  "title": "Event Custom Data",
  "description": "Event-specific data for attribution and reporting",
  "type": "object",
  "properties": {
    "value": {
      "type": "number",
      "description": "Monetary value of the event (should be accompanied by currency)",
      "minimum": 0
    },
    "currency": {
      "type": "string",
      "pattern": "^[A-Z]{3}$",
      "description": "ISO 4217 currency code"
    },
    "order_id": {
      "type": "string",
      "description": "Unique order or transaction identifier"
    },
    "content_ids": {
      "type": "array",
      "description": "Item identifiers for catalog attribution. Values are matched against catalog items using the identifier type declared by the catalog's content_id_type field (e.g., SKUs, GTINs, or vertical-specific IDs like job_id).",
      "items": {
        "type": "string"
      }
    },
    "content_type": {
      "type": "string",
      "description": "Category of content associated with the event (e.g., 'product', 'job', 'hotel'). Corresponds to the catalog type when used for catalog attribution."
    },
    "content_name": {
      "type": "string",
      "description": "Name of the product or content"
    },
    "content_category": {
      "type": "string",
      "description": "Category of the product or content"
    },
    "num_items": {
      "type": "integer",
      "description": "Number of items in the event",
      "minimum": 0
    },
    "search_string": {
      "type": "string",
      "description": "Search query for search events"
    },
    "progress_percent": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Content progress percentage reached, primarily for `watch_milestone` events. Use 25, 50, 75, or 100 for quartiles, or another publisher-defined threshold. Do not use `value` for non-monetary progress."
    },
    "progress_seconds": {
      "type": "number",
      "minimum": 0,
      "description": "Content progress duration reached in seconds, primarily for `watch_milestone` events. Use when the milestone is time-based rather than percentage-based."
    },
    "contents": {
      "type": "array",
      "description": "Per-item details for e-commerce events",
      "items": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string",
            "description": "Product or content identifier"
          },
          "quantity": {
            "type": "integer",
            "description": "Quantity of this item",
            "minimum": 1
          },
          "price": {
            "type": "number",
            "description": "Price per unit of this item",
            "minimum": 0
          },
          "brand": {
            "type": "string",
            "description": "Brand name of this item"
          }
        },
        "required": [
          "id"
        ],
        "additionalProperties": true
      }
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "additionalProperties": true
} as const;

export const core_EventSourceHealth = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/event-source-health.json",
  "title": "Event Source Health",
  "description": "Health assessment for a configured event source. Sellers evaluate the quality, completeness, and volume of events received from this source. Sellers with native quality scores (Snap EQS, Meta EMQ) relay them in detail; sellers without native scores derive status from operational metrics (volume, error rates, tag activity).",
  "type": "object",
  "properties": {
    "status": {
      "$ref": "/schemas/3.1.0/enums/assessment-status.json",
      "description": "Overall health status. Use this for cross-seller decisions — do not rely on detail.score for comparability. 'insufficient' covers the source-offline case (zero events received over the seller's evaluation window) — disambiguate via `events_received_24h: 0` and a stale `last_event_at`. Sellers MUST surface a corresponding impairment (reason_code: source_offline) on any active media buy whose conversion goals depend on an event source that has gone offline."
    },
    "detail": {
      "type": "object",
      "description": "Seller-specific scoring detail. Only present when the seller has a native quality score to relay. Buyer agents should use status (not detail) for cross-seller decisions. Detail is supplementary context for human review or advanced diagnostics.",
      "properties": {
        "score": {
          "type": "number",
          "minimum": 0,
          "description": "Seller-defined quality score. Scale varies by seller — only compare within the same seller."
        },
        "max_score": {
          "type": "number",
          "minimum": 1,
          "description": "Maximum possible score on this seller's scale."
        },
        "label": {
          "type": "string",
          "description": "Seller's name for this score (e.g., 'Event Quality Score', 'Event Match Quality')."
        }
      },
      "required": [
        "score",
        "max_score"
      ],
      "additionalProperties": true
    },
    "match_rate": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Fraction of events from this source that the seller successfully matched to ad interactions (0.0-1.0). Low match rates indicate weak user_match identifiers. Absent when the seller does not compute match rates."
    },
    "last_event_at": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp of the most recent event received from this source. Absent when no events have been received."
    },
    "evaluated_at": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp of when this health assessment was computed. When health is derived from reporting data, this may lag real-time. Buyer agents can use this to decide whether to trust stale assessments or re-request."
    },
    "events_received_24h": {
      "type": "integer",
      "minimum": 0,
      "description": "Number of events received from this source in the last 24 hours. Zero indicates the source is configured but not firing."
    },
    "issues": {
      "type": "array",
      "description": "Actionable issues detected with this event source. Sellers should limit to the top 3-5 most actionable items. Buyer agents should sort by severity rather than relying on array position.",
      "items": {
        "$ref": "/schemas/3.1.0/core/diagnostic-issue.json"
      }
    }
  },
  "required": [
    "status"
  ],
  "additionalProperties": true
} as const;

export const core_EventSurface = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/event-surface.json",
  "title": "Event Surface",
  "description": "Structured context for the surface where an event source or logged event originated. Use this when the flat `action_source` is too coarse, such as a creator channel, social profile, podcast feed, newsletter list, or another owned platform property. `category` is a closed vocabulary so buyers can reason generically; `property_type` and `namespace` are open strings so new platforms and property shapes do not require a schema change. The flat `action_source` remains for backward compatibility. When `category` matches an ActionSource value, producers SHOULD set `action_source` to the same value. When `category` is `owned_property`, producers SHOULD keep the most compatible flat `action_source` for legacy consumers, commonly `system_generated` for platform-native events or `other` when no closer value applies.",
  "type": "object",
  "properties": {
    "category": {
      "type": "string",
      "description": "Generic surface category. `owned_property` covers durable creator or brand-controlled properties hosted by a platform, such as channels, profiles, feeds, lists, podcasts, or playlists.",
      "enum": [
        "owned_property",
        "website",
        "app",
        "offline",
        "phone_call",
        "chat",
        "email",
        "in_store",
        "system_generated",
        "other"
      ],
      "enumDescriptions": {
        "owned_property": "Event occurred on or against a durable creator or brand-controlled platform property",
        "website": "Event occurred on a website",
        "app": "Event occurred in a mobile or desktop app",
        "offline": "Event occurred offline or was imported from offline data",
        "phone_call": "Event originated from a phone call",
        "chat": "Event originated from a chat conversation",
        "email": "Event originated from an email interaction",
        "in_store": "Event occurred at a physical retail location",
        "system_generated": "Event was generated by an automated system",
        "other": "Other surface category"
      }
    },
    "property_type": {
      "type": "string",
      "description": "Open vocabulary describing the kind of property, for example `channel`, `profile`, `feed`, `list`, `podcast`, `playlist`, or `newsletter`. Required by convention when `category` is `owned_property`; optional for other categories.",
      "minLength": 1,
      "maxLength": 128
    },
    "namespace": {
      "type": "string",
      "description": "Platform, publisher, or system namespace for the property, such as `video_platform`, `short_video_app`, `audio_service`, or a seller-defined namespace. This is intentionally not an enum.",
      "minLength": 1,
      "maxLength": 128
    },
    "property_id": {
      "type": "string",
      "description": "Optional identifier for the property within `namespace`.",
      "minLength": 1,
      "maxLength": 256,
      "x-entity": "property"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "category"
  ],
  "additionalProperties": true
} as const;

export const core_Event = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/event.json",
  "title": "Event",
  "description": "A marketing event (conversion, engagement, or custom) for attribution and optimization",
  "type": "object",
  "properties": {
    "event_id": {
      "type": "string",
      "description": "Unique identifier for deduplication (scoped to event_type + event_source_id)",
      "minLength": 1,
      "maxLength": 256
    },
    "event_type": {
      "$ref": "/schemas/3.1.0/enums/event-type.json",
      "description": "Standard event type"
    },
    "event_time": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp when the event occurred"
    },
    "user_match": {
      "$ref": "/schemas/3.1.0/core/user-match.json",
      "description": "User identifiers for attribution matching"
    },
    "custom_data": {
      "$ref": "/schemas/3.1.0/core/event-custom-data.json",
      "description": "Event-specific data (value, currency, items, etc.)"
    },
    "action_source": {
      "$ref": "/schemas/3.1.0/enums/action-source.json",
      "description": "Where the event originated"
    },
    "surface": {
      "$ref": "/schemas/3.1.0/core/event-surface.json",
      "description": "Optional structured surface context for the event, such as an owned channel, profile, feed, podcast, newsletter list, website, app, or store. Complements `action_source`; use it when optimization-relevant meaning would otherwise live only in platform-specific `ext` metadata."
    },
    "event_source_url": {
      "type": "string",
      "format": "uri",
      "description": "URL where the event occurred (required when action_source is 'website')"
    },
    "custom_event_name": {
      "type": "string",
      "description": "Name for custom events (used when event_type is 'custom')"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "allOf": [
    {
      "if": {
        "properties": {
          "event_type": {
            "const": "watch_milestone"
          }
        },
        "required": [
          "event_type"
        ]
      },
      "then": {
        "required": [
          "custom_data"
        ],
        "properties": {
          "custom_data": {
            "allOf": [
              {
                "$ref": "/schemas/3.1.0/core/event-custom-data.json"
              },
              {
                "anyOf": [
                  {
                    "required": [
                      "progress_percent"
                    ]
                  },
                  {
                    "required": [
                      "progress_seconds"
                    ]
                  }
                ]
              }
            ]
          }
        }
      }
    }
  ],
  "required": [
    "event_id",
    "event_type",
    "event_time"
  ],
  "additionalProperties": true
} as const;

export const core_Ext = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/ext.json",
  "title": "Extension Object",
  "description": "Extension object for platform-specific, vendor-namespaced parameters. Extensions are always optional and must be namespaced under a vendor/platform key (e.g., ext.gam, ext.roku). Used for custom capabilities, partner-specific configuration, and features being proposed for standardization.",
  "type": "object",
  "additionalProperties": true
} as const;

export const core_FeatureRequirement = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/feature-requirement.json",
  "title": "Feature Requirement",
  "description": "A feature-based requirement — a reusable predicate over a feature value. Used by property list filters today; designed for reuse in other surfaces (audience filters, creative gates) in future versions. Use min_value/max_value for quantitative features, allowed_values for binary/categorical features.",
  "type": "object",
  "properties": {
    "feature_id": {
      "type": "string",
      "description": "Feature to evaluate (discovered via get_adcp_capabilities)"
    },
    "min_value": {
      "type": "number",
      "description": "Minimum numeric value required (for quantitative features)"
    },
    "max_value": {
      "type": "number",
      "description": "Maximum numeric value allowed (for quantitative features)"
    },
    "allowed_values": {
      "type": "array",
      "description": "Values that pass the requirement (for binary/categorical features)",
      "items": {},
      "minItems": 1
    },
    "if_not_covered": {
      "type": "string",
      "enum": [
        "exclude",
        "include"
      ],
      "default": "exclude",
      "description": "How to handle properties where this feature is not covered. 'exclude' (default): property is removed from the list. 'include': property passes this requirement (fail-open)."
    },
    "policy_id": {
      "type": "string",
      "description": "Optional attribution — when this requirement encodes a specific buyer-chosen threshold authorized by a policy, policy_id references the authorizing PolicyEntry. Producers populate when the mechanism exists because of a specific policy (e.g., max_value: 15 on audience_children_composition because of uk_hfss); do NOT populate when the requirement is a general filter unrelated to any policy. Governance findings echo this policy_id when emitting denials traced to the requirement. See /docs/governance/policy-attribution.",
      "$comment": "x-entity deliberately omitted — a PolicyEntry reference can resolve to either a governance_registry_policy or a governance_inline_policy depending on the authorizing entry's source. See issue #2685."
    }
  },
  "required": [
    "feature_id"
  ],
  "additionalProperties": false
} as const;

export const core_FlightItem = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/flight-item.json",
  "title": "Flight Item",
  "description": "A flight route within a flight-type catalog. Carries origin/destination, airline, pricing, and schedule data that platforms use for flight ads and dynamic travel remarketing. Maps to Google DynamicFlightsAsset, Meta flight catalogs, and similar formats.",
  "type": "object",
  "properties": {
    "flight_id": {
      "type": "string",
      "description": "Unique identifier for this flight route or offer."
    },
    "origin": {
      "type": "object",
      "description": "Departure airport or city.",
      "properties": {
        "airport_code": {
          "type": "string",
          "pattern": "^[A-Z]{3}$",
          "description": "IATA airport code (e.g., 'AMS', 'JFK', 'LHR')."
        },
        "city": {
          "type": "string",
          "description": "City name (e.g., 'Amsterdam', 'New York')."
        }
      },
      "required": [
        "airport_code"
      ],
      "additionalProperties": false
    },
    "destination": {
      "type": "object",
      "description": "Arrival airport or city.",
      "properties": {
        "airport_code": {
          "type": "string",
          "pattern": "^[A-Z]{3}$",
          "description": "IATA airport code."
        },
        "city": {
          "type": "string",
          "description": "City name."
        }
      },
      "required": [
        "airport_code"
      ],
      "additionalProperties": false
    },
    "airline": {
      "type": "string",
      "description": "Airline name or IATA airline code."
    },
    "price": {
      "$ref": "/schemas/3.1.0/core/price.json",
      "description": "Ticket price or starting fare."
    },
    "description": {
      "type": "string",
      "description": "Route description or promotional text."
    },
    "departure_time": {
      "type": "string",
      "format": "date-time",
      "description": "Departure date and time (ISO 8601)."
    },
    "arrival_time": {
      "type": "string",
      "format": "date-time",
      "description": "Arrival date and time (ISO 8601)."
    },
    "image_url": {
      "type": "string",
      "format": "uri",
      "description": "Promotional image URL (typically a destination photo)."
    },
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Booking page URL for this route."
    },
    "tags": {
      "type": "array",
      "description": "Tags for filtering (e.g., 'direct', 'red-eye', 'business-class').",
      "items": {
        "type": "string"
      },
      "minItems": 1
    },
    "assets": {
      "type": "array",
      "description": "Typed creative asset pools for this flight. Uses the same OfferingAssetGroup structure as offering-type catalogs. Standard group IDs: 'images_landscape' (destination hero), 'images_vertical' (9:16 for Stories), 'images_square' (1:1). Enables formats to declare typed image requirements that map unambiguously to the right asset regardless of platform.",
      "items": {
        "$ref": "/schemas/3.1.0/core/offering-asset-group.json"
      },
      "minItems": 1
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "flight_id",
    "origin",
    "destination"
  ],
  "additionalProperties": true,
  "examples": [
    {
      "description": "Direct transatlantic route",
      "data": {
        "flight_id": "ams-jfk-summer",
        "origin": {
          "airport_code": "AMS",
          "city": "Amsterdam"
        },
        "destination": {
          "airport_code": "JFK",
          "city": "New York"
        },
        "airline": "KLM",
        "price": {
          "amount": 449,
          "currency": "EUR"
        },
        "description": "Direct flights from Amsterdam to New York, daily departures.",
        "image_url": "https://images.acmeair.com/routes/ams-jfk.jpg",
        "url": "https://acmeair.com/flights/ams-jfk",
        "tags": [
          "direct",
          "transatlantic"
        ]
      }
    },
    {
      "description": "Budget European route",
      "data": {
        "flight_id": "bcn-lis-q4",
        "origin": {
          "airport_code": "BCN",
          "city": "Barcelona"
        },
        "destination": {
          "airport_code": "LIS",
          "city": "Lisbon"
        },
        "price": {
          "amount": 39,
          "currency": "EUR"
        },
        "url": "https://acmeair.com/flights/bcn-lis",
        "tags": [
          "budget",
          "short-haul"
        ]
      }
    }
  ]
} as const;

