export const core_OptimizationGoal = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/optimization-goal.json",
  "title": "Optimization Goal",
  "description": "A single optimization target for a package. Packages accept an array of optimization_goals. When multiple goals are present, priority determines which the seller focuses on — 1 is highest priority (primary goal); higher numbers are secondary. When priorities are present but no goal is priority 1, the goal with the lowest priority value is primary (e.g., priorities of 2 and 3 mean 2 is primary). Duplicate priority values result in undefined seller behavior.",
  "discriminator": {
    "propertyName": "kind"
  },
  "oneOf": [
    {
      "type": "object",
      "description": "Optimize for a seller-tracked delivery metric. No event source required — the seller tracks these natively.",
      "properties": {
        "kind": {
          "type": "string",
          "const": "metric"
        },
        "metric": {
          "type": "string",
          "enum": [
            "clicks",
            "views",
            "completed_views",
            "viewed_seconds",
            "attention_seconds",
            "attention_score",
            "engagements",
            "follows",
            "saves",
            "profile_visits",
            "reach"
          ],
          "description": "Seller-native metric to optimize for. Delivery metrics: clicks (link clicks, swipe-throughs, CTA taps that navigate away), views (viewable impressions), completed_views (video/audio completions — see view_duration_seconds), reach (unique audience reach — see reach_unit and target_frequency). Duration/score metrics: viewed_seconds (time in view per impression — reported back via `delivery-metrics.viewability.viewed_seconds`, governed by the viewability `standard`). Audience action metrics: engagements (any direct interaction with the ad unit beyond viewing — social reactions/comments/shares, story/unit opens, interactive overlay taps, companion banner interactions on audio and CTV), follows (new followers, page likes, artist/podcast/channel follows, or free channel/feed subscribes; paid subscriptions use event_type: subscribe), saves (saves, bookmarks, playlist adds, pins — signals of intent to return), profile_visits (visits to the brand's in-platform page — profile, artist page, channel, or storefront. Does not include external website clicks, which are covered by 'clicks'). **DEPRECATED values** (slated for removal at next major): `attention_seconds` and `attention_score` — these have no industry-graduated definition (DoubleVerify, IAS, Adelaide, TVision, Lumen each define them differently) and cannot be meaningfully optimized for without a vendor binding. Use `kind: 'vendor_metric'` with an explicit `vendor` and `metric_id` instead — that path binds the goal to a specific measurement vendor and reconciles to the same `(vendor, metric_id)` key in delivery's `vendor_metric_values[]`. Sellers MAY reject the deprecated values with `TERMS_REJECTED` and a suggestion to use the `vendor_metric` kind."
        },
        "reach_unit": {
          "allOf": [
            {
              "$ref": "/schemas/3.1.0/enums/reach-unit.json"
            }
          ],
          "description": "Unit for reach measurement. Required when metric is 'reach'. Must be a value declared in the product's metric_optimization.supported_reach_units."
        },
        "target_frequency": {
          "type": "object",
          "description": "Target frequency band for reach optimization. Only applicable when metric is 'reach'. Frames frequency as an optimization signal: the seller should treat impressions toward entities already within the [min, max] band as lower-value, and impressions toward unreached entities as higher-value. This shifts budget toward fresh reach rather than re-reaching known users. When omitted, the seller maximizes unique reach without a frequency constraint. A hard cap can still be layered via targeting_overlay.frequency_cap if a ceiling is needed.",
          "properties": {
            "min": {
              "type": "integer",
              "minimum": 1,
              "description": "Minimum frequency for an entity to be considered meaningfully reached within the window. Impressions that would bring an entity below this threshold are treated as high-value (growing reach). When omitted, the seller uses their platform default (typically 1)."
            },
            "max": {
              "type": "integer",
              "minimum": 1,
              "description": "Frequency at which an entity is considered saturated within the window. Impressions toward entities at or above this threshold are treated as lower-value. When both min and max are present, max must be greater than or equal to min. When omitted, the seller determines the saturation point."
            },
            "window": {
              "allOf": [
                {
                  "$ref": "/schemas/3.1.0/core/duration.json"
                }
              ],
              "description": "Time window over which frequency is measured (e.g. {\"interval\": 7, \"unit\": \"days\"} or {\"interval\": 1, \"unit\": \"campaign\"} for the full flight). Weekly windows are typical for brand campaigns; daily windows suit high-cadence direct response."
            }
          },
          "required": [
            "window"
          ],
          "anyOf": [
            {
              "required": [
                "min"
              ]
            },
            {
              "required": [
                "max"
              ]
            }
          ],
          "additionalProperties": true
        },
        "view_duration_seconds": {
          "type": "number",
          "exclusiveMinimum": 0,
          "description": "Minimum video view duration in seconds that qualifies as a completed_view for this goal. Only applicable when metric is 'completed_views'. When omitted, the seller uses their platform default (typically 2–15 seconds). Common values: 2 (Snap/LinkedIn default), 6 (TikTok), 15 (Snap 15-second views, Meta ThruPlay). Sellers declare which durations they support in metric_optimization.supported_view_durations. Sellers must reject goals with unsupported values — silent rounding would create measurement discrepancies."
        },
        "target": {
          "description": "Target for this metric. When omitted, the seller optimizes for maximum metric volume within budget.",
          "discriminator": {
            "propertyName": "kind"
          },
          "oneOf": [
            {
              "type": "object",
              "description": "Target cost per unit of the metric (e.g., cost per click, cost per completed view).",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "cost_per"
                },
                "value": {
                  "type": "number",
                  "exclusiveMinimum": 0,
                  "description": "Target cost per metric unit in the buy currency"
                }
              },
              "required": [
                "kind",
                "value"
              ],
              "additionalProperties": true
            },
            {
              "type": "object",
              "description": "Minimum per-impression rate for this metric. The metric defines the units: proportions for count metrics (e.g., 0.001 for 0.1% CTR, 0.70 for 70% viewability), seconds for duration metrics (e.g., 3.0 for 3s in view), or score for score metrics.",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "threshold_rate"
                },
                "value": {
                  "type": "number",
                  "exclusiveMinimum": 0,
                  "description": "Minimum per-impression value. Units depend on the metric: proportion (clicks, views, completed_views), seconds (viewed_seconds, attention_seconds), or score (attention_score)."
                }
              },
              "required": [
                "kind",
                "value"
              ],
              "additionalProperties": true
            }
          ]
        },
        "priority": {
          "type": "integer",
          "minimum": 1,
          "description": "Relative priority among all optimization goals on this package. 1 = highest priority (primary goal); higher numbers are lower priority (secondary signals). When omitted, sellers may use array position as priority."
        }
      },
      "required": [
        "kind",
        "metric"
      ],
      "additionalProperties": true
    },
    {
      "type": "object",
      "description": "Optimize for advertiser-tracked conversion events. Requires event sources registered via sync_event_sources.",
      "properties": {
        "kind": {
          "type": "string",
          "const": "event"
        },
        "event_sources": {
          "type": "array",
          "description": "Event source and type pairs that feed this goal. Each entry identifies a source and event type to include. When the seller supports multi_source_event_dedup (declared in get_adcp_capabilities), they deduplicate by event_id across all entries — the same business event from multiple sources counts once, using value_field and value_factor from the first matching entry. When multi_source_event_dedup is false or absent, buyers should use a single entry per goal; the seller will use only the first entry. All event sources must be configured via sync_event_sources.",
          "items": {
            "type": "object",
            "properties": {
              "event_source_id": {
                "type": "string",
                "minLength": 1,
                "description": "Event source to include (must be configured on this account via sync_event_sources)"
              },
              "event_type": {
                "$ref": "/schemas/3.1.0/enums/event-type.json",
                "description": "Event type to include from this source (e.g., purchase, lead, app_install, refund)"
              },
              "custom_event_name": {
                "type": "string",
                "description": "Required when event_type is 'custom'. Platform-specific name for the custom event."
              },
              "value_field": {
                "type": "string",
                "description": "Which field in the event's custom_data carries the monetary value. The seller must use this field for value extraction and aggregation when computing ROAS and conversion value metrics. Required on at least one entry when target.kind is 'per_ad_spend' or 'maximize_value' — sellers must reject these target kinds when no event source entry includes value_field. When present without a value-oriented target, the seller may use it for delivery reporting (conversion_value, roas) but must not change the optimization objective. Common values: 'value', 'order_total', 'profit_margin'. This is not passed as a parameter to underlying platform APIs — the seller maps it to their platform's value ingestion mechanism."
              },
              "value_factor": {
                "type": "number",
                "default": 1,
                "description": "Multiplier the seller must apply to value_field before aggregation. Use -1 for refund events (negate the value), 0.01 for values in cents, -0.01 for refunds in cents. A value of 0 zeroes out this source's value contribution (the source still counts for event dedup). Defaults to 1. This is not passed as a parameter to underlying platform APIs — the seller applies it when computing aggregated value metrics."
              }
            },
            "required": [
              "event_source_id",
              "event_type"
            ],
            "additionalProperties": true
          },
          "minItems": 1
        },
        "target": {
          "description": "Target cost or return for this event goal. When omitted, the seller optimizes for maximum conversion count within budget — regardless of whether value_field is present on event sources. The presence of value_field alone does not change the optimization objective; it only makes value available for reporting. An explicit target of maximize_value or per_ad_spend is required to steer toward value.",
          "discriminator": {
            "propertyName": "kind"
          },
          "oneOf": [
            {
              "type": "object",
              "description": "Target cost per conversion event (after deduplication across event_sources).",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "cost_per"
                },
                "value": {
                  "type": "number",
                  "exclusiveMinimum": 0,
                  "description": "Target cost per event in the buy currency"
                }
              },
              "required": [
                "kind",
                "value"
              ],
              "additionalProperties": true
            },
            {
              "type": "object",
              "description": "Target return per unit of ad spend, calculated as sum(value_field * value_factor) / spend across all deduplicated events. Requires value_field on at least one event_sources entry.",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "per_ad_spend"
                },
                "value": {
                  "type": "number",
                  "exclusiveMinimum": 0,
                  "description": "Target return ratio (e.g., 4.0 means $4 of value per $1 spent)"
                }
              },
              "required": [
                "kind",
                "value"
              ],
              "additionalProperties": true
            },
            {
              "type": "object",
              "description": "Maximize total conversion value within budget, without a specific return ratio target. Steers spend toward higher-value conversions rather than maximizing conversion count. Requires value_field on at least one event_sources entry.",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "maximize_value"
                }
              },
              "required": [
                "kind"
              ],
              "additionalProperties": true
            }
          ]
        },
        "attribution_window": {
          "allOf": [
            {
              "$ref": "/schemas/3.1.0/core/attribution-window.json"
            }
          ],
          "description": "Attribution window for this optimization goal — references the canonical `attribution-window` shape (post_click, post_view, model). Values must match an option declared in the seller's `conversion_tracking.attribution_windows` capability. Sellers MUST reject windows not in their declared capabilities. When the entire field is omitted, the seller uses their default window."
        },
        "priority": {
          "type": "integer",
          "minimum": 1,
          "description": "Relative priority among all optimization goals on this package. 1 = highest priority (primary goal); higher numbers are lower priority (secondary signals). When omitted, sellers may use array position as priority."
        }
      },
      "required": [
        "kind",
        "event_sources"
      ],
      "additionalProperties": true
    },
    {
      "type": "object",
      "description": "Optimize for a vendor-attested measurement metric. Use when the metric has no graduated industry-standard definition and must be reconciled to a specific vendor — e.g., attention (DoubleVerify, IAS, Adelaide, TVision, Lumen), panel-based brand lift (Kantar, Upwave, Cint), emissions (Scope3, Good-Loop), retail-media partner metrics. The vendor + metric_id pair binds buyer→seller→vendor end-to-end: the seller's bidding stack steers toward this specific vendor's measurement, and delivery reports the value via `vendor_metric_values[]` with the same `(vendor, metric_id)` key. Three preconditions for goal acceptance: (1) Discovery — the `metric_id` SHOULD appear in the vendor's published `measurement.metrics[]` catalog (queried from the vendor's `brand.json` `agents[type='measurement']`). Sellers SHOULD verify against a cached snapshot of the vendor's capability response; staleness handling is implementation-defined. SHOULD this minor while measurement-vendor adoption of AdCP-conformant capability publication catches up; tightens to MUST at the next minor. (2) Capability — the `(vendor, metric_id)` pair MUST appear in the product's `vendor_metric_optimization.supported_metrics[]`, and the goal's `target.kind` MUST appear in that entry's `supported_targets`. (3) Reporting coherence — the package's `committed_metrics[]` MUST include a matching `{ scope: 'vendor', vendor, metric_id }` entry. Sellers MUST reject goals failing the capability or reporting-coherence preconditions. Optimization without committed reporting is unverifiable and is therefore disallowed at the wire level. Precondition checks are seller-runtime; the schema's `required` only validates structural presence of `kind`, `vendor`, and `metric_id`.",
      "properties": {
        "kind": {
          "type": "string",
          "const": "vendor_metric"
        },
        "vendor": {
          "$ref": "/schemas/3.1.0/core/brand-ref.json",
          "description": "Vendor that defines and computes this metric. Same shape as `vendor_metric_values.vendor`, `reporting_capabilities.vendor_metrics[].vendor`, and `vendor_metric_optimization.supported_metrics[].vendor` — symmetric across discovery, capability, commitment, optimization, and reporting surfaces."
        },
        "metric_id": {
          "$ref": "/schemas/3.1.0/core/vendor-metric-id.json",
          "description": "Identifier for the metric within the vendor's vocabulary (e.g., `attention_score`, `attention_seconds`, `gco2e_per_impression`, `awareness_lift`). MUST be present in the vendor's published `measurement.metrics[]` catalog and in the product's `vendor_metric_optimization.supported_metrics[]`."
        },
        "target": {
          "description": "Target for this vendor metric. When omitted, the seller optimizes for maximum metric volume / score within budget. `cost_per` and `threshold_rate` semantics mirror the same target kinds on the `metric` kind — units are vendor-defined and depend on the vendor's `measurement.metrics[]` declaration for this `metric_id`.",
          "discriminator": {
            "propertyName": "kind"
          },
          "oneOf": [
            {
              "type": "object",
              "description": "Target cost per unit of the vendor metric (e.g., cost per attention-second).",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "cost_per"
                },
                "value": {
                  "type": "number",
                  "exclusiveMinimum": 0,
                  "description": "Target cost per metric unit in the buy currency. Units of the metric are vendor-defined."
                }
              },
              "required": [
                "kind",
                "value"
              ],
              "additionalProperties": true
            },
            {
              "type": "object",
              "description": "Minimum per-impression value for this vendor metric (e.g., attention_score ≥ 70).",
              "properties": {
                "kind": {
                  "type": "string",
                  "const": "threshold_rate"
                },
                "value": {
                  "type": "number",
                  "exclusiveMinimum": 0,
                  "description": "Minimum per-impression value. Units of the metric are vendor-defined."
                }
              },
              "required": [
                "kind",
                "value"
              ],
              "additionalProperties": true
            }
          ]
        },
        "priority": {
          "type": "integer",
          "minimum": 1,
          "description": "Relative priority among all optimization goals on this package. 1 = highest priority (primary goal); higher numbers are lower priority (secondary signals). When omitted, sellers may use array position as priority."
        }
      },
      "required": [
        "kind",
        "vendor",
        "metric_id"
      ],
      "additionalProperties": true
    }
  ]
} as const;

export const core_OutcomeMeasurement = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/outcome-measurement.json",
  "title": "Outcome Measurement (Deprecated)",
  "description": "**Deprecated as of this minor.** Predates the unified measurement-vocabulary pattern. Outcome metrics (incremental_sales_lift, brand_lift, foot_traffic, conversion_lift, brand_search_lift, attributed sales) are now expressible through the same primitives as the rest of the measurement surface:\n\n- **Outcome metric capability** → declared via `reporting_capabilities.available_metrics` on the product. Closed enum entries: `incremental_sales_lift`, `brand_lift`, `foot_traffic`, `conversion_lift`, `brand_search_lift`. Existing entries `conversions`, `conversion_value`, `roas`, `cost_per_acquisition`, `units_sold`, `new_to_brand_rate`, `new_to_brand_units`, `leads` already covered most outcome-metric needs.\n- **Attributed sales** (the retail-media value prop) → `conversion_value` with `qualifier.attribution_methodology: 'deterministic_purchase'`. **Walmart Connect's `attributedSalesIn14Days`** maps to `conversion_value` + `qualifier.attribution_methodology: 'deterministic_purchase'` + `qualifier.attribution_window: {interval: 14, unit: 'days'}`. Same pattern for Amazon DSP attributed sales, Kroger Precision attributed sales, Criteo Retail Media attributed sales — the protocol does not invent a separate `attributed_sales` metric ID because the qualifier handles the methodology split.\n- **Brand lift** → `brand_lift` metric_id PLUS `qualifier.lift_dimension` (closed enum: awareness, consideration, favorability, purchase_intent, ad_recall). Brand-lift vendors (Kantar, Upwave, Cint, DV) report each dimension separately; the qualifier ensures rows aren't combined.\n- **Attribution methodology** → `qualifier.attribution_methodology` (`deterministic_purchase`, `probabilistic`, `panel_based`, `modeled`).\n- **Attribution window** → `qualifier.attribution_window` (structured duration `{interval, unit}`, never a shorthand string).\n- **Vendor identity** (typically the seller for retail-media closed loop) → vendor-scope `committed_metrics` entries with the BrandRef anchored on the seller's measurement-agent capability (or absent when the seller is the implicit vendor). For third-party retail measurement (Circana, NielsenIQ, IRI for retail MMM; Kantar/Upwave for brand lift on retail-media inventory), use `performance_standards.vendor` to pin the third-party identity.\n- **Reporting frequency / format** → planned for a follow-up `reporting_capabilities` extension; existing `outcome_measurement.reporting` field continues to work for one minor.\n\nThis schema is retained for one-minor backwards compatibility on `product.outcome_measurement`. Removed at the next major. New implementations SHOULD declare outcome capabilities via `reporting_capabilities.available_metrics` and consumers reconcile via `committed_metrics`/`metric_aggregates` with the appropriate qualifier.",
  "type": "object",
  "properties": {
    "type": {
      "type": "string",
      "description": "Type of measurement",
      "examples": [
        "incremental_sales_lift",
        "brand_lift",
        "foot_traffic"
      ]
    },
    "attribution": {
      "type": "string",
      "description": "Attribution methodology",
      "examples": [
        "deterministic_purchase",
        "probabilistic"
      ]
    },
    "window": {
      "allOf": [
        {
          "$ref": "/schemas/3.1.0/core/duration.json"
        }
      ],
      "description": "Attribution window as a structured duration (e.g., {\"interval\": 30, \"unit\": \"days\"})."
    },
    "reporting": {
      "type": "string",
      "description": "Reporting frequency and format",
      "examples": [
        "weekly_dashboard",
        "real_time_api"
      ]
    }
  },
  "required": [
    "type",
    "attribution",
    "reporting"
  ],
  "additionalProperties": true
} as const;

export const core_Overlay = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/overlay.json",
  "title": "Overlay",
  "description": "A publisher-controlled element that renders on top of buyer creative content within the ad placement. Creative agents should avoid placing critical content (CTAs, logos, key copy) within overlay bounds.",
  "type": "object",
  "properties": {
    "id": {
      "type": "string",
      "description": "Identifier for this overlay (e.g., 'play_pause', 'volume', 'publisher_logo', 'carousel_prev', 'carousel_next')"
    },
    "description": {
      "type": "string",
      "description": "Human-readable explanation of what this overlay is and how buyers should account for it"
    },
    "visual": {
      "type": "object",
      "description": "Optional visual reference for this overlay element. Useful for creative agents compositing previews and for buyers understanding what will appear over their content. Must include at least one of: url, light, or dark.",
      "properties": {
        "url": {
          "type": "string",
          "format": "uri",
          "description": "URL to a theme-neutral overlay graphic (SVG or PNG). Use when a single file works for all backgrounds, e.g. an SVG using CSS custom properties or currentColor."
        },
        "light": {
          "type": "string",
          "format": "uri",
          "description": "URL to the overlay graphic for use on light/bright backgrounds (SVG or PNG)"
        },
        "dark": {
          "type": "string",
          "format": "uri",
          "description": "URL to the overlay graphic for use on dark backgrounds (SVG or PNG)"
        }
      },
      "minProperties": 1,
      "additionalProperties": false
    },
    "bounds": {
      "type": "object",
      "description": "Position and size of the overlay relative to the asset's own top-left corner. See 'unit' for coordinate interpretation.",
      "properties": {
        "x": {
          "type": "number",
          "description": "Horizontal offset from the asset's left edge"
        },
        "y": {
          "type": "number",
          "description": "Vertical offset from the asset's top edge"
        },
        "width": {
          "type": "number",
          "minimum": 0,
          "description": "Width of the overlay"
        },
        "height": {
          "type": "number",
          "minimum": 0,
          "description": "Height of the overlay"
        },
        "unit": {
          "type": "string",
          "enum": [
            "px",
            "fraction",
            "inches",
            "cm",
            "mm",
            "pt"
          ],
          "description": "'px' = absolute pixels from asset top-left. 'fraction' = proportional to asset dimensions (0.0 = edge, 1.0 = opposite edge). 'inches', 'cm', 'mm', 'pt' (1/72 inch) = physical units for print overlays, measured from asset top-left."
        }
      },
      "required": [
        "x",
        "y",
        "width",
        "height",
        "unit"
      ],
      "additionalProperties": false
    }
  },
  "required": [
    "id",
    "bounds"
  ],
  "additionalProperties": false
} as const;

export const core_PackageSignalTargetingGroup = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/package-signal-targeting-group.json",
  "title": "Package Signal Targeting Group",
  "description": "A basic Boolean group of package-level signal targeting entries. 'any' means the user must match at least one signal in the group. 'none' means the user must match none of the signals in the group. Use groups for portable include/exclude composition such as (A OR B) AND NOT (C OR D).",
  "type": "object",
  "properties": {
    "operator": {
      "type": "string",
      "description": "How to evaluate the signals in this group. 'any' is an OR include group. 'none' is an exclusion group equivalent to NOT (A OR B OR C).",
      "enum": [
        "any",
        "none"
      ]
    },
    "signals": {
      "type": "array",
      "description": "Signal targeting entries evaluated by this group. Each entry uses the package signal targeting shape, including signal_ref, value expression, and optional pricing, execution-handle, or activation fields.",
      "items": {
        "$ref": "/schemas/3.1.0/core/package-signal-targeting.json"
      },
      "minItems": 1
    }
  },
  "required": [
    "operator",
    "signals"
  ],
  "additionalProperties": true
} as const;

export const core_PackageSignalTargetingGroups = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/package-signal-targeting-groups.json",
  "title": "Package Signal Targeting Groups",
  "description": "Top-level basic Boolean composition for package signal targeting. The groups-level operator is required; v1 supports operator 'all', meaning every child group must be satisfied. This represents the portable baseline: (any of include group 1) AND (any of include group 2) AND NOT (any of exclude group N).",
  "type": "object",
  "properties": {
    "operator": {
      "type": "string",
      "enum": [
        "all"
      ],
      "description": "Groups-level operator. Required even though v1 only supports 'all': every child group must be satisfied."
    },
    "groups": {
      "type": "array",
      "description": "Signal targeting groups to evaluate. Use operator 'any' for include groups and 'none' for exclusion groups.",
      "items": {
        "$ref": "/schemas/3.1.0/core/package-signal-targeting-group.json"
      },
      "minItems": 1
    }
  },
  "required": [
    "operator",
    "groups"
  ],
  "additionalProperties": true
} as const;

export const core_PackageSignalTargeting = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/package-signal-targeting.json",
  "title": "Package Signal Targeting",
  "description": "Buy-time selection of one seller-offered signal inside a package signal targeting group. The signal_ref uses scope 'product' for a product-local signal option, scope 'data_provider' for a signal defined in a data provider's published adagents.json signals[], or scope 'signal_source' for a source-native signal that is not published in adagents.json signals[]. The selected product's inline Product.signal_targeting_options, get_signals feed when inline options are omitted, and signal_targeting_rules define buy-time eligibility. Inclusion and exclusion are controlled by the parent group operator: use operator 'any' to include users matching the signal expression and operator 'none' to exclude users matching the signal expression. For binary signals, value MUST be true; do not use value=false for exclusion inside signal_targeting_groups. Use audience_include/audience_exclude only for buyer-managed first-party audiences registered through sync_audiences.",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/signal-targeting-expression.json"
    }
  ],
  "properties": {
    "pricing_option_id": {
      "type": "string",
      "description": "Pricing option selected for this signal. Use the pricing_option_id from the product's signal_targeting_options entry when product-scoped pricing is present; otherwise use the seller get_signals pricing only when the product option does not override it. Required when the selected signal has pricing_options; omit only when the signal is bundled into the product price or has no incremental cost.",
      "x-entity": "vendor_pricing_option"
    },
    "signal_agent_segment_id": {
      "type": "string",
      "description": "Optional opaque resolved-segment or seller execution handle for this signal. Omit when signal_ref plus the value expression is sufficient for the seller to resolve the signal. Include when the product option exposes a separate runtime or activation handle, and pass it verbatim. Buyers SHOULD prefer an exposed segment handle over reconstructing condition identity from categorical values because the handle can carry provider namespace and methodology distinctions.",
      "x-entity": "signal_activation_id"
    },
    "activation_key": {
      "$ref": "/schemas/3.1.0/core/activation-key.json",
      "description": "Destination-specific activation key returned by get_signals or activate_signal. Usually omitted for seller-offered signals selected directly through the same seller; include only when the selected signal was separately activated and the seller requires the activation key to correlate the package selection."
    }
  },
  "additionalProperties": true
} as const;

export const core_PackageSchema = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/package.json",
  "title": "Package",
  "description": "A specific product within a media buy (line item)",
  "type": "object",
  "properties": {
    "package_id": {
      "type": "string",
      "description": "Seller's unique identifier for the package",
      "x-entity": "package"
    },
    "product_id": {
      "type": "string",
      "description": "ID of the product this package is based on. For packages created from an explicit create_media_buy package request, sellers MUST echo the request package's product_id on every response package object that represents that requested package.",
      "x-entity": "product"
    },
    "budget": {
      "type": "number",
      "description": "Budget allocation for this package in the currency specified by the pricing option",
      "minimum": 0
    },
    "pacing": {
      "$ref": "/schemas/3.1.0/enums/pacing.json"
    },
    "pricing_option_id": {
      "type": "string",
      "description": "ID of the selected pricing option from the product's pricing_options array",
      "x-entity": "product_pricing_option"
    },
    "bid_price": {
      "type": "number",
      "description": "Bid price for auction-based pricing. This is the exact bid/price to honor unless the selected pricing option has max_bid=true, in which case bid_price is the buyer's maximum willingness to pay (ceiling).",
      "minimum": 0
    },
    "price_breakdown": {
      "description": "Breakdown of the effective price for this package. On fixed-price packages, echoes the pricing option's breakdown. On auction packages, shows the clearing price breakdown including any commission or settlement terms.",
      "$ref": "/schemas/3.1.0/pricing-options/price-breakdown.json"
    },
    "impressions": {
      "type": "number",
      "description": "Impression goal for this package",
      "minimum": 0
    },
    "catalogs": {
      "type": "array",
      "description": "Catalogs this package promotes. Each catalog MUST have a distinct type (e.g., one product catalog, one store catalog). This constraint is enforced at the application level — sellers MUST reject requests containing multiple catalogs of the same type with a validation_error. Echoed from the create_media_buy request.",
      "items": {
        "$ref": "/schemas/3.1.0/core/catalog.json"
      }
    },
    "format_ids": {
      "type": "array",
      "description": "Legacy named-format IDs supplied for this package on create_media_buy. Sellers SHOULD echo this field whenever the request included it, including dual-emission cases where `format_option_refs` was the winning selector, so read surfaces preserve the original wire contract. Omitted means the request did not carry legacy format_ids unless the seller cannot reconstruct legacy requests created before this field was persisted.",
      "items": {
        "$ref": "/schemas/3.1.0/core/format-id.json"
      }
    },
    "format_option_refs": {
      "type": "array",
      "description": "Structured 3.1+ format option references supplied for this package on create_media_buy. Sellers SHOULD echo this field whenever the request included it. Publisher-catalog-backed options are identified by `{ scope: \"publisher\", publisher_domain, format_option_id }`; product-local options are identified by `{ scope: \"product\", format_option_id }` and resolve only against this package's target product. Omitted means the request did not carry format_option_refs unless the seller cannot reconstruct legacy requests created before this field was persisted.",
      "items": {
        "$ref": "/schemas/3.1.0/core/format-option-ref.json"
      },
      "minItems": 1
    },
    "format_kind": {
      "$ref": "/schemas/3.1.0/core/canonical-format-kind.json",
      "description": "Direct canonical selector supplied for this package on create_media_buy. Sellers SHOULD echo this field whenever the request included it, including informational-echo cases where `format_ids` was the winning selector, so read surfaces preserve the original wire contract."
    },
    "params": {
      "type": "object",
      "description": "Parameters for the direct canonical selector in `format_kind`, echoed from the create_media_buy request whenever the request included it. Requires `format_kind`; omitted only when the request did not carry direct canonical params or when the seller cannot reconstruct legacy requests created before this field was persisted.",
      "additionalProperties": true
    },
    "targeting_overlay": {
      "$ref": "/schemas/3.1.0/core/targeting.json"
    },
    "measurement_terms": {
      "$ref": "/schemas/3.1.0/core/measurement-terms.json",
      "description": "Agreed billing measurement and makegood terms for this package. Reflects what was negotiated — may differ from the buyer's proposal or the product's defaults. When present, these terms are binding for the package's duration."
    },
    "performance_standards": {
      "type": "array",
      "description": "Agreed performance standards for this package. When any entry specifies a vendor, creatives assigned to this package MUST include corresponding tracker_script or tracker_pixel assets from that vendor.",
      "items": {
        "$ref": "/schemas/3.1.0/core/performance-standard.json"
      },
      "minItems": 1
    },
    "committed_metrics": {
      "type": "array",
      "description": "The binding reporting contract for this package — what the seller has agreed to populate in delivery reports. Each entry carries an explicit `committed_at` timestamp, so the array also serves as the contract amendment ledger: day-1 commitments share `committed_at = create_media_buy.confirmed_at`; mid-flight additions carry their own timestamps. When `create_media_buy.confirmed_at` is null for a provisional buy, sellers MUST omit `committed_metrics` until commitment. The first response that sets `confirmed_at` MAY include the initial committed-metrics set, and each such entry's `committed_at` MUST equal `confirmed_at`. The `missing_metrics` field on `get_media_buy_delivery` reconciles against this list, filtering to entries where `committed_at < reporting_period.end` (a metric committed mid-flight is only audited from its commitment timestamp forward). Sellers stamp the day-1 set on the `create_media_buy` response; mid-flight additions are appended via `update_media_buy` (append-only — sellers MUST reject attempts to modify or remove existing entries with `validation_error`, suggested code: `IMMUTABLE_FIELD`). Optional in v1; absence means the seller does not provide an audit-grade contract and `missing_metrics` falls back to the product's live `available_metrics` (a known audit gap — buyers SHOULD treat absence as 'no audit-grade contract' rather than 'clean delivery'). Each entry uses an explicit `scope` discriminator: `standard` for entries from the closed `available-metric.json` enum, `vendor` for vendor-defined metrics anchored on a BrandRef. The unified shape is symmetric with `missing_metrics` and `aggregated_totals.metric_aggregates` — same atomic unit `(scope, metric_id, qualifier)` across contract, diff, and delivery, so reconciliation collapses to a row-level join on the tuple. Replaces the parallel-array design that shipped briefly in #3510.",
      "items": {
        "$ref": "/schemas/3.1.0/core/committed-metric.json"
      },
      "minItems": 1,
      "examples": [
        [
          {
            "scope": "standard",
            "metric_id": "impressions",
            "committed_at": "2026-04-29T10:53:00Z"
          },
          {
            "scope": "standard",
            "metric_id": "spend",
            "committed_at": "2026-04-29T10:53:00Z"
          },
          {
            "scope": "standard",
            "metric_id": "completed_views",
            "committed_at": "2026-04-29T10:53:00Z"
          },
          {
            "scope": "vendor",
            "vendor": {
              "domain": "attentionvendor.example"
            },
            "metric_id": "attention_units",
            "committed_at": "2026-04-29T10:53:00Z"
          },
          {
            "scope": "standard",
            "metric_id": "viewable_rate",
            "qualifier": {
              "viewability_standard": "mrc"
            },
            "committed_at": "2026-05-30T14:22:00Z"
          }
        ]
      ]
    },
    "creative_assignments": {
      "type": "array",
      "description": "Creative assets assigned to this package",
      "items": {
        "$ref": "/schemas/3.1.0/core/creative-assignment.json"
      }
    },
    "format_ids_to_provide": {
      "type": "array",
      "description": "Format IDs that creative assets will be provided for this package",
      "items": {
        "$ref": "/schemas/3.1.0/core/format-id.json"
      }
    },
    "optimization_goals": {
      "type": "array",
      "description": "Optimization targets for this package. The seller optimizes delivery toward these goals in priority order. Common pattern: event goals (purchase, install) as primary targets at priority 1; metric goals (clicks, views) as secondary proxy signals at priority 2+.",
      "items": {
        "$ref": "/schemas/3.1.0/core/optimization-goal.json"
      },
      "minItems": 1
    },
    "start_time": {
      "type": "string",
      "format": "date-time",
      "not": {
        "const": "asap"
      },
      "description": "Flight start date/time for this package in ISO 8601 format. When omitted, the package inherits the media buy's start_time. Sellers SHOULD always include the resolved value in responses, even when inherited."
    },
    "end_time": {
      "type": "string",
      "format": "date-time",
      "description": "Flight end date/time for this package in ISO 8601 format. When omitted, the package inherits the media buy's end_time. Sellers SHOULD always include the resolved value in responses, even when inherited."
    },
    "paused": {
      "type": "boolean",
      "description": "Whether this package is paused by the buyer. Paused packages do not deliver impressions. Defaults to false.",
      "default": false
    },
    "canceled": {
      "type": "boolean",
      "description": "Whether this package has been canceled. Canceled packages stop delivery and cannot be reactivated. Defaults to false.",
      "default": false
    },
    "cancellation": {
      "type": "object",
      "description": "Cancellation metadata. Present only when canceled is true.",
      "required": [
        "canceled_at",
        "canceled_by"
      ],
      "properties": {
        "canceled_at": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp when this package was canceled."
        },
        "canceled_by": {
          "$ref": "/schemas/3.1.0/enums/canceled-by.json",
          "description": "Which party initiated the package cancellation."
        },
        "reason": {
          "type": "string",
          "description": "Reason the package was canceled.",
          "maxLength": 500
        },
        "acknowledged_at": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp when the seller acknowledged the cancellation. Confirms inventory has been released and billing stopped. Absent until the seller processes the cancellation."
        }
      },
      "additionalProperties": false
    },
    "agency_estimate_number": {
      "type": "string",
      "maxLength": 100,
      "description": "Agency estimate or authorization number for this package. Echoed from the buyer's request. When present on the package, takes precedence over the media buy-level estimate number."
    },
    "creative_deadline": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp for creative upload or change deadline for this package. After this deadline, creative changes are rejected. When absent, the media buy's creative_deadline applies."
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json",
      "description": "Opaque package-level correlation data echoed unchanged in responses, webhooks, and read surfaces. Buyers targeting mixed seller populations SHOULD include a per-package correlation value here, commonly context.buyer_ref, so responses from legacy sellers that do not echo product_id can still be mapped back to the requested product or line item. Sellers MUST preserve this object unchanged and MUST NOT parse it for business logic."
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "package_id"
  ],
  "dependencies": {
    "params": [
      "format_kind"
    ]
  },
  "additionalProperties": true
} as const;

