export const core_Price = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/price.json",
  "title": "Price",
  "description": "A monetary amount with currency and optional billing period. Used across catalog item types for product prices, nightly hotel rates, salary ranges, rental costs, and similar monetary values.",
  "type": "object",
  "properties": {
    "amount": {
      "type": "number",
      "minimum": 0,
      "description": "Monetary amount in the specified currency."
    },
    "currency": {
      "type": "string",
      "pattern": "^[A-Z]{3}$",
      "description": "ISO 4217 currency code (e.g., 'USD', 'EUR', 'GBP')."
    },
    "period": {
      "type": "string",
      "enum": [
        "night",
        "month",
        "year",
        "one_time"
      ],
      "description": "Billing period. 'night' for hotel rates, 'month' or 'year' for salaries and rentals, 'one_time' for purchase prices. Omit when the period is obvious from context (e.g., a vehicle price is always one-time)."
    }
  },
  "required": [
    "amount",
    "currency"
  ],
  "additionalProperties": false,
  "examples": [
    {
      "description": "One-time purchase price",
      "data": {
        "amount": 29.99,
        "currency": "USD"
      }
    },
    {
      "description": "Hotel nightly rate",
      "data": {
        "amount": 189,
        "currency": "EUR",
        "period": "night"
      }
    },
    {
      "description": "Annual salary",
      "data": {
        "amount": 85000,
        "currency": "USD",
        "period": "year"
      }
    }
  ]
} as const;

