export const core_RegistryEvent = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/registry-event.json",
  "title": "Registry Event",
  "description": "A single cursor-ordered event from the AgenticAdvertising.org registry change feed. Events are denormalized so RegistrySync clients can update local property, agent, publisher, and authorization indexes without re-reading the full registry. The discriminator is event_type; each branch defines the event-specific payload shape. See specs/registry-change-feed.md.",
  "type": "object",
  "discriminator": {
    "propertyName": "event_type"
  },
  "required": [
    "event_id",
    "event_type",
    "entity_type",
    "entity_id",
    "payload",
    "actor",
    "created_at"
  ],
  "properties": {
    "event_id": {
      "type": "string",
      "format": "uuid",
      "description": "Stable logical event identifier and feed cursor. UUID v7 is REQUIRED so consumers can apply events in event_id order without relying on producer clocks."
    },
    "event_type": {
      "type": "string",
      "enum": [
        "property.created",
        "property.updated",
        "property.merged",
        "property.stale",
        "property.reactivated",
        "collection.created",
        "collection.updated",
        "collection.merged",
        "collection.removed",
        "agent.discovered",
        "agent.removed",
        "agent.profile_updated",
        "agent.compliance_changed",
        "agent.verification_earned",
        "agent.verification_lost",
        "publisher.adagents_discovered",
        "publisher.adagents_changed",
        "authorization.granted",
        "authorization.revoked",
        "authorization.modified"
      ],
      "description": "Discriminator. Determines the shape of payload."
    },
    "entity_type": {
      "type": "string",
      "enum": [
        "property",
        "collection",
        "agent",
        "publisher",
        "authorization"
      ],
      "description": "Entity class touched by this event."
    },
    "entity_id": {
      "type": "string",
      "description": "Primary identifier for the changed entity. For property.* events this is the property_rid; for agent.* events this is the agent_url; for publisher.adagents_changed this is the publisher domain; for authorization.* events this is the authorization row id or a stable agent/publisher composite."
    },
    "payload": {
      "type": "object",
      "description": "Event-type-specific payload. Shape is determined by event_type per the oneOf below."
    },
    "actor": {
      "type": "string",
      "description": "Internal producer label for audit and debugging, such as pipeline:crawler or trigger:caa_emit_event. Consumers MUST treat this as informational and not as an authorization principal."
    },
    "created_at": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp when the registry emitted the event. Advisory only; consumers MUST order and cursor by event_id."
    }
  },
  "oneOf": [
    {
      "description": "property.created - a new property_rid was assigned.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "property.created"
        },
        "entity_type": {
          "type": "string",
          "const": "property"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/propertyPayload"
            },
            {
              "type": "object",
              "required": [
                "property_rid",
                "classification",
                "identifiers"
              ]
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "property.updated - classification, identifiers, or metadata changed.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "property.updated"
        },
        "entity_type": {
          "type": "string",
          "const": "property"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/propertyPayload"
            },
            {
              "type": "object",
              "required": [
                "property_rid"
              ]
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "property.merged - one property_rid became an alias of another.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "property.merged"
        },
        "entity_type": {
          "type": "string",
          "const": "property"
        },
        "payload": {
          "type": "object",
          "required": [
            "alias_rid",
            "canonical_rid"
          ],
          "properties": {
            "alias_rid": {
              "type": "string",
              "format": "uuid",
              "description": "Retired property_rid that now aliases to canonical_rid."
            },
            "canonical_rid": {
              "type": "string",
              "format": "uuid",
              "description": "Canonical property_rid that consumers should retain."
            },
            "evidence": {
              "type": "string",
              "description": "Registry evidence source for the merge, such as adagents_json or manual_review."
            }
          },
          "additionalProperties": true
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "property.stale - a property has aged out of active resolution.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "property.stale"
        },
        "entity_type": {
          "type": "string",
          "const": "property"
        },
        "payload": {
          "type": "object",
          "required": [
            "property_rid"
          ],
          "properties": {
            "property_rid": {
              "type": "string",
              "format": "uuid"
            },
            "last_resolved_at": {
              "type": "string",
              "format": "date-time"
            },
            "reason": {
              "type": "string"
            }
          },
          "additionalProperties": true
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "property.reactivated - a stale property was resolved again.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "property.reactivated"
        },
        "entity_type": {
          "type": "string",
          "const": "property"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/propertyPayload"
            },
            {
              "type": "object",
              "required": [
                "property_rid"
              ],
              "properties": {
                "reactivated_at": {
                  "type": "string",
                  "format": "date-time"
                }
              }
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "collection.created - a new collection_rid was assigned.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "collection.created"
        },
        "entity_type": {
          "type": "string",
          "const": "collection"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/collectionPayload"
            },
            {
              "type": "object",
              "required": [
                "collection_rid",
                "publisher_domain",
                "collection_id",
                "identifiers"
              ]
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "collection.updated - collection metadata or distribution identifiers changed.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "collection.updated"
        },
        "entity_type": {
          "type": "string",
          "const": "collection"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/collectionPayload"
            },
            {
              "type": "object",
              "required": [
                "collection_rid"
              ]
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "collection.merged - one collection_rid became an alias of another.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "collection.merged"
        },
        "entity_type": {
          "type": "string",
          "const": "collection"
        },
        "payload": {
          "type": "object",
          "required": [
            "alias_rid",
            "canonical_rid"
          ],
          "properties": {
            "alias_rid": {
              "type": "string",
              "format": "uuid",
              "description": "Retired collection_rid that now aliases to canonical_rid."
            },
            "canonical_rid": {
              "type": "string",
              "format": "uuid",
              "description": "Canonical collection_rid that consumers should retain."
            },
            "evidence": {
              "type": "string",
              "description": "Registry evidence source for the merge, such as adagents_json or manual_review."
            }
          },
          "additionalProperties": true
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "collection.removed - a collection is no longer visible in the publisher's authoritative catalog.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "collection.removed"
        },
        "entity_type": {
          "type": "string",
          "const": "collection"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/collectionPayload"
            },
            {
              "type": "object",
              "required": [
                "collection_rid",
                "publisher_domain",
                "status"
              ],
              "properties": {
                "status": {
                  "type": "string",
                  "const": "removed"
                }
              }
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "agent.discovered - a new agent appeared in crawled registry data.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "agent.discovered"
        },
        "entity_type": {
          "type": "string",
          "const": "agent"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/agentProfilePayload"
            },
            {
              "type": "object",
              "required": [
                "agent_url"
              ]
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "agent.removed - an agent no longer appears in any crawled adagents.json authorization graph.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "agent.removed"
        },
        "entity_type": {
          "type": "string",
          "const": "agent"
        },
        "payload": {
          "type": "object",
          "required": [
            "agent_url"
          ],
          "properties": {
            "agent_url": {
              "type": "string",
              "format": "uri"
            },
            "removed_from_publishers": {
              "type": "array",
              "items": {
                "$ref": "#/$defs/domain"
              },
              "minItems": 1
            }
          },
          "additionalProperties": true
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "agent.profile_updated - an agent inventory profile changed.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "agent.profile_updated"
        },
        "entity_type": {
          "type": "string",
          "const": "agent"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/agentProfilePayload"
            },
            {
              "type": "object",
              "required": [
                "agent_url"
              ],
              "properties": {
                "changed_fields": {
                  "$ref": "#/$defs/changedFields"
                }
              }
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "agent.compliance_changed - an agent verification or compliance heartbeat changed status.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "agent.compliance_changed"
        },
        "entity_type": {
          "type": "string",
          "const": "agent"
        },
        "payload": {
          "$ref": "#/$defs/compliancePayload"
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "agent.verification_earned - an agent earned an AAO Verified badge.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "agent.verification_earned"
        },
        "entity_type": {
          "type": "string",
          "const": "agent"
        },
        "payload": {
          "type": "object",
          "required": [
            "agent_url",
            "role",
            "verified_specialisms"
          ],
          "properties": {
            "agent_url": {
              "type": "string",
              "format": "uri"
            },
            "role": {
              "$ref": "#/$defs/badgeRole"
            },
            "verified_specialisms": {
              "type": "array",
              "items": {
                "type": "string"
              },
              "minItems": 1
            },
            "adcp_version": {
              "type": "string"
            }
          },
          "additionalProperties": true
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "agent.verification_lost - an agent lost an AAO Verified badge.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "agent.verification_lost"
        },
        "entity_type": {
          "type": "string",
          "const": "agent"
        },
        "payload": {
          "type": "object",
          "required": [
            "agent_url",
            "role",
            "reason"
          ],
          "properties": {
            "agent_url": {
              "type": "string",
              "format": "uri"
            },
            "role": {
              "$ref": "#/$defs/badgeRole"
            },
            "reason": {
              "type": "string"
            },
            "adcp_version": {
              "type": "string"
            }
          },
          "additionalProperties": true
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "publisher.adagents_discovered - the crawler found a publisher adagents.json file and projected it into the registry.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "publisher.adagents_discovered"
        },
        "entity_type": {
          "type": "string",
          "const": "publisher"
        },
        "payload": {
          "$ref": "#/$defs/publisherAdagentsPayload"
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "publisher.adagents_changed - the registry crawler detected a publisher adagents.json change.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "publisher.adagents_changed"
        },
        "entity_type": {
          "type": "string",
          "const": "publisher"
        },
        "payload": {
          "allOf": [
            {
              "$ref": "#/$defs/publisherAdagentsPayload"
            },
            {
              "type": "object",
              "properties": {
                "properties_added": {
                  "type": "integer",
                  "minimum": 0
                },
                "properties_removed": {
                  "type": "integer",
                  "minimum": 0
                },
                "agents_added": {
                  "type": "array",
                  "items": {
                    "type": "string",
                    "format": "uri"
                  }
                },
                "agents_removed": {
                  "type": "array",
                  "items": {
                    "type": "string",
                    "format": "uri"
                  }
                },
                "changed_fields": {
                  "$ref": "#/$defs/changedFields"
                }
              }
            }
          ]
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "authorization.granted - an agent became authorized for a publisher or scoped inventory slice.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "authorization.granted"
        },
        "entity_type": {
          "type": "string",
          "const": "authorization"
        },
        "payload": {
          "$ref": "#/$defs/authorizationPayload"
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "authorization.revoked - an agent authorization is no longer visible in the effective registry set.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "authorization.revoked"
        },
        "entity_type": {
          "type": "string",
          "const": "authorization"
        },
        "payload": {
          "$ref": "#/$defs/authorizationPayload"
        }
      },
      "required": [
        "event_type"
      ]
    },
    {
      "description": "authorization.modified - an authorization row remained visible, but externally visible metadata changed.",
      "properties": {
        "event_type": {
          "type": "string",
          "const": "authorization.modified"
        },
        "entity_type": {
          "type": "string",
          "const": "authorization"
        },
        "payload": {
          "$ref": "#/$defs/authorizationPayload"
        }
      },
      "required": [
        "event_type"
      ]
    }
  ],
  "$defs": {
    "domain": {
      "type": "string",
      "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
    },
    "publisherAdagentsPayload": {
      "type": "object",
      "anyOf": [
        {
          "required": [
            "publisher_domain"
          ]
        },
        {
          "required": [
            "domain"
          ]
        }
      ],
      "properties": {
        "publisher_domain": {
          "$ref": "#/$defs/domain"
        },
        "domain": {
          "$ref": "#/$defs/domain",
          "description": "Legacy alias for publisher_domain retained for early feed examples."
        },
        "properties_added": {
          "type": "integer",
          "minimum": 0
        },
        "properties_removed": {
          "type": "integer",
          "minimum": 0
        },
        "agents_added": {
          "type": "array",
          "items": {
            "type": "string",
            "format": "uri"
          }
        },
        "agents_removed": {
          "type": "array",
          "items": {
            "type": "string",
            "format": "uri"
          }
        },
        "agent_count": {
          "type": "integer",
          "minimum": 0
        },
        "property_count": {
          "type": "integer",
          "minimum": 0
        },
        "collection_count": {
          "type": "integer",
          "minimum": 0
        },
        "discovery_method": {
          "type": "string"
        },
        "manager_domain": {
          "type": [
            "string",
            "null"
          ]
        },
        "source": {
          "type": "string"
        }
      },
      "additionalProperties": true
    },
    "badgeRole": {
      "type": "string",
      "enum": [
        "media-buy",
        "creative",
        "signals",
        "governance",
        "brand",
        "sponsored-intelligence"
      ]
    },
    "stringArray": {
      "type": "array",
      "items": {
        "type": "string"
      }
    },
    "changedFields": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "minItems": 1,
      "description": "Advisory list of changed top-level field names. Consumers MAY use this for targeted index refresh but MUST treat the event payload as authoritative."
    },
    "classification": {
      "type": "string",
      "enum": [
        "property",
        "ad_infra",
        "publisher_mask",
        "network",
        "unclassified"
      ]
    },
    "propertySource": {
      "type": "string",
      "enum": [
        "authoritative",
        "enriched",
        "contributed"
      ]
    },
    "propertyPayload": {
      "type": "object",
      "properties": {
        "property_rid": {
          "type": "string",
          "format": "uuid"
        },
        "classification": {
          "$ref": "#/$defs/classification"
        },
        "source": {
          "$ref": "#/$defs/propertySource"
        },
        "identifiers": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/identifier.json"
          },
          "minItems": 1
        },
        "publisher_domain": {
          "$ref": "#/$defs/domain"
        },
        "property": {
          "$ref": "/schemas/3.1.0/core/property.json",
          "description": "Optional full post-change property object when available."
        },
        "changed_fields": {
          "$ref": "#/$defs/changedFields"
        }
      },
      "additionalProperties": true
    },
    "collectionIdentifier": {
      "type": "object",
      "properties": {
        "publisher_domain": {
          "$ref": "#/$defs/domain",
          "description": "Distribution platform domain, such as youtube.com or spotify.com."
        },
        "type": {
          "$ref": "/schemas/3.1.0/enums/distribution-identifier-type.json"
        },
        "value": {
          "type": "string"
        }
      },
      "required": [
        "publisher_domain",
        "type",
        "value"
      ],
      "additionalProperties": false
    },
    "collectionPayload": {
      "type": "object",
      "properties": {
        "collection_rid": {
          "type": "string",
          "format": "uuid"
        },
        "publisher_domain": {
          "$ref": "#/$defs/domain"
        },
        "collection_id": {
          "type": [
            "string",
            "null"
          ],
          "description": "Publisher-local collection_id from the authoritative adagents.json."
        },
        "name": {
          "type": [
            "string",
            "null"
          ]
        },
        "kind": {
          "anyOf": [
            {
              "$ref": "/schemas/3.1.0/enums/collection-kind.json"
            },
            {
              "type": "null"
            }
          ]
        },
        "source": {
          "$ref": "#/$defs/propertySource"
        },
        "status": {
          "type": "string",
          "enum": [
            "active",
            "stale",
            "removed"
          ]
        },
        "identifiers": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/collectionIdentifier"
          },
          "description": "Distribution identifiers that alias this collection across platforms."
        },
        "collection": {
          "$ref": "/schemas/3.1.0/core/collection.json",
          "description": "Optional full post-change collection object when available."
        },
        "changed_fields": {
          "$ref": "#/$defs/changedFields"
        }
      },
      "additionalProperties": true
    },
    "agentProfilePayload": {
      "type": "object",
      "properties": {
        "agent_url": {
          "type": "string",
          "format": "uri"
        },
        "name": {
          "type": "string"
        },
        "type": {
          "type": "string",
          "enum": [
            "sales",
            "creative",
            "signals",
            "governance",
            "measurement",
            "unknown"
          ]
        },
        "channels": {
          "$ref": "#/$defs/stringArray"
        },
        "property_types": {
          "$ref": "#/$defs/stringArray"
        },
        "markets": {
          "type": "array",
          "items": {
            "type": "string",
            "pattern": "^[A-Z]{2}$"
          },
          "uniqueItems": true
        },
        "categories": {
          "$ref": "#/$defs/stringArray"
        },
        "category_taxonomy": {
          "type": [
            "string",
            "null"
          ]
        },
        "format_ids": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/format-id.json"
          }
        },
        "tags": {
          "$ref": "#/$defs/stringArray"
        },
        "delivery_types": {
          "$ref": "#/$defs/stringArray"
        },
        "property_count": {
          "type": "integer",
          "minimum": 0
        },
        "publisher_count": {
          "type": "integer",
          "minimum": 0
        },
        "has_tmp": {
          "type": "boolean"
        },
        "updated_at": {
          "type": "string",
          "format": "date-time"
        }
      },
      "additionalProperties": true
    },
    "countries": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^[A-Z]{2}$"
      },
      "minItems": 1,
      "uniqueItems": true
    },
    "authorizationPayload": {
      "type": "object",
      "required": [
        "agent_url",
        "publisher_domain"
      ],
      "properties": {
        "id": {
          "type": "string",
          "format": "uuid",
          "description": "Registry authorization row id when the event is backed by a materialized effective authorization row."
        },
        "agent_url": {
          "type": "string",
          "format": "uri"
        },
        "agent_url_canonical": {
          "type": "string",
          "description": "Registry-canonicalized form of agent_url for equality checks."
        },
        "publisher_domain": {
          "$ref": "#/$defs/domain"
        },
        "authorization_type": {
          "type": "string",
          "enum": [
            "property_ids",
            "property_tags",
            "inline_properties",
            "publisher_properties",
            "signal_ids",
            "signal_tags"
          ],
          "description": "When present, identifies the adagents.json authorization variant represented by this payload."
        },
        "authorized_for": {
          "type": [
            "string",
            "null"
          ]
        },
        "property_ids": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/property-id.json"
          },
          "minItems": 1
        },
        "property_tags": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/property-tag.json"
          },
          "minItems": 1
        },
        "properties": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/property.json"
          },
          "minItems": 1
        },
        "publisher_properties": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/publisher-property-selector.json"
          },
          "minItems": 1
        },
        "property_rid": {
          "type": [
            "string",
            "null"
          ],
          "format": "uuid",
          "description": "Catalog property_rid for materialized per-property authorization rows. Null for publisher-wide rows."
        },
        "property_id_slug": {
          "type": [
            "string",
            "null"
          ],
          "description": "Publisher-local property id for materialized per-property authorization rows."
        },
        "placement_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "minItems": 1
        },
        "placement_tags": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "minItems": 1,
          "uniqueItems": true
        },
        "collections": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/collection-selector.json"
          },
          "minItems": 1
        },
        "countries": {
          "$ref": "#/$defs/countries"
        },
        "delegation_type": {
          "type": "string",
          "enum": [
            "direct",
            "delegated",
            "ad_network"
          ]
        },
        "exclusive": {
          "type": "boolean"
        },
        "signing_keys": {
          "type": "array",
          "items": {
            "$ref": "/schemas/3.1.0/core/agent-signing-key.json"
          },
          "minItems": 1,
          "description": "Publisher-attested signing keys copied from adagents.json when the registry has them. Advisory in feed events; verifiers MUST re-fetch the authoritative publisher artifact before treating keys as a trust anchor."
        },
        "effective_from": {
          "type": "string",
          "format": "date-time"
        },
        "effective_until": {
          "type": "string",
          "format": "date-time"
        },
        "evidence": {
          "type": "string",
          "enum": [
            "adagents_json",
            "agent_claim",
            "community",
            "override"
          ]
        },
        "disputed": {
          "type": "boolean"
        },
        "created_by": {
          "type": [
            "string",
            "null"
          ]
        },
        "expires_at": {
          "type": [
            "string",
            "null"
          ],
          "format": "date-time"
        },
        "created_at": {
          "type": [
            "string",
            "null"
          ],
          "format": "date-time"
        },
        "updated_at": {
          "type": [
            "string",
            "null"
          ],
          "format": "date-time"
        },
        "override_applied": {
          "type": "boolean"
        },
        "override_reason": {
          "type": [
            "string",
            "null"
          ]
        }
      },
      "additionalProperties": true
    },
    "compliancePayload": {
      "type": "object",
      "required": [
        "agent_url",
        "previous_status",
        "current_status",
        "tracks",
        "storyboards_passing",
        "storyboards_total"
      ],
      "properties": {
        "agent_url": {
          "type": "string",
          "format": "uri"
        },
        "previous_status": {
          "$ref": "#/$defs/complianceStatus"
        },
        "current_status": {
          "$ref": "#/$defs/complianceStatus"
        },
        "headline": {
          "type": [
            "string",
            "null"
          ]
        },
        "tracks": {
          "type": "object",
          "description": "Map of compliance track id to track status.",
          "additionalProperties": {
            "type": "string",
            "enum": [
              "pass",
              "fail",
              "partial",
              "skip",
              "silent",
              "warning",
              "unknown",
              "skipped"
            ]
          }
        },
        "storyboards_passing": {
          "type": "integer",
          "minimum": 0
        },
        "storyboards_total": {
          "type": "integer",
          "minimum": 0
        },
        "storyboards": {
          "type": "array",
          "items": {
            "type": "object",
            "required": [
              "storyboard_id",
              "status"
            ],
            "properties": {
              "storyboard_id": {
                "type": "string"
              },
              "status": {
                "$ref": "#/$defs/storyboardStatus"
              },
              "steps_passed": {
                "type": "integer",
                "minimum": 0
              },
              "steps_total": {
                "type": "integer",
                "minimum": 0
              }
            },
            "additionalProperties": true
          }
        }
      },
      "additionalProperties": true
    },
    "complianceStatus": {
      "type": "string",
      "enum": [
        "passing",
        "degraded",
        "failing",
        "unknown"
      ]
    },
    "storyboardStatus": {
      "type": "string",
      "enum": [
        "passing",
        "failing",
        "partial",
        "untested",
        "skipped",
        "not_selected",
        "unknown"
      ]
    }
  }
} as const;

export const core_RegistryFeedResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/registry-feed-response.json",
  "title": "Registry Feed Response",
  "description": "Response from GET /api/registry/feed. The events array contains cursor-ordered registry events; cursor is the value to pass on the next poll. See specs/registry-change-feed.md.",
  "type": "object",
  "properties": {
    "events": {
      "type": "array",
      "items": {
        "$ref": "/schemas/3.1.0/core/registry-event.json"
      }
    },
    "cursor": {
      "type": [
        "string",
        "null"
      ],
      "format": "uuid",
      "description": "Pass this value as cursor on the next request to continue polling. Null only when the feed has no events and no prior cursor."
    },
    "has_more": {
      "type": "boolean",
      "description": "True when more events are immediately available after cursor."
    }
  },
  "required": [
    "events",
    "cursor",
    "has_more"
  ],
  "additionalProperties": true
} as const;

export const core_ReportingCapabilities = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/reporting-capabilities.json",
  "title": "Reporting Capabilities",
  "description": "Reporting capabilities available for a product",
  "type": "object",
  "properties": {
    "available_reporting_frequencies": {
      "type": "array",
      "description": "Supported reporting frequency options",
      "items": {
        "$ref": "/schemas/3.1.0/enums/reporting-frequency.json"
      },
      "minItems": 1,
      "uniqueItems": true
    },
    "expected_delay_minutes": {
      "type": "integer",
      "description": "Expected delay in minutes before reporting data becomes available (e.g., 240 for 4-hour delay)",
      "minimum": 0,
      "examples": [
        240,
        300,
        1440
      ]
    },
    "timezone": {
      "type": "string",
      "description": "Timezone for reporting periods. Use 'UTC' or IANA timezone (e.g., 'America/New_York'). Critical for daily/monthly frequency alignment.",
      "examples": [
        "UTC",
        "America/New_York",
        "Europe/London",
        "America/Los_Angeles"
      ]
    },
    "supports_webhooks": {
      "type": "boolean",
      "description": "Whether this product supports webhook-based reporting notifications"
    },
    "available_metrics": {
      "type": "array",
      "description": "Metrics available in reporting. Impressions and spend are always implicitly included. When a creative format declares reported_metrics, buyers receive the intersection of these product-level metrics and the format's reported_metrics.",
      "items": {
        "$ref": "/schemas/3.1.0/enums/available-metric.json"
      },
      "uniqueItems": true,
      "examples": [
        [
          "impressions",
          "spend",
          "clicks",
          "completed_views"
        ],
        [
          "impressions",
          "spend",
          "conversions"
        ]
      ]
    },
    "vendor_metrics": {
      "type": "array",
      "description": "Vendor-defined metrics this product can report, beyond the closed `available_metrics` enum. Each entry is a pointer (`{ vendor, metric_id }`) into the vendor's metric catalog — the canonical definition (standard alignment, accreditations, methodology, unit, human-readable description) lives at the vendor's `get_adcp_capabilities.measurement.metrics[]`, queried once per vendor when needed. Use this for proprietary metrics like attention scores, emissions, panel-based demographics, or platform-native social metrics not yet in the standard enum. Sellers populate values in delivery via `delivery-metrics.json#/properties/vendor_metric_values`. The metric is identified by the tuple `(vendor, metric_id)`; identifiers are namespaced by the vendor, so the same `metric_id` may mean different things in different vendors' vocabularies. Semantic uniqueness key is `(vendor.domain, vendor.brand_id, metric_id)`; sellers MUST de-duplicate before emission and MUST NOT declare the same vendor metric twice. Buyers MAY treat duplicate `(vendor, metric_id)` rows as a seller-side conformance bug. (JSON Schema `uniqueItems` is not used here because BrandRef carries optional fields whose absence/presence would defeat deep-equal — uniqueness is on the semantic key, enforced at build/validation time on the seller side.) Promotion path: when the industry converges on a metric via a published standard, the spec adds it to the closed `available_metrics` enum and the vendor extensions become historical aliases.",
      "items": {
        "type": "object",
        "properties": {
          "vendor": {
            "$ref": "/schemas/3.1.0/core/brand-ref.json",
            "description": "Vendor that defines and computes this metric. The vendor's `brand.json` is the discovery anchor for the measurement agent (entry with `type: 'measurement'` in the `agents[]` array); the metric's standard alignment, accreditations, and methodology live at that agent's `get_adcp_capabilities.measurement.metrics[]` and are not duplicated inline here."
          },
          "metric_id": {
            "$ref": "/schemas/3.1.0/core/vendor-metric-id.json",
            "description": "Identifier for the metric within the vendor's vocabulary (e.g., `attention_units`, `gco2e_per_impression`, `demographic_reach`)."
          }
        },
        "required": [
          "vendor",
          "metric_id"
        ],
        "additionalProperties": false
      }
    },
    "supports_creative_breakdown": {
      "type": "boolean",
      "description": "Whether this product supports creative-level metric breakdowns in delivery reporting (by_creative within by_package)"
    },
    "supports_keyword_breakdown": {
      "type": "boolean",
      "description": "Whether this product supports keyword-level metric breakdowns in delivery reporting (by_keyword within by_package)"
    },
    "supports_geo_breakdown": {
      "$ref": "/schemas/3.1.0/core/geo-breakdown-support.json",
      "description": "Geographic breakdown support for this product. Declares which geo levels and systems are available for by_geo reporting within by_package."
    },
    "supports_device_type_breakdown": {
      "type": "boolean",
      "description": "Whether this product supports device type breakdowns in delivery reporting (by_device_type within by_package)"
    },
    "supports_device_platform_breakdown": {
      "type": "boolean",
      "description": "Whether this product supports device platform breakdowns in delivery reporting (by_device_platform within by_package)"
    },
    "supports_audience_breakdown": {
      "type": "boolean",
      "description": "Whether this product supports audience segment breakdowns in delivery reporting (by_audience within by_package)"
    },
    "supports_placement_breakdown": {
      "type": "boolean",
      "description": "Whether this product supports placement breakdowns in delivery reporting (by_placement within by_package)"
    },
    "date_range_support": {
      "type": "string",
      "enum": [
        "date_range",
        "lifetime_only"
      ],
      "description": "Whether delivery data can be filtered to arbitrary date ranges. 'date_range' means the platform supports start_date/end_date parameters. 'lifetime_only' means the platform returns campaign lifetime totals and date range parameters are not accepted.",
      "default": "date_range"
    },
    "windowed_pull_granularities": {
      "type": "array",
      "description": "Granularities at which this product honors per-window pulls on get_media_buy_delivery (via request `time_granularity` + `include_window_breakdown: true`). Closes the GET-side half of the snapshot/log two-paths-parity contract for data-bearing events: a buyer who missed a webhook fire at any granularity listed here can reconstruct an identical payload by polling. Capability-scoped MUST — sellers MUST honor pulls at any granularity declared here, and MUST return UNSUPPORTED_GRANULARITY for pulls outside the set. Sellers MAY emit higher-frequency webhooks than they expose for pull (common where the webhook is a Kafka tap and historical reads go through a warehouse with coarser granularity); buyers see the gap up front via this capability and treat the webhook as primary for those frequencies. Absent or empty means the product only supports cumulative date-range pulls and full per-window recovery via GET is unavailable — see snapshot-and-log Rule 4.",
      "items": {
        "$ref": "/schemas/3.1.0/enums/reporting-frequency.json"
      },
      "uniqueItems": true,
      "examples": [
        [
          "daily"
        ],
        [
          "hourly",
          "daily"
        ],
        [
          "hourly",
          "daily",
          "monthly"
        ]
      ]
    },
    "measurement_windows": {
      "type": "array",
      "description": "Measurement maturation stages available for this product. Used by any channel where billing-grade data is produced in phases rather than arriving final on day one. Examples: broadcast/linear TV (Live → C3 → C7 DVR accumulation), DOOH (tentative plays → post-IVT/fraud-check final), digital with IVT filtering (raw → GIVT filtered → SIVT filtered), podcast (7-day downloads → 30-day downloads). Each window defines an accumulation period and expected data availability. When present, delivery reports reference a specific window_id. Sellers whose data is final on first delivery typically omit this.",
      "items": {
        "$ref": "/schemas/3.1.0/core/measurement-window.json"
      },
      "minItems": 1,
      "uniqueItems": true
    }
  },
  "required": [
    "available_reporting_frequencies",
    "expected_delay_minutes",
    "timezone",
    "supports_webhooks",
    "available_metrics",
    "date_range_support"
  ],
  "additionalProperties": true
} as const;

export const core_ReportingWebhook = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/reporting-webhook.json",
  "title": "Reporting Webhook",
  "description": "Webhook configuration for automated reporting delivery. Configures where and how campaign performance reports are sent.",
  "type": "object",
  "properties": {
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Webhook endpoint URL for reporting notifications"
    },
    "token": {
      "type": "string",
      "description": "Optional client-provided token for webhook validation. Echoed back in webhook payload to validate request authenticity.",
      "minLength": 16
    },
    "authentication": {
      "type": "object",
      "description": "Legacy authentication configuration for webhook delivery (A2A-compatible). Opts the receiver into Bearer or HMAC-SHA256 signing. Both schemes are deprecated; the preferred signing profile for new integrations is RFC 9421, where the seller signs with a key published at its brand.json agents[] entry and the buyer verifies against the seller's JWKS — no shared secret crosses the wire (see docs/building/implementation/security.mdx#webhook-callbacks). This field is required in AdCP 3.x; the requirement is removed in AdCP 4.0 when the default RFC 9421 path becomes the only path.",
      "properties": {
        "schemes": {
          "type": "array",
          "description": "Array of authentication schemes. ['Bearer'] for simple token auth, ['HMAC-SHA256'] for legacy shared-secret signing. Both are deprecated; new integrations SHOULD use the RFC 9421 webhook signing profile instead.",
          "items": {
            "$ref": "/schemas/3.1.0/enums/auth-scheme.json"
          },
          "minItems": 1,
          "maxItems": 1
        },
        "credentials": {
          "type": "string",
          "description": "Credentials for the legacy scheme. For Bearer: token sent in Authorization header. For HMAC-SHA256: shared secret used to generate signature. Minimum 32 characters. Exchanged out-of-band during onboarding.",
          "minLength": 32
        }
      },
      "required": [
        "schemes",
        "credentials"
      ],
      "additionalProperties": false
    },
    "reporting_frequency": {
      "type": "string",
      "enum": [
        "hourly",
        "daily",
        "monthly"
      ],
      "description": "Frequency for automated reporting delivery. Must be supported by all products in the media buy."
    },
    "requested_metrics": {
      "type": "array",
      "description": "Optional list of metrics to include in webhook notifications. If omitted, all available metrics are included. Must be subset of product's available_metrics.",
      "items": {
        "$ref": "/schemas/3.1.0/enums/available-metric.json"
      },
      "uniqueItems": true
    }
  },
  "required": [
    "url",
    "authentication",
    "reporting_frequency"
  ],
  "additionalProperties": true
} as const;

