export const core_VendorMetricId = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/vendor-metric-id.json",
  "title": "Vendor Metric ID",
  "description": "Identifier for a vendor-defined metric within the vendor's vocabulary. Stable lookup key; the vendor publishes the canonical list (with category, methodology, and standard alignment) in `brand.json` `agents[type='measurement']`. Lowercase with underscores so a future enum promotion into `available-metric.json` is a literal string lift. Identifier is namespaced by the vendor — the same `metric_id` may mean different things in different vendors' vocabularies.",
  "type": "string",
  "x-entity": "vendor_metric",
  "minLength": 1,
  "maxLength": 64,
  "pattern": "^[a-z][a-z0-9_]*$",
  "examples": [
    "attention_units",
    "gco2e_per_impression",
    "demographic_reach",
    "co_view_index",
    "incremental_lift_percent"
  ]
} as const;

export const core_VendorMetricOptimizationSupportedMetric = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/vendor-metric-optimization-supported-metric.json",
  "title": "Vendor Metric Optimization Supported Metric",
  "description": "One vendor-defined metric that a product can optimize toward. Identified by the tuple `(vendor, metric_id)` plus the supported target kinds for optimization goals.",
  "type": "object",
  "properties": {
    "vendor": {
      "$ref": "/schemas/3.1.0/core/brand-ref.json",
      "description": "Vendor that defines and computes this metric. The vendor's `brand.json` is the discovery anchor for the measurement agent (entry with `type: 'measurement'` in the `agents[]` array); the metric's definition, methodology, and unit live at that agent's `get_adcp_capabilities.measurement.metrics[]` and are not duplicated inline here. Same shape as the `vendor` field on `reporting_capabilities.vendor_metrics` for symmetry across optimization and reporting capability declarations."
    },
    "metric_id": {
      "$ref": "/schemas/3.1.0/core/vendor-metric-id.json",
      "description": "Identifier for the metric within the vendor's vocabulary (e.g., `attention_score`, `attention_seconds`, `gco2e_per_impression`, `awareness_lift`). MUST be present in the vendor's published `measurement.metrics[]` catalog."
    },
    "supported_targets": {
      "type": "array",
      "description": "Target kinds available for `vendor_metric` goals against this `(vendor, metric_id)` pair. Values match `target.kind` on the optimization goal. `cost_per` — target cost per metric unit (e.g., $0.05 per attention-second). `threshold_rate` — minimum per-impression value (e.g., attention_score ≥ 70). Only these target kinds are accepted — goals with unlisted target kinds will be rejected. A goal without a target implicitly maximizes the metric within budget — no declaration needed for that mode. When omitted, buyers can still set target-less vendor_metric goals.",
      "uniqueItems": true,
      "items": {
        "type": "string",
        "enum": [
          "cost_per",
          "threshold_rate"
        ]
      }
    }
  },
  "required": [
    "vendor",
    "metric_id"
  ],
  "additionalProperties": false
} as const;

export const core_VendorMetricOptimization = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/vendor-metric-optimization.json",
  "title": "Vendor Metric Optimization",
  "description": "Vendor-attested metric optimization capabilities for a product. Presence indicates the product supports `optimization_goals` with `kind: 'vendor_metric'` — i.e., the seller's bidding stack can steer delivery toward a specific vendor's metric. This is the optimization-side counterpart to `reporting_capabilities.vendor_metrics`, which declares which vendor metrics the product can *report*. The two are related but distinct: a product may be able to commit to reporting a vendor metric (the vendor's SDK fires on the inventory) without being able to optimize against it (the optimization signal isn't actionable in the seller's bidding stack). Each `supported_metrics` entry is the tuple `(vendor, metric_id)` plus the target kinds the seller supports for that pair. Buyers MUST set `vendor_metric` goals only against entries declared here; sellers MUST reject goals whose `(vendor, metric_id)` is not in `supported_metrics`, and MUST reject goals whose `target.kind` is not in the matching entry's `supported_targets`. Buyers SHOULD also verify the metric is in the vendor's published `measurement.metrics[]` catalog (the discovery-layer check — softened from MUST while measurement-vendor adoption of AdCP-conformant capability publication catches up; tightens to MUST at the next minor) and that the package's `committed_metrics[]` includes a matching `{ scope: 'vendor', vendor, metric_id }` entry (the reporting-coherence check — optimizing for a metric you don't commit to reporting is unverifiable). The `maximize_value` target kind from the `event` goal kind is intentionally excluded — it's monetary-only; a buyer wanting to maximize a vendor metric uses the target-less form of the `vendor_metric` goal. Precondition checks are seller-runtime, not JSON-Schema-enforceable: the schema's `required` only validates structural presence of `vendor` and `metric_id`.",
  "type": "object",
  "properties": {
    "supported_metrics": {
      "type": "array",
      "description": "Vendor-defined metrics this product can steer delivery toward. Each entry pairs a vendor identity (BrandRef anchored on the vendor's `brand.json` `agents[type='measurement']`) with a `metric_id` from that vendor's published `measurement.metrics[]` catalog, plus the target kinds the seller supports for the pair. Semantic uniqueness key is `(vendor.domain, vendor.brand_id, metric_id)`; sellers MUST de-duplicate before publication. JSON Schema `uniqueItems` blocks exact-object duplicates; semantic deduplication on the BrandRef-domain key is a seller obligation.",
      "uniqueItems": true,
      "items": {
        "$ref": "/schemas/3.1.0/core/vendor-metric-optimization-supported-metric.json"
      }
    }
  },
  "required": [
    "supported_metrics"
  ],
  "additionalProperties": true
} as const;

export const core_VendorMetricValue = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/vendor-metric-value.json",
  "title": "Vendor Metric Value",
  "description": "A reported value for a vendor-defined metric, emitted in `delivery-metrics.json` `vendor_metric_values` parallel to standard scalars. Identifies the vendor (BrandRef), the metric name within that vendor's vocabulary, the value, and the coverage denominator (`measurable_impressions`) — vendor measurement is rarely 100% coverage. The `breakdown` slot accommodates vendors that emit structured payloads beyond a single scalar (panel demographic breakouts, co-view ratios, incremental decompositions). To add fields beyond what this schema defines, vendors place them inside `breakdown` rather than alongside the standard envelope.",
  "type": "object",
  "properties": {
    "vendor": {
      "$ref": "/schemas/3.1.0/core/brand-ref.json",
      "description": "Vendor that produced this value. Matches a `vendor_metrics[].vendor` declaration on the product."
    },
    "metric_id": {
      "$ref": "/schemas/3.1.0/core/vendor-metric-id.json",
      "description": "Identifier for the metric within the vendor's vocabulary. Matches a `vendor_metrics[].metric_id` declaration on the product."
    },
    "value": {
      "type": "number",
      "description": "The reported value. Unit semantics are vendor-defined — see `unit` field below and the vendor's `brand.json` measurement-agent documentation."
    },
    "unit": {
      "type": "string",
      "description": "Unit of the value. Free-form to accommodate the heterogeneity of vendor metrics (e.g., `score`, `seconds`, `persons`, `gCO2e`, `USD`, `lift_percent`). When the value is monetary, use the ISO 4217 code (e.g., `USD`, `EUR`); for non-monetary, use whatever the vendor publishes. Optional on every row — the canonical unit lives at the vendor's measurement-agent metric definition (`brand.json` `agents[type='measurement']`). When sellers populate it inline they SHOULD match the vendor's published unit; buyers MAY resolve from the vendor's measurement agent when this field is absent.",
      "examples": [
        "score",
        "seconds",
        "persons",
        "gCO2e",
        "USD",
        "lift_percent",
        "index"
      ]
    },
    "measurable_impressions": {
      "type": "number",
      "description": "Number of impressions in this reporting period that the vendor was able to measure. Coverage denominator — buyers compute coverage rate as `measurable_impressions / impressions`. When absent, coverage is unspecified — buyers MUST NOT compute a coverage rate or assume full coverage. When the vendor measured zero impressions but is integrated, set to 0 explicitly. When the entry is omitted from `vendor_metric_values` entirely, the buyer infers no measurement happened (no integration). This pattern parallels `viewability.measurable_impressions` (`delivery-metrics.json#/properties/viewability`), which has handled vendor coverage in the IAS/DV/MRC ecosystem for over a decade — same convention: absence is unknown, not full.",
      "minimum": 0
    },
    "breakdown": {
      "type": "object",
      "description": "Optional structured payload for vendor metrics that don't fit a single scalar — panel demographic breakouts, co-view audience composition, incremental reach + frequency + lift decompositions. Free-form; the keys and value semantics are defined by the vendor (see the vendor's `brand.json` measurement-agent docs). Buyers MUST treat this object as opaque without consulting the vendor's documentation. Vendors place any fields beyond the standard envelope (e.g., confidence intervals, panel sizes) inside this object rather than at the top level.",
      "x-adcp-open-payload": true,
      "additionalProperties": true
    }
  },
  "required": [
    "vendor",
    "metric_id",
    "value"
  ],
  "additionalProperties": false,
  "examples": [
    {
      "vendor": {
        "domain": "attentionvendor.example"
      },
      "metric_id": "attention_units",
      "value": 4.2,
      "unit": "score",
      "measurable_impressions": 8000
    },
    {
      "vendor": {
        "domain": "emissionsvendor.example"
      },
      "metric_id": "gco2e_per_impression",
      "value": 0.85,
      "unit": "gCO2e"
    },
    {
      "vendor": {
        "domain": "panelmeasurement.example"
      },
      "metric_id": "demographic_reach",
      "value": 1500000,
      "unit": "persons",
      "measurable_impressions": 9200000,
      "breakdown": {
        "age_18_34_male": 320000,
        "age_18_34_female": 295000,
        "age_35_54_male": 405000,
        "age_35_54_female": 480000
      }
    }
  ]
} as const;

export const core_VendorPricingOption = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/vendor-pricing-option.json",
  "title": "Vendor Pricing Option",
  "description": "A pricing option offered by a vendor agent (signals, creative, governance). Combines pricing_option_id with the pricing model fields. Pass pricing_option_id in report_usage for billing verification. All vendor discovery responses return pricing_options as an array — vendors may offer multiple options (volume tiers, context-specific rates, different models per product line).",
  "allOf": [
    {
      "type": "object",
      "properties": {
        "pricing_option_id": {
          "type": "string",
          "description": "Opaque identifier for this pricing option, unique within the vendor agent. Pass this in report_usage to identify which pricing option was applied.",
          "x-entity": "vendor_pricing_option"
        },
        "applies_to_output_format_ids": {
          "type": "array",
          "description": "Creative transformers only: scopes this pricing option to specific output formats, so one transformer can price different outputs differently (e.g. a multi-publisher template charging per publisher format). When present, the option applies only to leaves whose format matches one of these; an unscoped option (this field absent) is the default for any output. A build targeting an output that matches no scoped option AND has no unscoped default is rejected with UNPRICEABLE_OUTPUT — never billed at a guessed rate (no silent fallback). Inert for non-creative vendors (signals/governance), which omit it.",
          "items": {
            "$ref": "/schemas/3.1.0/core/format-id.json"
          },
          "minItems": 1
        }
      },
      "required": [
        "pricing_option_id"
      ]
    },
    {
      "$ref": "/schemas/3.1.0/core/signal-pricing.json"
    }
  ]
} as const;

export const core_VersionEnvelope = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/version-envelope.json",
  "title": "AdCP Version Envelope",
  "description": "Release-precision AdCP protocol version negotiation fields. Composed via `allOf` into every AdCP request and response schema so the version semantics live in exactly one place. Distinct from `core/protocol-envelope.json`, which wraps responses at the transport layer (context_id / task_id / status / payload). This envelope is part of the payload itself.",
  "type": "object",
  "properties": {
    "adcp_version": {
      "type": "string",
      "description": "Release-precision AdCP version (VERSION.RELEASE, e.g. \"3.0\", \"3.1\", \"3.1-beta\"). On a request: the buyer's release pin — the seller validates against its supported_versions and returns VERSION_UNSUPPORTED on cross-major mismatch, or downshifts to the highest supported release within the same major. On a response: the release the seller actually served — clients SHOULD validate the response against that release's schema, not against their pin. Patches are not negotiated; surface them as build_version on capabilities for operational visibility. When omitted, falls back to adcp_major_version (deprecated) or server default. Buyers SHOULD emit both adcp_version and adcp_major_version through 3.x to remain compatible with sellers that only read the legacy field. NORMALIZATION: SDKs that read full-semver values from bundle metadata (e.g. ComplianceIndex.published_version = \"3.1.0-beta.1\") MUST normalize to release-precision (\"3.1-beta.1\") before emitting on the wire — meta-field values are NOT valid wire values.",
      "pattern": "^\\d+\\.\\d+(-[a-zA-Z0-9.-]+)?$",
      "examples": [
        "3.0",
        "3.1",
        "3.1-beta",
        "3.1-rc.1"
      ]
    },
    "adcp_major_version": {
      "type": "integer",
      "description": "DEPRECATED in favor of adcp_version (release-precision string). Servers MUST continue to honor this field through 3.x. Removed in 4.0. Original semantics: the AdCP major version the buyer's payloads conform to. Sellers validate against their supported major_versions and return VERSION_UNSUPPORTED if unsupported. When omitted, the seller assumes its highest supported version.",
      "minimum": 1,
      "maximum": 99
    }
  }
} as const;

export const core_WebhookActivityRecord = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/webhook-activity-record.json",
  "title": "Webhook Activity Record",
  "description": "Single webhook delivery attempt surfaced to a calling principal as a buyer-side debug aid. Represents one HTTP attempt of a logical webhook fire from the seller to the buyer's registered endpoint — retries of the same logical fire share `idempotency_key` and differ by `attempt`. This is the canonical record shape for any AdCP resource that exposes a `webhook_activity[]` log on its read API; see snapshot-and-log.mdx § Webhook activity log pattern for the full normative contract (scoping, retention, three-state presence, request-field conventions).",
  "type": "object",
  "properties": {
    "idempotency_key": {
      "type": "string",
      "description": "Equals the `idempotency_key` carried in the webhook payload itself (see docs/building/by-layer/L3/webhooks.mdx § Dedup by `idempotency_key`). Stable across retry attempts of the same logical fire — retries with `attempt` > 1 reuse this key. Buyers correlate this surface with their own endpoint logs via this exact field; the spec deliberately reuses the payload key rather than minting a parallel `delivery_id` so callers do not need a join table. Format is sender-defined; callers MUST treat as opaque."
    },
    "subscriber_id": {
      "type": "string",
      "description": "Identifies which registered webhook subscriber received this fire. **Required on records from account-anchored notification channels** (`notification_configs[]` registered via `sync_accounts`) — every subscriber has a `subscriber_id` at registration time, the seller MUST echo it on every fire and every activity record. **Optional on records from per-resource push channels** (`push_notification_config` on a media buy or task) — the calling principal is unambiguous in single-subscriber configurations and the field MAY be omitted; sellers MUST populate it once `reporting_webhook` adopts multi-subscriber (per #3009 in AdCP 4.0). Buyers MUST NOT use absence as a signal that no other subscribers exist; that information is not exposed by this surface."
    },
    "fired_at": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 timestamp when the seller initiated the HTTP request for this attempt."
    },
    "completed_at": {
      "type": [
        "string",
        "null"
      ],
      "format": "date-time",
      "description": "ISO 8601 timestamp when the seller observed the response (or terminal timeout / connection error — for `timeout` and `connection_error` outcomes, `completed_at` is set to the moment the seller declared the attempt terminal). Explicitly `null` when the attempt is still in flight or queued for retry (status `pending`); MUST be set as `null` rather than omitted so callers can distinguish 'still in flight' from 'field missing'."
    },
    "notification_type": {
      "$ref": "/schemas/3.1.0/enums/notification-type.json",
      "description": "Notification type carried by this fire, verbatim from the webhook payload. Includes both delivery-report types (`scheduled`, `final`, `delayed`, `adjusted`) and health-notification types (`impairment`). All share the same persistent-channel webhook contract and the same buyer-side debug need."
    },
    "sequence_number": {
      "type": "integer",
      "description": "Sequence number from the webhook payload. Surfaced here so the buyer can spot stale-sequence drops and gaps without correlating against their own endpoint log. Absent for notification types that do not carry a sequence number.",
      "minimum": 0
    },
    "attempt": {
      "type": "integer",
      "description": "1-indexed retry counter for this logical fire. Initial fire is attempt=1; retries increment. Sellers MUST emit one record per attempt, so a successful first-attempt fire appears as a single record with `attempt: 1` and a 3-attempt retry trail appears as three records sharing `idempotency_key`.",
      "minimum": 1
    },
    "status": {
      "type": "string",
      "description": "Outcome of this attempt. `success` — response received with 2xx (`http_status_code` populated). `failed` — response received with non-2xx (`http_status_code` populated). `timeout` — no response within the seller's configured timeout (`http_status_code` null). `connection_error` — DNS / TLS / socket failure before any HTTP response (`http_status_code` null). `pending` — attempt is in flight or queued for retry (`completed_at` null, `http_status_code` null). The `timeout` / `connection_error` split is intentional and operationally distinct: `timeout` typically signals a slow / overloaded buyer endpoint, `connection_error` typically signals it is unreachable or misconfigured.",
      "enum": [
        "success",
        "failed",
        "timeout",
        "connection_error",
        "pending"
      ]
    },
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Target URL for this fire. Query string and fragment MUST be stripped before surfacing — buyers commonly stash bearer tokens in the query string and sellers MUST NOT echo those back through this debug surface. Sellers SHOULD additionally redact path segments matching obvious secret patterns (e.g., a path segment that is high-entropy random material or matches a UUID / token format). Buyers matching this against their own configured URL should compare by origin + path; query strings will not match and that mismatch is expected."
    },
    "http_status_code": {
      "type": [
        "integer",
        "null"
      ],
      "description": "HTTP status code returned by the buyer's endpoint. Explicitly `null` when no HTTP response was received (status `timeout`, `connection_error`, or `pending`); MUST be set as `null` rather than omitted.",
      "minimum": 100,
      "maximum": 599
    },
    "response_time_ms": {
      "type": [
        "integer",
        "null"
      ],
      "description": "Wall-clock latency between request send and response receipt, in milliseconds. Explicitly `null` when the attempt did not complete (`timeout`, `connection_error`, `pending`); MUST be set as `null` rather than omitted.",
      "minimum": 0
    },
    "payload_size_bytes": {
      "type": "integer",
      "description": "Size of the request body the seller sent, in bytes. Useful for diagnosing oversized-payload rejections from the buyer's gateway.",
      "minimum": 0
    },
    "error_message": {
      "type": [
        "string",
        "null"
      ],
      "description": "Short human-readable server-side classification of why this attempt did not succeed (e.g., `connection refused`, `TLS handshake timeout`, `HTTP 503 Service Unavailable`). Explicitly `null` for `success` (MUST be set as `null` rather than omitted). Sellers MUST NOT include request headers, request body content, or response body content in this field — payload surfacing is reserved for a future `include_webhook_payloads` extension and is subject to stricter access controls. Sellers SHOULD also avoid including buyer-endpoint internal hostnames, stack traces, or other implementation detail leaked by the response — keep it a stable classification string.",
      "maxLength": 500
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json",
      "description": "Resource-specific extension slot. Adopters MAY surface a resource-specific cross-reference (e.g., `creative_id` on a creative-lifecycle record, `media_buy_id` on a record nested inside an account-level read) under `ext` rather than adding top-level fields — the canonical record shape stays uniform across resources and the `ext` envelope absorbs per-resource needs. Top-level extensions are not permitted (`additionalProperties: false`)."
    }
  },
  "required": [
    "idempotency_key",
    "fired_at",
    "notification_type",
    "attempt",
    "status",
    "url"
  ],
  "additionalProperties": false
} as const;

export const core_WebhookChallengeResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/webhook-challenge-response.json",
  "title": "Webhook Challenge Response",
  "description": "Response body a receiver returns to prove control of an account-level notification_configs[] URL. The receiver must echo the challenge value from webhook-challenge.json in exactly one of `challenge` or `token`.",
  "type": "object",
  "properties": {
    "challenge": {
      "type": "string",
      "description": "Echo of the challenge value supplied by the seller.",
      "minLength": 32,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{32,255}$"
    },
    "token": {
      "type": "string",
      "description": "Backward-compatible alias for `challenge`. Receivers SHOULD prefer `challenge`; sellers MUST accept either field.",
      "minLength": 32,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{32,255}$"
    }
  },
  "anyOf": [
    {
      "required": [
        "challenge"
      ]
    },
    {
      "required": [
        "token"
      ]
    }
  ],
  "not": {
    "required": [
      "challenge",
      "token"
    ]
  },
  "additionalProperties": false,
  "examples": [
    {
      "description": "Preferred response shape",
      "data": {
        "challenge": "example-challenge-token-000000000000"
      }
    },
    {
      "description": "Backward-compatible response shape",
      "data": {
        "token": "example-challenge-token-000000000000"
      }
    }
  ]
} as const;

export const core_WebhookChallenge = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/core/webhook-challenge.json",
  "title": "Webhook Challenge",
  "description": "Proof-of-control challenge payload sent by a seller to an account-level notification_configs[] URL before activating a new or changed active subscriber. The seller sends this payload as an HTTPS POST after URL normalization and SSRF validation, and before treating the subscriber as active. The challenge POST itself MUST be signed with the seller's RFC 9421 webhook profile key even when the candidate config selects legacy delivery auth; new signers use `adcp_use: \"request-signing\"` and deprecated `webhook-signing` keys remain accepted during the compatibility window. `delivery_auth` describes the future webhook delivery mode, not the challenge's own signing mode.",
  "type": "object",
  "properties": {
    "type": {
      "type": "string",
      "const": "webhook.challenge",
      "description": "Discriminator for endpoint proof-of-control challenges."
    },
    "challenge": {
      "type": "string",
      "description": "Opaque, cryptographically random value that the receiver must echo in the response body. Recommended encoding: base64url without padding.",
      "minLength": 32,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{32,255}$"
    },
    "account_id": {
      "type": "string",
      "description": "Seller account identifier for the account whose notification_configs[] entry is being challenged.",
      "x-entity": "account"
    },
    "subscriber_id": {
      "type": "string",
      "description": "Buyer-supplied subscriber identifier from the notification_configs[] entry being challenged.",
      "minLength": 1,
      "maxLength": 64,
      "pattern": "^[A-Za-z0-9_.:-]{1,64}$"
    },
    "seller_agent_url": {
      "type": "string",
      "format": "uri",
      "description": "Exact seller agent URL whose RFC 9421 webhook profile key signs this challenge and that will send subsequent webhooks."
    },
    "delivery_auth": {
      "type": "object",
      "description": "Authentication/signing mode the seller will use for subsequent webhooks delivered to this notification config.",
      "properties": {
        "mode": {
          "type": "string",
          "enum": [
            "rfc9421",
            "Bearer",
            "HMAC-SHA256"
          ],
          "description": "Future webhook delivery authentication mode. `rfc9421` is used when notification_configs[].authentication is absent; Bearer and HMAC-SHA256 are the deprecated legacy modes selected by notification_configs[].authentication."
        },
        "credential_fingerprint": {
          "type": "string",
          "description": "SHA-256 hex fingerprint of the exact legacy credential string supplied in notification_configs[].authentication.credentials. Required when mode is Bearer or HMAC-SHA256; absent for rfc9421.",
          "pattern": "^[a-f0-9]{64}$"
        }
      },
      "required": [
        "mode"
      ],
      "allOf": [
        {
          "if": {
            "properties": {
              "mode": {
                "type": "string",
                "const": "rfc9421"
              }
            },
            "required": [
              "mode"
            ]
          },
          "then": {
            "not": {
              "required": [
                "credential_fingerprint"
              ]
            }
          }
        },
        {
          "if": {
            "properties": {
              "mode": {
                "type": "string",
                "enum": [
                  "Bearer",
                  "HMAC-SHA256"
                ]
              }
            },
            "required": [
              "mode"
            ]
          },
          "then": {
            "required": [
              "credential_fingerprint"
            ]
          }
        }
      ],
      "additionalProperties": false
    },
    "event_types": {
      "type": "array",
      "description": "Normalized notification types requested by the subscriber at the time of the challenge. Part of the endpoint proof scope; changing event_types[] requires a fresh challenge before the new set can become active.",
      "items": {
        "$ref": "/schemas/3.1.0/enums/notification-type.json"
      },
      "minItems": 1,
      "uniqueItems": true
    }
  },
  "required": [
    "type",
    "challenge",
    "account_id",
    "subscriber_id",
    "seller_agent_url",
    "delivery_auth",
    "event_types"
  ],
  "additionalProperties": false,
  "examples": [
    {
      "description": "Endpoint proof-of-control challenge",
      "data": {
        "type": "webhook.challenge",
        "challenge": "example-challenge-token-000000000000",
        "account_id": "acct_123",
        "subscriber_id": "buyer-primary",
        "seller_agent_url": "https://seller.example/adcp",
        "delivery_auth": {
          "mode": "rfc9421"
        },
        "event_types": [
          "creative.status_changed",
          "creative.purged"
        ]
      }
    }
  ]
} as const;

