export const creative_PreviewCreativeRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/preview-creative-request.json",
  "title": "Preview Creative Request",
  "description": "Request to generate previews of creative manifests. Uses request_type to select single, batch, or variant mode.",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    },
    {
      "if": {
        "properties": {
          "request_type": {
            "const": "single"
          }
        }
      },
      "then": {
        "required": [
          "creative_manifest"
        ]
      }
    },
    {
      "if": {
        "properties": {
          "request_type": {
            "const": "batch"
          }
        }
      },
      "then": {
        "required": [
          "requests"
        ]
      }
    },
    {
      "if": {
        "properties": {
          "request_type": {
            "const": "variant"
          }
        }
      },
      "then": {
        "required": [
          "variant_id"
        ]
      }
    }
  ],
  "properties": {
    "request_type": {
      "type": "string",
      "enum": [
        "single",
        "batch",
        "variant"
      ],
      "description": "Preview mode. 'single' previews one creative manifest. 'batch' previews multiple creatives in one call. 'variant' replays a post-flight variant by ID."
    },
    "creative_manifest": {
      "$ref": "/schemas/3.1.0/core/creative-manifest.json",
      "description": "Complete creative manifest with all required assets for the format. Required when request_type is 'single'. Also accepted per item in batch mode."
    },
    "format_id": {
      "$ref": "/schemas/3.1.0/core/format-id.json",
      "description": "Always a structured object {agent_url, id} — never a plain string. Format identifier for rendering the preview. Defaults to creative_manifest.format_id if omitted. Used in single mode."
    },
    "inputs": {
      "type": "array",
      "description": "Array of input sets for generating multiple preview variants. Each input set defines macros and context values for one preview rendering. Used in single mode.",
      "items": {
        "type": "object",
        "properties": {
          "name": {
            "type": "string",
            "description": "Human-readable name for this input set (e.g., 'Sunny morning on mobile', 'Evening podcast ad', 'Desktop dark mode')"
          },
          "macros": {
            "type": "object",
            "description": "Macro values to use for this preview. Supports all universal macros from the format's supported_macros list.",
            "additionalProperties": {
              "type": "string"
            }
          },
          "context_description": {
            "type": "string",
            "description": "Natural language description of the context for AI-generated content (e.g., 'User just searched for running shoes', 'Podcast discussing weather patterns')"
          }
        },
        "required": [
          "name"
        ],
        "additionalProperties": true
      },
      "minItems": 1
    },
    "template_id": {
      "type": "string",
      "description": "Specific template ID for custom format rendering. Used in single mode."
    },
    "quality": {
      "$ref": "/schemas/3.1.0/enums/creative-quality.json",
      "description": "Render quality. 'draft' produces fast, lower-fidelity renderings. 'production' produces full-quality renderings. In batch mode, sets the default for all requests (individual items can override)."
    },
    "output_format": {
      "$ref": "/schemas/3.1.0/enums/preview-output-format.json",
      "default": "url",
      "description": "Output format. 'url' returns preview_url (iframe-embeddable URL), 'html' returns preview_html (raw HTML). In batch mode, sets the default for all requests (individual items can override). Default: 'url'."
    },
    "item_limit": {
      "type": "integer",
      "minimum": 1,
      "description": "Maximum number of catalog items to render per preview variant. Used in single mode. Creative agents SHOULD default to a reasonable sample when omitted and the catalog is large."
    },
    "requests": {
      "type": "array",
      "description": "Array of preview requests (1-50 items). Required when request_type is 'batch'. Each item follows the single request structure.",
      "items": {
        "type": "object",
        "properties": {
          "format_id": {
            "$ref": "/schemas/3.1.0/core/format-id.json",
            "description": "Format identifier for rendering the preview. Defaults to creative_manifest.format_id if omitted."
          },
          "creative_manifest": {
            "$ref": "/schemas/3.1.0/core/creative-manifest.json",
            "description": "Complete creative manifest with all required assets."
          },
          "inputs": {
            "type": "array",
            "description": "Array of input sets for generating multiple preview variants",
            "items": {
              "type": "object",
              "properties": {
                "name": {
                  "type": "string",
                  "description": "Human-readable name for this input set"
                },
                "macros": {
                  "type": "object",
                  "description": "Macro values to use for this preview",
                  "additionalProperties": {
                    "type": "string"
                  }
                },
                "context_description": {
                  "type": "string",
                  "description": "Natural language description of the context for AI-generated content"
                }
              },
              "required": [
                "name"
              ],
              "additionalProperties": true
            },
            "minItems": 1
          },
          "template_id": {
            "type": "string",
            "description": "Specific template ID for custom format rendering"
          },
          "quality": {
            "$ref": "/schemas/3.1.0/enums/creative-quality.json",
            "description": "Render quality for this preview. Overrides batch-level default."
          },
          "output_format": {
            "$ref": "/schemas/3.1.0/enums/preview-output-format.json",
            "default": "url",
            "description": "Output format for this preview. Overrides batch-level default."
          },
          "item_limit": {
            "type": "integer",
            "minimum": 1,
            "description": "Maximum number of catalog items to render in this preview."
          }
        },
        "required": [
          "creative_manifest"
        ],
        "additionalProperties": true
      },
      "minItems": 1,
      "maxItems": 50
    },
    "variant_id": {
      "type": "string",
      "description": "Platform-assigned variant identifier from get_creative_delivery response. Required when request_type is 'variant'."
    },
    "creative_id": {
      "type": "string",
      "description": "Creative identifier for context. Used in variant mode.",
      "x-entity": "creative"
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "request_type"
  ],
  "additionalProperties": true
} as const;

export const creative_PreviewCreativeResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/preview-creative-response.json",
  "title": "Preview Creative Response",
  "description": "Response containing preview links for one or more creatives. Format matches the request: single preview response for single requests, batch results for batch requests.",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    },
    {
      "$ref": "/schemas/3.1.0/core/protocol-envelope.json"
    }
  ],
  "discriminator": {
    "propertyName": "response_type"
  },
  "oneOf": [
    {
      "title": "PreviewCreativeSingleResponse",
      "type": "object",
      "description": "Single preview response - each preview URL returns an HTML page that can be embedded in an iframe",
      "properties": {
        "response_type": {
          "type": "string",
          "const": "single",
          "description": "Discriminator indicating this is a single preview response"
        },
        "previews": {
          "type": "array",
          "description": "Array of preview variants. Each preview corresponds to an input set from the request. If no inputs were provided, returns a single default preview.",
          "items": {
            "type": "object",
            "properties": {
              "preview_id": {
                "type": "string",
                "description": "Unique identifier for this preview variant"
              },
              "renders": {
                "type": "array",
                "description": "Array of rendered pieces for this preview variant. Most formats render as a single piece. Companion ad formats (video + banner), multi-placement formats, and adaptive formats render as multiple pieces.",
                "items": {
                  "$ref": "/schemas/3.1.0/creative/preview-render.json"
                },
                "minItems": 1
              },
              "input": {
                "type": "object",
                "description": "The input parameters that generated this preview variant. Echoes back the request input or shows defaults used.",
                "properties": {
                  "name": {
                    "type": "string",
                    "description": "Human-readable name for this variant"
                  },
                  "macros": {
                    "type": "object",
                    "description": "Macro values applied to this variant",
                    "additionalProperties": {
                      "type": "string"
                    }
                  },
                  "context_description": {
                    "type": "string",
                    "description": "Context description applied to this variant"
                  }
                },
                "required": [
                  "name"
                ]
              }
            },
            "required": [
              "preview_id",
              "renders",
              "input"
            ]
          },
          "minItems": 1
        },
        "interactive_url": {
          "type": "string",
          "format": "uri",
          "description": "Optional URL to an interactive testing page that shows all preview variants with controls to switch between them, modify macro values, and test different scenarios."
        },
        "expires_at": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp when preview links expire. **Optional.** Omit when preview URLs do not expire (some creative agents serve perpetually-valid preview URLs — e.g., signed asset URLs with no TTL, or session-scoped previews that the agent retires explicitly via revocation). When present, consumers MUST treat the URLs as invalid after this timestamp; when omitted, consumers MAY assume the preview URLs are valid until the creative agent revokes them out-of-band (no protocol-level revocation signal exists in 3.x — buyers requiring expiry guarantees SHOULD require sellers that publish `expires_at`)."
        },
        "context": {
          "$ref": "/schemas/3.1.0/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.1.0/core/ext.json"
        }
      },
      "required": [
        "response_type",
        "previews"
      ],
      "additionalProperties": true
    },
    {
      "title": "PreviewCreativeBatchResponse",
      "type": "object",
      "description": "Batch preview response - contains results for multiple creative requests",
      "properties": {
        "response_type": {
          "type": "string",
          "const": "batch",
          "description": "Discriminator indicating this is a batch preview response"
        },
        "results": {
          "type": "array",
          "description": "Array of preview results corresponding to each request in the same order. results[0] is the result for requests[0], results[1] for requests[1], etc. Order is guaranteed even when some requests fail. Each result contains either a successful preview response or an error.",
          "items": {
            "type": "object",
            "properties": {
              "success": {
                "type": "boolean",
                "description": "Whether this preview request succeeded"
              },
              "creative_id": {
                "type": "string",
                "description": "ID of the creative this result corresponds to. Enables correlation when processing batch results.",
                "x-entity": "creative"
              },
              "response": {
                "type": "object",
                "description": "Preview data for successful requests",
                "properties": {
                  "previews": {
                    "type": "array",
                    "description": "Array of preview variants for this creative",
                    "items": {
                      "type": "object",
                      "properties": {
                        "preview_id": {
                          "type": "string"
                        },
                        "renders": {
                          "type": "array",
                          "items": {
                            "$ref": "/schemas/3.1.0/creative/preview-render.json"
                          },
                          "minItems": 1
                        },
                        "input": {
                          "type": "object",
                          "properties": {
                            "name": {
                              "type": "string"
                            },
                            "macros": {
                              "type": "object",
                              "additionalProperties": {
                                "type": "string"
                              }
                            },
                            "context_description": {
                              "type": "string"
                            }
                          },
                          "required": [
                            "name"
                          ]
                        }
                      },
                      "required": [
                        "preview_id",
                        "renders",
                        "input"
                      ]
                    },
                    "minItems": 1
                  },
                  "interactive_url": {
                    "type": "string",
                    "format": "uri"
                  },
                  "expires_at": {
                    "type": "string",
                    "format": "date-time",
                    "description": "When the preview URLs expire. **Optional** — omit for non-expiring preview URLs. See the single-preview branch's `expires_at` description for the full convention."
                  }
                },
                "required": [
                  "previews"
                ]
              },
              "errors": {
                "type": "array",
                "description": "Errors for failed requests",
                "items": {
                  "$ref": "/schemas/3.1.0/core/error.json"
                },
                "minItems": 1
              }
            },
            "required": [
              "success",
              "creative_id"
            ],
            "oneOf": [
              {
                "title": "PreviewBatchResultSuccess",
                "properties": {
                  "success": {
                    "type": "boolean",
                    "const": true,
                    "description": "Indicates this preview request succeeded"
                  }
                },
                "required": [
                  "response"
                ]
              },
              {
                "title": "PreviewBatchResultError",
                "properties": {
                  "success": {
                    "type": "boolean",
                    "const": false,
                    "description": "Indicates this preview request failed"
                  }
                },
                "required": [
                  "errors"
                ]
              }
            ]
          },
          "minItems": 1
        },
        "context": {
          "$ref": "/schemas/3.1.0/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.1.0/core/ext.json"
        }
      },
      "required": [
        "response_type",
        "results"
      ],
      "additionalProperties": true
    },
    {
      "title": "PreviewCreativeVariantResponse",
      "type": "object",
      "description": "Variant preview response - shows what a specific creative variant looked like when served during delivery",
      "properties": {
        "response_type": {
          "type": "string",
          "const": "variant",
          "description": "Discriminator indicating this is a variant preview response"
        },
        "variant_id": {
          "type": "string",
          "description": "Platform-assigned variant identifier"
        },
        "creative_id": {
          "type": "string",
          "description": "Creative identifier this variant belongs to",
          "x-entity": "creative"
        },
        "previews": {
          "type": "array",
          "description": "Array of rendered pieces for this variant. Most formats render as a single piece.",
          "items": {
            "type": "object",
            "properties": {
              "preview_id": {
                "type": "string",
                "description": "Unique identifier for this preview"
              },
              "renders": {
                "type": "array",
                "description": "Rendered pieces for this variant",
                "items": {
                  "$ref": "/schemas/3.1.0/creative/preview-render.json"
                },
                "minItems": 1
              }
            },
            "required": [
              "preview_id",
              "renders"
            ]
          },
          "minItems": 1
        },
        "manifest": {
          "$ref": "/schemas/3.1.0/core/creative-manifest.json",
          "description": "The rendered creative manifest for this variant — the actual output that was served, not the input assets"
        },
        "expires_at": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp when preview links expire. **Optional** — omit for non-expiring preview URLs. See the top-level `PreviewCreativeResponse` branch for the full convention."
        },
        "context": {
          "$ref": "/schemas/3.1.0/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.1.0/core/ext.json"
        }
      },
      "required": [
        "response_type",
        "variant_id",
        "previews"
      ],
      "additionalProperties": true
    }
  ],
  "properties": {}
} as const;

