export const creative_SyncCreativesResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/sync-creatives-response.json",
  "title": "Sync Creatives Response",
  "description": "Response from creative sync operation. Exactly one of three shapes: (1) synchronous success — per-creative results in the creatives array (best-effort processing with per-item status/failures); (2) terminal failure — errors array with no creatives processed; (3) submitted task envelope — status 'submitted' with task_id when the whole operation is queued (batch ingestion, async review that must settle before per-item results can be issued). The submitted branch MAY carry advisory errors for non-blocking warnings; terminal failures belong in the error branch. Final per-item results land on the task completion artifact, not this envelope. These three shapes are mutually exclusive — a response has exactly one.",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    },
    {
      "$ref": "/schemas/3.1.0/core/protocol-envelope.json"
    }
  ],
  "oneOf": [
    {
      "title": "SyncCreativesSuccess",
      "description": "Success response - sync operation processed creatives (may include per-item failures)",
      "type": "object",
      "properties": {
        "dry_run": {
          "type": "boolean",
          "description": "Whether this was a dry run (no actual changes made)"
        },
        "creatives": {
          "type": "array",
          "description": "Results for each creative processed. Items with action='failed' indicate per-item validation/processing failures, not operation-level failures.",
          "items": {
            "type": "object",
            "properties": {
              "creative_id": {
                "type": "string",
                "description": "Creative ID from the request",
                "x-entity": "creative"
              },
              "account": {
                "$ref": "/schemas/3.1.0/core/account.json",
                "description": "Account that owns this creative"
              },
              "action": {
                "$ref": "/schemas/3.1.0/enums/creative-action.json",
                "description": "Action taken for this creative during this sync operation (lifecycle operation, not approval state)."
              },
              "status": {
                "$ref": "/schemas/3.1.0/enums/creative-status.json",
                "description": "Advisory review-lifecycle state of the creative after this sync — a UI hint and polling-scheduling signal, NOT a spend-authorization gate. Orthogonal to action — action says what the sync did (created, updated, ...); status says where the creative sits in review. Values come from CreativeStatus only (processing, pending_review, approved, suspended, rejected, archived) — never from CreativeAction. Sellers with async review return processing or pending_review; sellers with synchronous review MAY return a terminal value (approved, rejected) or suspended when a recoverable dependency/authorization gate prevents serving. Buyers MUST NOT gate downstream spend or package activation on status: approved from this response — a compromised or buggy seller could declare approved while bypassing content-policy review. Reconcile via list_creatives or a signed review webhook before committing spend. Authoritative state is always via list_creatives. MUST be omitted when action is failed or deleted (the creative has no meaningful review state — failure details belong in the errors array; deleted creatives are gone from the library). Omit entirely when the seller has no review lifecycle at all."
              },
              "platform_id": {
                "type": "string",
                "description": "Platform-specific ID assigned to the creative"
              },
              "changes": {
                "type": "array",
                "description": "Field names that were modified (only present when action='updated')",
                "items": {
                  "type": "string"
                }
              },
              "errors": {
                "type": "array",
                "description": "Validation or processing errors (only present when action='failed')",
                "items": {
                  "$ref": "/schemas/3.1.0/core/error.json"
                }
              },
              "warnings": {
                "type": "array",
                "description": "Non-fatal warnings about this creative",
                "items": {
                  "type": "string"
                }
              },
              "preview_url": {
                "type": "string",
                "format": "uri",
                "description": "Preview URL for generative creatives (only present for generative formats)"
              },
              "expires_at": {
                "type": "string",
                "format": "date-time",
                "description": "ISO 8601 timestamp when preview link expires (only present when preview_url exists)"
              },
              "assigned_to": {
                "type": "array",
                "description": "Package IDs this creative was successfully assigned to (only present when assignments were requested)",
                "items": {
                  "type": "string"
                }
              },
              "assignment_errors": {
                "type": "object",
                "description": "Assignment errors by package ID (only present when assignment failures occurred)",
                "patternProperties": {
                  "^[a-zA-Z0-9_-]+$": {
                    "type": "string",
                    "description": "Error message for this package assignment"
                  }
                },
                "additionalProperties": true
              }
            },
            "required": [
              "creative_id",
              "action"
            ],
            "additionalProperties": true,
            "allOf": [
              {
                "if": {
                  "properties": {
                    "action": {
                      "enum": [
                        "failed",
                        "deleted"
                      ]
                    }
                  },
                  "required": [
                    "action"
                  ]
                },
                "then": {
                  "not": {
                    "required": [
                      "status"
                    ]
                  }
                }
              }
            ]
          }
        },
        "sandbox": {
          "type": "boolean",
          "description": "When true, this response contains simulated data from sandbox mode."
        },
        "context": {
          "$ref": "/schemas/3.1.0/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.1.0/core/ext.json"
        }
      },
      "required": [
        "creatives"
      ],
      "additionalProperties": true,
      "not": {
        "anyOf": [
          {
            "required": [
              "errors"
            ]
          },
          {
            "required": [
              "task_id"
            ]
          },
          {
            "properties": {
              "status": {
                "const": "submitted"
              }
            },
            "required": [
              "status"
            ]
          }
        ]
      }
    },
    {
      "title": "SyncCreativesError",
      "description": "Error response - operation failed completely, no creatives were processed",
      "type": "object",
      "properties": {
        "errors": {
          "type": "array",
          "description": "Operation-level errors that prevented processing any creatives (e.g., authentication failure, service unavailable, invalid request format)",
          "items": {
            "$ref": "/schemas/3.1.0/core/error.json"
          },
          "minItems": 1
        },
        "context": {
          "$ref": "/schemas/3.1.0/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.1.0/core/ext.json"
        }
      },
      "required": [
        "errors"
      ],
      "additionalProperties": true,
      "not": {
        "anyOf": [
          {
            "required": [
              "creatives"
            ]
          },
          {
            "required": [
              "dry_run"
            ]
          },
          {
            "required": [
              "sandbox"
            ]
          },
          {
            "required": [
              "task_id"
            ]
          },
          {
            "properties": {
              "status": {
                "const": "submitted"
              }
            },
            "required": [
              "status"
            ]
          }
        ]
      }
    },
    {
      "title": "SyncCreativesSubmitted",
      "description": "Async task envelope returned when the whole sync operation cannot be confirmed before the response is emitted — for example, when the seller batches ingestion, when async review must settle before per-item results can be issued, or when governance review gates the sync. The buyer polls tasks/get with task_id or receives a webhook when the task completes; the creatives array with per-item action/status lands on the completion artifact, not this envelope. Per-item async review (an item in pending_review while the rest of the sync resolves synchronously) belongs on the SyncCreativesSuccess branch with status: pending_review, not here.",
      "type": "object",
      "properties": {
        "status": {
          "type": "string",
          "const": "submitted",
          "description": "Task-level status literal. Discriminates this async envelope from the synchronous success shape, whose creatives array carries per-item approval state via CreativeStatus. See task-status.json for the full task-status enum."
        },
        "task_id": {
          "type": "string",
          "description": "Task handle the buyer uses with tasks/get, and that the seller references on push-notification callbacks. The creatives array is issued on the completion artifact, not here. Per AdCP wire conventions this is snake_case; A2A adapters MAY surface it as taskId, but the payload field emitted by the agent is task_id.",
          "x-entity": "task"
        },
        "message": {
          "type": "string",
          "maxLength": 2000,
          "description": "Optional human-readable explanation of why the task is submitted — e.g., 'Batch ingestion queued; typical turnaround 15-30 minutes.' Plain text only. Buyers MUST treat this as untrusted seller input: escape before rendering to HTML UIs, and sanitize or isolate before passing to an LLM prompt context — a hostile seller may inject prompt-injection payloads aimed at the buyer's agent."
        },
        "errors": {
          "type": "array",
          "description": "Optional advisory errors accompanying the submitted envelope. Use only for non-blocking warnings (e.g., throttled_severity advisories, governance observations). Terminal failures belong in the error branch, not here.",
          "items": {
            "$ref": "/schemas/3.1.0/core/error.json"
          }
        },
        "context": {
          "$ref": "/schemas/3.1.0/core/context.json"
        },
        "ext": {
          "$ref": "/schemas/3.1.0/core/ext.json"
        }
      },
      "required": [
        "status",
        "task_id"
      ],
      "additionalProperties": true,
      "not": {
        "required": [
          "creatives"
        ]
      }
    }
  ],
  "properties": {}
} as const;

export const creative_ValidateInputRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/validate-input-request.json",
  "title": "Validate Input Request",
  "description": "Request payload for the validate_input task. Lets buyers dry-run a creative manifest against canonical formats and/or specific products before committing to a render. Cheaper than preview_creative (no synthesis cost). Used by build_creative internally to validate inputs before producing output. For genuinely nondeterministic generative platforms (Veo/Sora/Runway-class) where predictive validation is impossible, the platform's own post-synthesis QA loop applies — validate_input is the predictable-case primitive.\n\nThe `targets[]` array is a discriminated list of validation targets, mirroring the response shape on `validate-input-result.json#target`. Each entry has a `kind` (canonical | product | third_party_format) plus a kind-specific identifier. Discriminated-by-kind on both sides eliminates a wire-shape mismatch: a previous draft used `format_ids: string[]` for canonical names alongside `product_ids: string[]`, which collided with `Product.format_ids: FormatId[]` ({agent_url, id}) — codegen would emit the same field name with two different types. Discriminated `targets[]` makes the intent explicit and codegen-clean.",
  "type": "object",
  "required": [
    "manifest"
  ],
  "properties": {
    "account": {
      "$ref": "/schemas/3.1.0/core/account-ref.json",
      "description": "Optional account scope for seller-specific product validation. Required by sellers that route product declarations by buyer account."
    },
    "brand": {
      "$ref": "/schemas/3.1.0/core/brand-ref.json",
      "description": "Optional brand scope when account is omitted or the seller keys sandbox validation by brand identity."
    },
    "manifest": {
      "$ref": "/schemas/3.1.0/core/creative-manifest.json",
      "description": "Creative manifest to validate."
    },
    "targets": {
      "type": "array",
      "minItems": 1,
      "maxItems": 50,
      "description": "Discriminated list of validation targets. Each entry mirrors the `target` shape on `validate-input-result.json` so the request/response wire shapes match exactly. Multi-target requests enable universal-creative scenarios where one manifest targets multiple sellers' format declarations in a single round-trip; the response carries one result per target in the same order.",
      "items": {
        "type": "object",
        "required": [
          "kind",
          "id"
        ],
        "discriminator": {
          "propertyName": "kind"
        },
        "oneOf": [
          {
            "title": "Canonical Format Target",
            "properties": {
              "kind": {
                "type": "string",
                "const": "canonical"
              },
              "id": {
                "type": "string",
                "description": "Canonical format name from `canonical-format-kind.json` (e.g., `image`, `video_hosted`, `audio_daast`). Validators check the manifest against the canonical's parameter schema."
              }
            },
            "required": [
              "kind",
              "id"
            ]
          },
          {
            "title": "Product Target",
            "properties": {
              "kind": {
                "type": "string",
                "const": "product"
              },
              "id": {
                "type": "string",
                "description": "Product ID. Validators check the manifest against the product's inline `ProductFormatDeclaration` narrowing of the canonical (parameter constraints, slot requirements, platform extensions)."
              }
            },
            "required": [
              "kind",
              "id"
            ]
          },
          {
            "title": "Third-Party Format Target",
            "properties": {
              "kind": {
                "type": "string",
                "const": "third_party_format"
              },
              "id": {
                "type": "string",
                "format": "uri",
                "description": "URI-form format identifier referencing a third-party format definition (e.g., `https://flashtalking.example/formats/image_300x250@sha256:...`). Validators fetch the definition (digest-pinned, cached) and validate the manifest against it."
              }
            },
            "required": [
              "kind",
              "id"
            ]
          }
        ]
      }
    }
  },
  "additionalProperties": true,
  "examples": [
    {
      "description": "Dry-run a video manifest against canonical video_hosted and a specific Meta product in one round-trip",
      "data": {
        "manifest": {
          "format_kind": "video_hosted",
          "assets": {
            "video_main": {
              "asset_type": "video",
              "url": "https://cdn.acme.example/spring-30s.mp4",
              "duration_ms": 30000,
              "width": 1080,
              "height": 1920
            }
          },
          "brand": {
            "domain": "acme.example"
          }
        },
        "targets": [
          {
            "kind": "canonical",
            "id": "video_hosted"
          },
          {
            "kind": "product",
            "id": "meta_reels_us"
          }
        ]
      }
    }
  ]
} as const;

export const creative_ValidateInputResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/validate-input-response.json",
  "title": "Validate Input Response",
  "description": "Response payload for the validate_input task. Returns per-target validation results — one entry per format_id or product_id requested. Each result carries a `result_kind` discriminator (`validated_pass` / `validated_fail` / `unvalidatable_nondeterministic`) so callers can branch on three meaningfully different outcomes. The `predicted` field on violations carries the platform's pre-flight estimate (e.g., predicted audio duration from text-length analysis), NOT the actual output — there is no protocol state for orphaned out-of-spec artifacts. For nondeterministic generative platforms (Veo / Sora / Runway-class with `synthesis_nondeterministic: true`), the result_kind is `unvalidatable_nondeterministic` — predictive validation is impossible, the platform's post-synthesis QA loop applies on `build_creative`, and out-of-spec output never reaches this surface (instead `build_creative` returns task_failed with synthesis_failed reason).\n\nThe `ValidateInputResult` type is split into its own schema (`/schemas/creative/validate-input-result.json`) rather than inlined here because the same per-target shape is intended for reuse by adjacent async-validation surfaces (planned: per-batch result envelopes on `build_creative` async paths, and asynchronous canonical-against-product validation in `sync_creatives`). Producers that only need the synchronous batch shape today MAY treat the split as YAGNI, but the schema reuse anchors the violation/retry shape so downstream surfaces don't drift.",
  "type": "object",
  "required": [
    "results"
  ],
  "properties": {
    "results": {
      "type": "array",
      "items": {
        "$ref": "/schemas/3.1.0/creative/validate-input-result.json"
      },
      "description": "Per-target validation results."
    }
  },
  "additionalProperties": true,
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    },
    {
      "$ref": "/schemas/3.1.0/core/protocol-envelope.json"
    }
  ]
} as const;

export const creative_ValidateInputResult = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/validate-input-result.json",
  "title": "Validate Input Result",
  "description": "Per-target result of a validate_input call. The `result_kind` discriminator (replacing the earlier boolean `ok`) lets buyers distinguish three meaningfully different outcomes:\n\n- `validated_pass` — manifest validates cleanly against the target. Buyers can submit with confidence.\n- `validated_fail` — manifest is structurally evaluable AND fails specific constraints. `violations[]` enumerates which. Buyers fix and retry.\n- `unvalidatable_nondeterministic` — predictive validation is impossible because the target's production pipeline is genuinely nondeterministic (Veo / Sora / Runway-class formats with `synthesis_nondeterministic: true`). The platform's own post-synthesis QA loop applies; outcome is unknowable until `build_creative` runs. Buyers MUST plan for the QA-loop semantics: submission may return `task_failed` with a `synthesis_failed` reason if the QA loop exhausts. There is no protocol state for orphaned out-of-spec artifacts.\n\nThe boolean `ok` field carried in earlier drafts is removed — it conflated `validated_fail` (a real validation result the buyer can act on) with `unvalidatable_nondeterministic` (a structural property of the target the buyer needs to handle differently). `validated_fail` returns `violations[]`; `unvalidatable_nondeterministic` does not (there's nothing to enumerate).\n\n**Scope of validation (normative).** `validate_input` validates **manifest structure** against the canonical / product / third-party format target — slot counts, asset types, parameter ranges, format-shape constraints. It does NOT predict the surface's per-impression rendering choice. This distinction matters for `composition_model: algorithmic` formats (`responsive_creative`, `agent_placement`) where the surface picks combinations or phrasing at delivery time: the buyer's asset pool can still be structurally validated (does it meet the count/size/length requirements?) → `validated_pass` or `validated_fail` with violations. What's unpredictable is the rendered output composition, and that's NOT what `validate_input` claims to predict. `unvalidatable_nondeterministic` is reserved for `synthesis_nondeterministic: true` cases where the production pipeline itself can't be evaluated upfront — distinct from algorithmic composition where the inputs ARE evaluable but the output rendering isn't. Buyers calling `validate_input` on an algorithmic-composition target SHOULD expect a structural verdict (pass/fail), not a rendering preview.",
  "type": "object",
  "required": [
    "target",
    "result_kind"
  ],
  "properties": {
    "target": {
      "type": "object",
      "required": [
        "kind",
        "id"
      ],
      "properties": {
        "kind": {
          "type": "string",
          "enum": [
            "canonical",
            "product",
            "third_party_format"
          ]
        },
        "id": {
          "type": "string",
          "description": "Canonical format name (e.g., 'image'), product_id, or URI-form format_id."
        }
      },
      "additionalProperties": true
    },
    "result_kind": {
      "type": "string",
      "enum": [
        "validated_pass",
        "validated_fail",
        "unvalidatable_nondeterministic"
      ],
      "description": "Discriminator for the validation outcome. See schema description for the three states. Replaces the earlier boolean `ok` to distinguish 'failed validation' from 'platform is nondeterministic, can't pre-validate'."
    },
    "violations": {
      "type": "array",
      "description": "When `result_kind` is `validated_fail`, the specific constraints the manifest fails to meet. MUST be absent (or empty) for `validated_pass` and `unvalidatable_nondeterministic` — neither has constraint violations to enumerate (`unvalidatable_nondeterministic` doesn't validate at all; `validated_pass` has nothing to fail).",
      "items": {
        "type": "object",
        "required": [
          "rule",
          "field"
        ],
        "properties": {
          "rule": {
            "type": "string",
            "description": "Rule name (e.g., 'duration_ms_range', 'aspect_ratio', 'max_file_size_kb')."
          },
          "expected": {
            "description": "Expected value or range (e.g., '28000-32000', '9:16', 200)."
          },
          "predicted": {
            "description": "Platform's pre-flight estimate for this field (NOT the actual output — there is no protocol state for orphaned out-of-spec artifacts). For TTS, this might be the predicted audio duration from text-length analysis. Helps the buyer fix the input before committing to a build."
          },
          "field": {
            "type": "string",
            "description": "Path to the violating field (e.g., 'assets.video_main.duration_ms')."
          },
          "retry_with": {
            "type": "object",
            "description": "Optional advisory adjustment hint. Platforms MAY suggest a corrected input shape; buyers MUST treat this as advisory, not authoritative.",
            "additionalProperties": true
          }
        },
        "additionalProperties": true
      }
    }
  },
  "allOf": [
    {
      "if": {
        "properties": {
          "result_kind": {
            "const": "validated_pass"
          }
        },
        "required": [
          "result_kind"
        ]
      },
      "then": {
        "not": {
          "required": [
            "violations"
          ]
        }
      }
    },
    {
      "if": {
        "properties": {
          "result_kind": {
            "const": "unvalidatable_nondeterministic"
          }
        },
        "required": [
          "result_kind"
        ]
      },
      "then": {
        "not": {
          "required": [
            "violations"
          ]
        }
      }
    }
  ],
  "additionalProperties": true,
  "examples": [
    {
      "description": "Manifest fails Meta Reels product narrowing because its duration exceeds the [3000, 90000] range",
      "data": {
        "target": {
          "kind": "product",
          "id": "meta_reels_us"
        },
        "result_kind": "validated_fail",
        "violations": [
          {
            "rule": "duration_ms_range",
            "expected": "3000-90000",
            "predicted": 95000,
            "field": "assets.video_main.duration_ms",
            "retry_with": {
              "trim_ms_from_end": 5000
            }
          }
        ]
      }
    },
    {
      "description": "Manifest passes canonical video_hosted (canonical doesn't constrain duration; products narrow)",
      "data": {
        "target": {
          "kind": "canonical",
          "id": "video_hosted"
        },
        "result_kind": "validated_pass"
      }
    },
    {
      "description": "Veo generative video product is unvalidatable up-front; buyer plans for the QA-loop semantics on build_creative",
      "data": {
        "target": {
          "kind": "product",
          "id": "veo_generative_video_vertical_15s"
        },
        "result_kind": "unvalidatable_nondeterministic"
      }
    }
  ]
} as const;

export const creative_VideoBrief = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/creative/video-brief.json",
  "title": "Video Brief",
  "description": "Structured per-segment generation brief for generative video products (Veo / Sora / Runway-class). Each `segments[]` entry declares a timed prompt the synthesis pipeline turns into a continuous shot — `order`, `duration_ms`, `prompt`, optional `vo` (voiceover line) and `caption` (on-screen text). This is a *generation* brief, not a creative-direction storyboard: there is no camera direction, shot type, mood, or reference-asset attachment. Buyers wanting to direct camera, lighting, or reference-image conditioning attach a `reference-asset.json` with `purpose: \"storyboard\"` separately — that's the visual-direction surface; video-brief is the structured prompt the model receives. Renamed from earlier `scenes` to call the shape what it is (a brief, not a scene-level production document).",
  "type": "object",
  "required": [
    "segments"
  ],
  "properties": {
    "segments": {
      "type": "array",
      "minItems": 1,
      "description": "Ordered list of per-segment prompts that compose the generated video. The sum of `duration_ms` across segments should match the target video duration declared by the format declaration's `duration_ms_exact` or `duration_ms_range`.",
      "items": {
        "type": "object",
        "required": [
          "order",
          "duration_ms",
          "prompt"
        ],
        "properties": {
          "order": {
            "type": "integer",
            "minimum": 1,
            "description": "1-indexed sequence position of this segment in the final video."
          },
          "duration_ms": {
            "type": "integer",
            "minimum": 1,
            "description": "Duration of this segment in milliseconds."
          },
          "prompt": {
            "type": "string",
            "description": "Text prompt fed to the synthesis pipeline for this segment (subject, action, setting, mood). Renamed from earlier `description` to make explicit that this is a generation prompt — not a description-of-finished-content."
          },
          "vo": {
            "type": "string",
            "description": "Voiceover line for this segment (optional)."
          },
          "caption": {
            "type": "string",
            "description": "On-screen caption text for this segment (optional)."
          }
        },
        "additionalProperties": true
      }
    }
  },
  "additionalProperties": true,
  "examples": [
    {
      "segments": [
        {
          "order": 1,
          "duration_ms": 3000,
          "prompt": "Sunset beach, brand logo overlay top-left, warm cinematic tone",
          "vo": "Welcome to summer with Acme",
          "caption": "Summer Sale Now"
        },
        {
          "order": 2,
          "duration_ms": 4000,
          "prompt": "Product close-up — limited-edition sneakers, slow zoom on stitching",
          "vo": "Limited edition. Hand-crafted.",
          "caption": "Up to 50% Off"
        },
        {
          "order": 3,
          "duration_ms": 3000,
          "prompt": "Logo end-card on solid brand-color background with CTA button overlay",
          "caption": "Shop Now"
        }
      ]
    }
  ]
} as const;

