export const enums_AdcpProtocol = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/adcp-protocol.json",
  "title": "AdCP Protocol",
  "description": "AdCP protocols for task categorization — referenced by tasks-list-request, webhook payloads, and other task-lifecycle surfaces. Values are kebab-case. This enum shares the same axis as supported_protocols (see /schemas/protocol/get-adcp-capabilities-response.json), which uses snake_case on the wire. Compliance testing support is declared via the `capabilities.compliance_testing` block, not as a protocol value.",
  "type": "string",
  "enum": [
    "media-buy",
    "signals",
    "governance",
    "creative",
    "brand",
    "sponsored-intelligence",
    "measurement"
  ],
  "enumDescriptions": {
    "media-buy": "Campaign creation, package management, delivery optimization, and conversion tracking",
    "signals": "Audience signal discovery and activation",
    "governance": "Property governance (identity, authorization, data, selection), brand standards, and compliance",
    "creative": "Creative asset management, format discovery, and rendering",
    "brand": "Brand identity, rights discovery, and rights acquisition",
    "sponsored-intelligence": "AI-mediated commerce and conversational sponsored experiences, including buyer-agent sessions and measurement of AI-surfaced outcomes",
    "measurement": "Experimental in 3.1. Measurement vendor capability discovery and per-metric reporting. Currently scoped to `get_adcp_capabilities` for catalog discovery (the `measurement` capability block); agents implementing it must list `measurement.core` in experimental_features. Additional measurement tasks (reporting, attribution, panel queries) land in subsequent minors."
  }
} as const;

export const enums_AdjustmentKind = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/adjustment-kind.json",
  "title": "Price Adjustment Kind",
  "description": "Categorizes how a price adjustment affects the transaction",
  "type": "string",
  "enum": [
    "fee",
    "discount",
    "commission",
    "settlement"
  ],
  "enumDescriptions": {
    "fee": "Increases the price the buyer pays and the revenue the seller receives. Applied between list_price and fixed_price (e.g., ad serving fees, data/targeting surcharges, brand safety verification).",
    "discount": "Reduces the price the buyer pays and the revenue the seller receives. Applied between list_price and fixed_price (e.g., volume discounts, negotiated rates, early booking).",
    "commission": "Does not change the buyer's price or budget. Represents a revenue split — the portion retained by an intermediary (e.g., agency commission). Budgets are managed inclusive of commissions.",
    "settlement": "Does not change the committed price or budget. Applied at invoicing or payment time (e.g., cash discount for early payment). Informational for buyer agents; affects actual settlement amount."
  }
} as const;

