export const enums_CatalogItemStatus = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/catalog-item-status.json",
  "title": "Catalog Item Status",
  "description": "Approval status of an individual item within a synced catalog. Platforms review catalog items and may approve, reject, or flag them for issues (similar to Google Merchant Center product review).",
  "type": "string",
  "enum": [
    "approved",
    "pending",
    "rejected",
    "warning",
    "withdrawn"
  ],
  "enumDescriptions": {
    "approved": "Item passed platform review and is eligible for use in campaigns. May be transitioned by the seller to 'withdrawn' on seller-initiated removal (inventory pulled, policy enforcement) — distinct from 'rejected', which signals a review outcome the buyer can remediate.",
    "pending": "Item is awaiting platform review. Items enter this state on initial sync and when re-synced after rejection.",
    "rejected": "Item failed platform review (missing fields, policy violation, invalid data). Not terminal — fix the issue in the catalog and re-sync to reset the item to pending.",
    "warning": "Item is approved and serving but has issues worth fixing (e.g., low-quality image, missing optional fields). The item remains eligible for delivery.",
    "withdrawn": "Seller has removed the item from active use — inventory pulled, policy enforcement, or other seller-initiated reasons not covered by 'rejected'. Distinct lifecycle from 'rejected': no buyer-side resubmit path. Sellers MUST surface a corresponding impairment on any active media buy that targets a package referencing this catalog item. Sellers MAY return the item to 'approved' on re-publication."
  }
} as const;

