export const enums_ForecastRangeUnit = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/forecast-range-unit.json",
  "title": "Forecast Range Unit",
  "description": "Describes how to interpret the points array in a DeliveryForecast — what axis the curve represents",
  "type": "string",
  "enum": [
    "spend",
    "availability",
    "reach_freq",
    "weekly",
    "daily",
    "clicks",
    "conversions",
    "package"
  ],
  "enumDescriptions": {
    "spend": "Points at ascending budget levels. Standard budget curve showing how delivery metrics scale with spend. Default when field is omitted.",
    "availability": "Each point represents total available inventory for the requested targeting and dates. Budget is omitted — metrics express what exists, not what a given spend level buys. Use metrics.spend to express the estimated cost. Typical for guaranteed and direct-sold inventory where the forecast is an availability check.",
    "reach_freq": "Points at ascending reach/frequency targets. Used in broadcast planning where the publisher shows how cost scales with frequency goals.",
    "weekly": "Metrics are per-week values. Budget refers to total campaign spend. Frequency of 3.2 means 3.2 exposures per week.",
    "daily": "Metrics are per-day values. Budget refers to total campaign spend.",
    "clicks": "Points at ascending click targets. Used in performance campaigns where the buyer specifies click goals.",
    "conversions": "Points at ascending conversion targets. Used in goal-based planning (e.g., Meta-style 'tell me your goal, I'll tell you the budget').",
    "package": "Each point represents a distinct inventory package (e.g., Good/Better/Best tiers, daypart packages, sponsorships). Points are not levels on a spend curve — they are separate products with different inventory compositions. Used by broadcast TV, audio, and DOOH sellers who sell packages rather than impressions at variable spend levels."
  }
} as const;

export const enums_ForecastableMetric = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/forecastable-metric.json",
  "title": "Forecastable Metric",
  "description": "Standard delivery, engagement, and availability metric names for forecasts. **Most values mirror `available-metric.json`** (the canonical closed delivery vocabulary) — `impressions`, `clicks`, `spend`, `views`, `completed_views`, `engagements`, `follows`, `saves`, `profile_visits`, `downloads`, `plays`, `reach`, `frequency`, `grps` are all shared. **Forecast-only deltas** are `audience_size`, `measured_impressions`, and `coverage_rate` — these exist here because forecasts can reasonably project them but delivery reporting today does not surface them as `available-metric` entries (delivery uses other paths: e.g., `measured_impressions` flows through `vendor_metric_values` when a third-party vendor reports it). When the industry converges on adding any of these to delivery reporting, those values graduate into `available-metric.json` and this enum's deltas shrink. For outcome/conversion forecasts (purchases, leads, app installs, etc.), use event-type enum values as metric keys instead. The ForecastPoint metrics map accepts any string key, so both forecastable-metric and event-type values can be used together.",
  "type": "string",
  "enum": [
    "audience_size",
    "reach",
    "frequency",
    "impressions",
    "clicks",
    "spend",
    "views",
    "completed_views",
    "grps",
    "engagements",
    "follows",
    "saves",
    "profile_visits",
    "measured_impressions",
    "downloads",
    "plays",
    "coverage_rate"
  ],
  "enumDescriptions": {
    "audience_size": "Estimated addressable audience size",
    "reach": "Estimated unique reach. The reach_unit field on DeliveryForecast specifies the measurement unit (individuals, households, devices, etc.).",
    "frequency": "Estimated average frequency per individual",
    "impressions": "Estimated ad-server or first-party delivery count. When measured_impressions is also present, impressions represents the seller's own delivery count while measured_impressions represents the third-party currency count — both may appear on the same forecast point as complementary layers.",
    "clicks": "Estimated clicks",
    "spend": "Estimated spend in the forecast currency",
    "views": "Estimated views at threshold (for CPV)",
    "completed_views": "Estimated video/audio completions. Threshold depends on view_duration_seconds if set on the optimization goal.",
    "grps": "Estimated Gross Rating Points (for CPP). When present, the demographic_system and demographic fields on DeliveryForecast should specify the target demographic.",
    "engagements": "Estimated engagements (social reactions, comments, shares, story opens, overlay taps, etc.)",
    "follows": "Estimated new followers, page likes, or free channel/feed subscribes",
    "saves": "Estimated saves, bookmarks, playlist adds, or pins",
    "profile_visits": "Estimated visits to the brand's in-platform page or profile",
    "measured_impressions": "Impressions as counted by the third-party measurement provider specified in measurement_source on DeliveryForecast. Complementary to impressions — both may appear on the same forecast point. impressions is the ad-server delivery count; measured_impressions is the third-party currency count. Present when measurement_source is set. Use with method 'guaranteed' for contractually committed delivery, or with method 'modeled' for third-party-measured estimates without a guarantee.",
    "downloads": "Estimated downloads. Primary currency for podcast advertising per IAB Podcast Measurement guidelines.",
    "plays": "Number of times the ad creative is displayed on a DOOH screen or played in a loop. Raw play count before any impression multiplier is applied. Use alongside impressions or measured_impressions when buyers need both the play count and the multiplied audience figure.",
    "coverage_rate": "Share of the declared forecast scope represented by this point. Used primarily for signal coverage and availability breakdowns. Range 0.0 to 1.0."
  }
} as const;

