export const enums_ImpairmentOfflineState = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/impairment-offline-state.json",
  "title": "Impairment Offline State",
  "description": "Canonical offline values that may appear in impairment.transition.to. Each value is the offline endpoint of a specific resource type's lifecycle enum. The resource_type ↔ offline_state pairing is validated by the impairment.coherence assertion — not by this schema — so a single shared enum is sufficient at the field-validation layer.",
  "type": "string",
  "enum": [
    "suspended",
    "rejected",
    "withdrawn",
    "insufficient",
    "depublished"
  ],
  "enumDescriptions": {
    "suspended": "Offline value of audience-status and a recoverable offline value of creative-status. Valid when resource_type='audience', and valid when resource_type='creative' for recoverable dependency/authorization loss such as a published-post authorization expiring or a source post becoming private.",
    "rejected": "Offline value of creative-status. Valid when resource_type='creative'. Reached from approved when seller revokes post-approval.",
    "withdrawn": "Offline value of catalog-item-status. Valid when resource_type='catalog_item'. Seller-initiated removal, distinct from review-failure rejection.",
    "insufficient": "Offline value of assessment-status surfaced through event-source-health.status. Valid when resource_type='event_source'. Covers source-offline (zero events received over the evaluation window) — disambiguate via events_received_24h and last_event_at.",
    "depublished": "Synthetic offline marker — property has no per-resource status field; publication state is derived from brand.json / adagents.json. Valid when resource_type='property'."
  }
} as const;

export const enums_ImpairmentReasonCode = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/enums/impairment-reason-code.json",
  "title": "Impairment Reason Code",
  "description": "Categorical reason a dependency resource entered an offline state, surfacing why a media buy is impaired. Flat shared enum across resource types — per-resource-type valid subsets are documented in enumDescriptions. Buyer agents key remediation logic off reason_code; free-text 'reason' on the impairment object carries human-readable detail.",
  "type": "string",
  "enum": [
    "policy_violation",
    "consent_expired",
    "ttl_expired",
    "pii_audit_failed",
    "seller_removed",
    "content_rejected",
    "identity_authorization_revoked",
    "identity_authorization_expired",
    "source_private",
    "source_offline",
    "property_depublished"
  ],
  "enumDescriptions": {
    "policy_violation": "Seller policy enforcement removed the resource from active use. Applies to: audience, creative, catalog_item, property.",
    "consent_expired": "Consent basis for using the resource has lapsed (e.g., hashed identifier consent expiry on a synced audience). Applies to: audience.",
    "ttl_expired": "Resource exceeded its time-to-live and was retired by the seller. Applies to: audience.",
    "pii_audit_failed": "Resource failed a privacy / PII audit. Applies to: audience.",
    "seller_removed": "Seller withdrew the resource from active use for operational reasons not covered by other codes (e.g., inventory withdrawal). Applies to: catalog_item, audience, creative, property. Distinct from policy_violation (seller-policy-driven) and from catalog_item's withdrawn state (the lifecycle endpoint) — this code is the impairment reason that surfaces when a previously-active resource is withdrawn.",
    "content_rejected": "Previously-approved creative content was re-reviewed and rejected. Applies to: creative.",
    "identity_authorization_revoked": "Authorization for a creative's referenced identity or post was revoked. Applies to: creative, especially `published_post` reference creatives. Offline state is usually `suspended` while authorization can be restored.",
    "identity_authorization_expired": "Authorization for a creative's referenced identity or post expired. Applies to: creative, especially `published_post` reference creatives. Offline state is usually `suspended` while authorization can be renewed.",
    "source_private": "A creative's referenced source post became private or inaccessible to the seller. Applies to: creative, especially `published_post` reference creatives. Offline state is usually `suspended` while visibility can be restored.",
    "source_offline": "Underlying event/signal source stopped firing (zero events received over the seller's evaluation window). Applies to: event_source.",
    "property_depublished": "Property was depublished or removed from the seller's catalog via brand.json / adagents.json. Verification is via the publisher's brand.json / adagents.json files. Applies to: property."
  }
} as const;

