export const errorDetails_AuthorizationRequired = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/error-details/authorization-required.json",
  "title": "Authorization Required Details",
  "description": "Recommended details shape for AUTHORIZATION_REQUIRED errors. The caller's AdCP credential was accepted, but the seller cannot complete the requested action until one or more downstream platform connections or grants are completed, restored, or refreshed.",
  "type": "object",
  "properties": {
    "required_connections": {
      "type": "array",
      "items": {
        "$ref": "/schemas/3.1.0/core/downstream-connection-requirement.json"
      },
      "description": "Complete set of downstream connections known to be required for the relevant product, format, or request."
    },
    "missing_connections": {
      "type": "array",
      "items": {
        "$ref": "/schemas/3.1.0/core/downstream-connection-requirement.json"
      },
      "description": "Subset of downstream connections that blocked the current request. Sellers SHOULD populate this array when the caller needs to route a human through a connections flow. Entries with `status` of `missing`, `pending`, `expired`, or `revoked` MUST include either `provider` or `authorization_url` so the buyer can route the remediation unambiguously."
    },
    "authorization_url": {
      "type": "string",
      "format": "uri",
      "description": "General recovery URL when there is a single obvious authorization step or when the seller has its own connection-management page."
    },
    "authorization_instructions": {
      "type": "string",
      "description": "Human-readable recovery instructions. Use `missing_connections[].authorization_instructions` when instructions differ per downstream connection."
    },
    "reference_authorization": {
      "type": "object",
      "description": "Legacy or provider-specific authorization hint for the referenced object. Prefer `missing_connections[]` for new implementations.",
      "additionalProperties": true
    }
  },
  "additionalProperties": true,
  "examples": [
    {
      "missing_connections": [
        {
          "provider": "social.example",
          "connection_type": "publisher_identity",
          "required_for": [
            "sync_creatives"
          ],
          "scope": "identity",
          "status": "missing",
          "resource_ref": {
            "post_url": "https://social.example/@acme/post/12345"
          },
          "authorization_url": "https://seller.example/connections/social/authorize?post=12345",
          "authorization_instructions": "Connect the creator or page that owns the source post."
        }
      ]
    }
  ]
} as const;

export const errorDetails_BillingNotPermittedForAgent = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/error-details/billing-not-permitted-for-agent.json",
  "title": "Billing Not Permitted For Agent Details",
  "description": "Recommended details shape for BILLING_NOT_PERMITTED_FOR_AGENT errors. Returned when the seller's declared `supported_billing` capability accepts the requested value but the calling buyer agent's commercial relationship with the seller does not (e.g., the agent is onboarded as passthrough-only — no payments relationship — so `agent` and `advertiser` reject). The shape is deliberately minimal: it returns the value that was rejected and at most one suggested retry value (typically `operator`). It MUST NOT carry the agent's full permitted-billing subset, the agent's other commercial state (rate cards, payment terms, credit limit, billing entity), or any per-account state — those are commercial-state oracles. Sellers MUST NOT add ad-hoc keys to this object: any field carrying per-agent commercial state is forbidden, even if `additionalProperties` would permit it. The recovery contract is: if `suggested_billing` is present, the agent MAY retry autonomously with that value; if absent, the rejection is terminal-pending-onboarding and the agent MUST surface to a human at the buyer to complete payments-relationship onboarding with the seller offline.",
  "type": "object",
  "properties": {
    "rejected_billing": {
      "$ref": "/schemas/3.1.0/enums/billing-party.json",
      "description": "The `billing` value the seller rejected — echoed verbatim from the request for caller-side reconciliation."
    },
    "suggested_billing": {
      "$ref": "/schemas/3.1.0/enums/billing-party.json",
      "description": "A single billing value the calling buyer agent MAY retry with autonomously. Typically `operator` for passthrough-only agents. Sellers MAY omit this field when no retryable value exists for this agent's commercial relationship — in that case the rejection is terminal-pending-onboarding and the buyer MUST complete offline payments-relationship onboarding before any value other than the original request will succeed. Sellers MUST NOT populate this field with the full subset of values the agent may use; the field surfaces at most one canonical retry."
    }
  },
  "required": [
    "rejected_billing"
  ],
  "additionalProperties": false,
  "examples": [
    {
      "rejected_billing": "agent",
      "suggested_billing": "operator"
    },
    {
      "rejected_billing": "advertiser"
    }
  ]
} as const;

export const errorDetails_BillingNotSupported = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/error-details/billing-not-supported.json",
  "title": "Billing Not Supported Details",
  "description": "Recommended details shape for BILLING_NOT_SUPPORTED errors. Returned when the seller declines the requested `billing` value either at the seller-wide capability level or at the per-account-relationship level. The shape lets callers dispatch on the gate that fired without parsing prose. The `scope` field MUST be omitted when the seller is responding on the unauthenticated/unestablished-identity path required by the uniform-response rule for `BILLING_NOT_PERMITTED_FOR_AGENT` — emitting `scope: \"account\"` to a caller whose agent identity is not established would itself act as a per-account-relationship oracle (same shape the uniform-response rule closes for the per-agent code).",
  "type": "object",
  "properties": {
    "scope": {
      "type": "string",
      "enum": [
        "capability",
        "account"
      ],
      "description": "Which gate fired. `\"capability\"` — the seller's `supported_billing` capability does not include the requested value (advice: choose from `supported_billing` and retry). `\"account\"` — the seller's capability accepts the value generally but not for the specific operator on this account (advice: try the next-most-permissive value the capability allows). Registered subset of the shared discriminator vocabulary in `enums/error-scope.json` — the per-agent scope is reserved for `BILLING_NOT_PERMITTED_FOR_AGENT` (which carries no explicit `scope` field) and for `PERMISSION_DENIED` with `error-details/agent-permission-denied.json`. Sellers MUST omit this field when the response is being returned to a caller whose agent identity has not been established (signed-request derivation or credential-to-agent mapping); see the uniform-response requirement in error-handling.mdx Billing and Account Setup."
    },
    "supported_billing": {
      "type": "array",
      "description": "Echoed copy of the seller's `supported_billing` capability for the caller's convenience — saves a `get_adcp_capabilities` round-trip when `scope` is `\"capability\"`. Sellers MAY omit this field; callers MUST treat absence as \"call `get_adcp_capabilities`\" rather than \"any value is permitted.\"",
      "items": {
        "$ref": "/schemas/3.1.0/enums/billing-party.json"
      },
      "minItems": 1
    }
  },
  "additionalProperties": true,
  "examples": [
    {
      "scope": "capability",
      "supported_billing": [
        "operator",
        "agent"
      ]
    },
    {
      "scope": "account"
    }
  ]
} as const;

