export const formats_Canonical__base = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/formats/canonical/_base.json",
  "title": "Canonical Format Base",
  "description": "Shared parameter fields that apply across canonical formats. Each canonical format extends this base with format-specific parameters (dimensions, durations, codecs, slot constraints).",
  "type": "object",
  "properties": {
    "experimental": {
      "type": "boolean",
      "default": false,
      "description": "When true, this canonical (or a seller's specific narrowing of it) may not work as declared — adopters SHOULD have a v1 fallback ready and SHOULD NOT route production budget without testing. Same semantics as `experimental` on protocols: 'this is shipping but may break, evolve, or fail.' Buyers reading `experimental: true` SHOULD prefer the v1 path when a v1 fallback exists for the same product (via `format_ids` on the parent product or via the v2 declaration's `v1_format_ref`).\n\nThree drivers of `experimental: true`:\n1. **Spec maturity** — the canonical's tracking model or parameter shape is still being settled (`agent_placement`'s tracking macros, `sponsored_placement`'s per-adapter contracts, `responsive_creative`'s algorithmic composition).\n2. **Adopter runtime gap** — the seller has declared the canonical in their catalog but their runtime doesn't yet honor it cleanly.\n3. **Custom shapes** — `format_kind: \"custom\"` is inherently experimental until the working group promotes a `format_shape` to a first-class canonical.\n\nReplaces the earlier `status` enum (`stable | preview | deprecated`) + `runtime_status` enum (`stable | preview | declared_only`) — two axes with subtle overlap. The single boolean is what buyers actually care about: do I treat this as production-stable or as 'try at my own risk.' Sellers SHOULD set `experimental: true` on canonicals or product declarations that aren't yet production-ready, regardless of which axis (spec, runtime, custom) drives the experimentation. The 9 non-experimental canonicals at 3.1 GA (`image`, `html5`, `display_tag`, `image_carousel`, `video_hosted`, `video_vast`, `audio_hosted`, `audio_daast`, `native_in_feed`) default to non-experimental at the canonical level; sellers MAY still mark a specific product declaration experimental (e.g., a beta runtime path for an existing product)."
    },
    "deprecated": {
      "type": "boolean",
      "default": false,
      "description": "When true, this canonical (or a seller's specific narrowing of it) is going away. Existing adopters are supported through the deprecation cycle; new adoption is discouraged. Pair with `migration_target_version` to indicate when the canonical is expected to be removed. Distinct from `experimental`: an experimental canonical may stabilize and stop being experimental; a deprecated canonical is on a sunset path."
    },
    "v1_translatable": {
      "type": "boolean",
      "default": true,
      "description": "Whether this canonical has any v1 named-format equivalent. `true` (default) — the canonical is structurally expressible as one or more v1 named formats (IAB display sizes, VAST tags, DAAST tags, etc.); v1→v2 projection via `v1-canonical-mapping.json` is meaningful. `false` — the canonical is inherently new in v2 and has no v1 form; v1's `list_creative_formats` couldn't express it because the underlying concept (algorithmic surface composition, AI-surface mentions, retail-media catalog placements, multi-card carousels) didn't exist as a v1 named-format archetype.\n\nLets SDKs distinguish two failure modes that today look identical: (a) the registry hasn't covered this canonical yet (correctable — seller adds explicit `canonical` field or files a registry entry) vs (b) no v1 path is possible (informational — buyer needs v2-aware consumption, or seller declares `canonical_formats_only: true` on the product declaration). SDKs encountering `v1_translatable: false` on a canonical SHOULD NOT emit `FORMAT_PROJECTION_FAILED` (which signals registry-coverage gap) — instead surface the inherent v1-unreachability as a different diagnostic or skip silently. The 4 inherently-v2 canonicals at 3.1 GA: `image_carousel`, `sponsored_placement`, `responsive_creative`, `agent_placement`."
    },
    "since_version": {
      "type": "string",
      "pattern": "^[1-9]\\d*\\.(0|[1-9]\\d*)$",
      "description": "AdCP MAJOR.MINOR version that introduced this canonical (e.g., '3.1', '3.2'). Lets adopters reason about minimum protocol version requirements when consuming a format declaration. Patch precision is intentionally rejected — canonicals are introduced at minor-version boundaries."
    },
    "migration_target_version": {
      "type": "string",
      "pattern": "^[1-9]\\d*\\.(0|[1-9]\\d*)$",
      "description": "AdCP MAJOR.MINOR version by which the working group expects this canonical to stabilize, surface a breaking revision, or (when `deprecated: true`) be removed. Patch precision is intentionally rejected — canonicals shift at minor-version boundaries. Absence signals 'no specific target' (omit the field rather than use a placeholder like 'unknown')."
    },
    "composition_model": {
      "type": "string",
      "enum": [
        "deterministic",
        "algorithmic"
      ],
      "description": "Whether the surface composes deterministically (buyer can predict per-slot rendering — sponsored_placement, image, video) or algorithmically (surface chooses combinations or phrasing — responsive_creative, agent_placement)."
    },
    "provenance_required": {
      "type": "boolean",
      "description": "When true, the product rejects unsigned synthesized assets. Builders calling build_creative MUST attach a C2PA-compatible provenance manifest attributing synthesis to the creative agent."
    },
    "platform_extensions": {
      "type": "array",
      "description": "Platform-specific extensions narrowing the canonical (pixel ID shapes, conversion event taxonomies, platform-specific CTAs/destinations). Each extension is a URI+digest reference resolved against the bundled `extensions` map in get_products responses or fetched directly.\n\n**Collision precedence (normative).** When two or more `platform_extensions[]` entries on the same declaration extend the same target (e.g., both extend `tracking`) with overlapping field names, **array order is authoritative — later entries override earlier ones on a per-field basis** (last-in-array-wins). SDKs MUST surface the overlap via the `errors[]` array on the `get_products` response with a structured code (`FORMAT_DECLARATION_DIVERGENT` is appropriate when the overlap appears across dual-emitted shapes; a producer-self-emitted overlap on a single declaration SHOULD use the same code with `error.details: { collision_kind: \"platform_extension_field\", target, overlapping_fields, winning_extension_uri }`). Producers SHOULD avoid the collision by emitting one extension per target or by partitioning fields across extensions; the deterministic precedence is for last-resort consistency across SDK implementations, not a sanctioned merging strategy.",
      "items": {
        "$ref": "/schemas/3.1.0/core/platform-extension-ref.json"
      }
    },
    "synthesis_nondeterministic": {
      "type": "boolean",
      "description": "When true, the format's production pipeline is genuinely nondeterministic — the platform cannot guarantee that synthesis from a given input set produces in-spec output. Veo / Sora / Runway-class generative video, and other AI-synthesis flows where output dimensions, duration, or quality vary per run. Implies a different validation contract: predictive `validate_input` is impossible; the platform's own post-synthesis QA loop applies; if the QA loop exhausts without producing a valid artifact, `build_creative` returns task_failed with a synthesis_failed reason. Distinct from `composition_model` (which describes how the surface composes per-slot rendering, not whether synthesis is deterministic). When false or absent, the format's production is predictable enough that `validate_input` can predict output properties from input properties.\n\n**Compatibility with `asset_source` / `item_production_model`**: `synthesis_nondeterministic: true` MAY pair with any of `seller_pre_rendered_from_brief`, `seller_human_designed`, or `agent_synthesized` (the QA loop is concept-level, not source-specific — 'seller renders from brief but each retry differs' is just as nondeterministic as Veo). It MUST NOT pair with `buyer_uploaded` (the buyer ships pre-rendered bytes; there's no synthesis step to be nondeterministic about). It MUST NOT pair with `publisher_host_recorded` (the publisher's host produces a deterministic-from-script output even if the human voice varies). When `synthesis_nondeterministic: true` is set with an incompatible source, validators SHOULD reject with a structured error.",
      "default": false
    },
    "slots": {
      "type": "array",
      "description": "Programmatic declaration of which canonical asset_group_id slots a manifest targeting this format must (or may) populate. Lets SDK codegen and validators enumerate expected slots without parsing the format's prose description. Each entry references an asset_group_id from the canonical vocabulary registry, paired with an `asset_type` so the validator knows which asset schema to apply. Format-level narrowing parameters that apply across all slots (e.g., flat `headline_max_chars` on responsive_creative) may also live on the format declaration; per-slot constraints (a specific slot's `max_chars` or `max_size_kb`) live on the slot entry.",
      "items": {
        "type": "object",
        "required": [
          "asset_group_id",
          "asset_type"
        ],
        "properties": {
          "asset_group_id": {
            "type": "string",
            "description": "Canonical asset_group_id from /schemas/core/asset-group-vocabulary.json. Non-canonical IDs are valid but trigger soft warnings."
          },
          "asset_type": {
            "type": "string",
            "enum": [
              "image",
              "video",
              "audio",
              "text",
              "markdown",
              "url",
              "html",
              "css",
              "javascript",
              "vast",
              "daast",
              "webhook",
              "brief",
              "catalog",
              "published_post",
              "zip",
              "card",
              "object",
              "pixel_tracker",
              "vast_tracker",
              "daast_tracker"
            ],
            "description": "Discriminator selecting the asset schema this slot accepts. SDK codegen uses this to type the slot value. `published_post` is an existing-post reference asset, not uploaded media bytes and not a catalog row. `card` is the multi-card carousel element type (see card-asset.json). `pixel_tracker` / `vast_tracker` / `daast_tracker` are the renderer-fired measurement-tracker primitives — see `/schemas/core/assets/pixel-tracker-asset.json` and the VAST / DAAST tracker schemas. `object` is a last-resort fallback for structured non-asset inputs that don't fit any primitive asset_type — prefer specific types whenever possible."
          },
          "required": {
            "type": "boolean",
            "description": "Whether this slot is required for a valid manifest.",
            "default": false
          },
          "min": {
            "type": "integer",
            "minimum": 0,
            "description": "Minimum count for repeatable / pool slots."
          },
          "max": {
            "type": "integer",
            "minimum": 1,
            "description": "Maximum count for repeatable / pool slots."
          },
          "max_chars": {
            "type": "integer",
            "minimum": 1,
            "description": "Per-slot character limit. Valid only when `asset_type` is `text`, `markdown`, or `brief`. Mutually exclusive with `max_size_kb` (which applies to binary asset types). Schema enforces via if/then so a producer can't set both on the same slot."
          },
          "max_size_kb": {
            "type": "integer",
            "minimum": 1,
            "description": "Per-slot file size limit in kilobytes. Valid only when `asset_type` is `image`, `video`, `audio`, or `zip`. Mutually exclusive with `max_chars` (which applies to text asset types). Schema enforces via if/then so a producer can't set both on the same slot."
          },
          "logo_slots": {
            "type": "array",
            "items": {
              "$ref": "/schemas/3.1.0/enums/logo-slot.json"
            },
            "uniqueItems": true,
            "description": "When `asset_group_id` is `logo`, renderer-facing brand.json logo slots acceptable for this format slot. Producers selecting from brand.json SHOULD prefer `logos[]` entries whose `slots[]` intersects this list, then apply `visual_guidelines.logo_usage_rules[]`."
          },
          "required_logo_slots": {
            "type": "array",
            "items": {
              "$ref": "/schemas/3.1.0/enums/logo-slot.json"
            },
            "uniqueItems": true,
            "description": "Subset of `logo_slots` for which this format expects explicit logo coverage. A manifest or brand-derived logo pool SHOULD include at least one usable logo for each required slot; if coverage is missing, builders SHOULD surface a validation warning or approval mapping instead of guessing from prose."
          },
          "description": {
            "type": "string",
            "description": "Human-readable description of what the slot expects from the buyer."
          },
          "consumed_for_production": {
            "type": "boolean",
            "default": false,
            "description": "Dispatch hint for `build_creative` and v1↔v2 wire translators: when `true`, the slot's value is consumed as INPUT to a production step (host-read script, brief copy fed to generative synthesis, catalog feed driving per-SKU rendering) and is not rendered verbatim. When `false` (default), the slot's value is rendered verbatim on the placement (image bytes, video file, display tag).\n\nMotivates the v1↔v2 dispatch table: pre-v2 buyers shipped production-consumed inputs separately in a `inputs` map on the build_creative request; v2 collapses inputs and rendered assets into a single `assets` map keyed by `asset_group_id`. SDK translators between v1 and v2 use this flag per canonical to know which assets in the v2 manifest map back to v1 `inputs` vs v1 `assets`. Without the per-slot flag the dispatch table lives in adopter code and every SDK gets it slightly different.\n\nProducers SHOULD set this explicitly on slots whose consumption pattern isn't obvious (host-read scripts on `audio_hosted`, briefs on generative `video_hosted`, catalog feeds on `sponsored_placement`). For canonicals where every slot is render-verbatim (`image`, `display_tag`, `video_vast`), the default `false` is sufficient and the flag MAY be omitted."
          }
        },
        "additionalProperties": true,
        "allOf": [
          {
            "$comment": "max_chars is valid only for text-shaped asset types; max_size_kb is valid only for binary asset types. A slot MUST NOT carry both; the type-appropriate one is enforced via if/then.",
            "if": {
              "properties": {
                "asset_type": {
                  "enum": [
                    "text",
                    "markdown",
                    "brief"
                  ]
                }
              },
              "required": [
                "asset_type"
              ]
            },
            "then": {
              "not": {
                "required": [
                  "max_size_kb"
                ]
              }
            }
          },
          {
            "if": {
              "properties": {
                "asset_type": {
                  "enum": [
                    "image",
                    "video",
                    "audio",
                    "zip"
                  ]
                }
              },
              "required": [
                "asset_type"
              ]
            },
            "then": {
              "not": {
                "required": [
                  "max_chars"
                ]
              }
            }
          },
          {
            "$comment": "Logo slot narrowing is only meaningful on the canonical logo asset group.",
            "if": {
              "not": {
                "properties": {
                  "asset_group_id": {
                    "const": "logo"
                  }
                },
                "required": [
                  "asset_group_id"
                ]
              }
            },
            "then": {
              "not": {
                "anyOf": [
                  {
                    "required": [
                      "logo_slots"
                    ]
                  },
                  {
                    "required": [
                      "required_logo_slots"
                    ]
                  }
                ]
              }
            }
          },
          {
            "$comment": "Non-size asset types (url, catalog, published_post, html, css, javascript, webhook, daast, vast, card, object, pixel_tracker, vast_tracker, daast_tracker) reject both — there's no defined per-slot size semantics on those.",
            "if": {
              "properties": {
                "asset_type": {
                  "enum": [
                    "url",
                    "catalog",
                    "published_post",
                    "html",
                    "css",
                    "javascript",
                    "webhook",
                    "daast",
                    "vast",
                    "card",
                    "object",
                    "pixel_tracker",
                    "vast_tracker",
                    "daast_tracker"
                  ]
                }
              },
              "required": [
                "asset_type"
              ]
            },
            "then": {
              "not": {
                "anyOf": [
                  {
                    "required": [
                      "max_chars"
                    ]
                  },
                  {
                    "required": [
                      "max_size_kb"
                    ]
                  }
                ]
              }
            }
          }
        ]
      }
    },
    "required_connections": {
      "type": "array",
      "items": {
        "$ref": "/schemas/3.1.0/core/downstream-connection-requirement.json"
      },
      "description": "Downstream platform connections or grants required to use this format declaration. These are in addition to the single AdCP caller credential. Use this when a platform product requires multiple downstream grants, such as an advertiser account connection plus a publisher identity or post authorization for published-post references."
    },
    "reference_mutability": {
      "type": "string",
      "enum": [
        "immutable_snapshot",
        "mutable_requires_reapproval",
        "mutable_auto_recheck"
      ],
      "description": "Policy for formats whose `slots` accept a `published_post` reference. `immutable_snapshot`: seller snapshots the referenced post at approval and later source changes do not change the served creative. `mutable_requires_reapproval`: the source post may change and material changes require review before continued serving. `mutable_auto_recheck`: the source post may change and the seller continuously or periodically rechecks authorization/policy without requiring buyer resubmission. Omit when the format has no `published_post` slot."
    },
    "production_window_business_days": {
      "type": "integer",
      "minimum": 0,
      "description": "Typical production turnaround in business days when the format requires seller-side production (e.g., host-recording from a buyer-supplied script). 0 for synchronous (e.g., generative AI); >0 for human-produced (e.g., podcast host-read). Absent when no production is required (buyer uploads complete creative)."
    }
  },
  "additionalProperties": true,
  "x-canonical-policy-required-params-not-enforced": "Canonical format schemas intentionally do NOT mark any of their parameter fields as `required` and use `additionalProperties: true`. The canonical is the loose contract — describing what parameters MAY narrow it. Products narrow the canonical with concrete values (and may also leave most parameters absent — buyers infer behavior from the canonical's prose description for any unspecified parameter). This is intentional, not an oversight: enforcing required params on the canonical would force every product to declare every parameter, which is the wrong direction (we want products to declare only the values that differ from sensible canonical defaults). Adopters writing strict validators should validate against the canonical's structural shape (what fields ARE valid) and apply business rules separately for product-level narrowing minima."
} as const;

export const governance_AttributeDefinition = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/governance/attribute-definition.json",
  "title": "Attribute Definition",
  "description": "Definition of a restricted personal data attribute in the policy registry. Attributes are the shared vocabulary used across campaign plans (restricted_attributes), signal definitions (restricted_attributes), and data marketplace catalogs. Each definition documents the regulatory basis, scope, and common signal patterns for the attribute category.",
  "type": "object",
  "properties": {
    "attribute_id": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9_]*$",
      "description": "Unique identifier for this attribute. Used in plan.restricted_attributes, signal-definition.restricted_attributes, and data marketplace catalog entries."
    },
    "name": {
      "type": "string",
      "description": "Human-readable name (e.g., 'Health Data')."
    },
    "description": {
      "type": "string",
      "description": "What this attribute category covers. Defines the boundary — what is and is not included."
    },
    "regulatory_basis": {
      "type": "array",
      "description": "Regulations that define or restrict this attribute category.",
      "items": {
        "type": "object",
        "properties": {
          "name": {
            "type": "string",
            "description": "Name of the regulation (e.g., 'GDPR Article 9(1)')."
          },
          "jurisdictions": {
            "type": "array",
            "items": {
              "type": "string"
            },
            "description": "ISO 3166-1 alpha-2 codes where this regulation applies."
          },
          "summary": {
            "type": "string",
            "description": "How this regulation defines or restricts the attribute."
          }
        },
        "required": [
          "name",
          "summary"
        ],
        "additionalProperties": false
      }
    },
    "includes": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Specific data types that fall within this category (e.g., for health_data: 'medical conditions', 'disability status', 'prescription history', 'inferred health from behavioral signals')."
    },
    "excludes": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Data types that might seem related but are explicitly outside this category. Helps with boundary cases."
    },
    "signal_patterns": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Common signal naming or tagging patterns that indicate this attribute (e.g., 'health:', 'condition_', 'diagnosis_'). Data providers and governance agents use these as hints when signals lack explicit restricted_attributes declarations."
    },
    "guidance": {
      "type": "string",
      "description": "Implementation notes. Covers edge cases, inferred vs. declared data, and common pitfalls."
    }
  },
  "required": [
    "attribute_id",
    "name",
    "description"
  ],
  "additionalProperties": false
} as const;

export const governance_AudienceConstraints = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/governance/audience-constraints.json",
  "title": "Audience Constraints",
  "description": "Buyer-defined audience targeting constraints for a campaign plan. Specifies who the campaign should and should not reach. The governance agent evaluates seller targeting against these constraints during check_governance.",
  "type": "object",
  "properties": {
    "include": {
      "type": "array",
      "description": "Desired audience criteria. The seller's targeting should align with these. Each criterion is evaluated independently — the combined targeting should satisfy at least one inclusion criterion.",
      "items": {
        "$ref": "/schemas/3.1.0/core/audience-selector.json"
      },
      "minItems": 1
    },
    "exclude": {
      "type": "array",
      "description": "Excluded audience criteria. The seller's targeting must not overlap with these. Exclusions take precedence over inclusions. Used for protected groups, vulnerable communities, regulatory restrictions, or brand safety.",
      "items": {
        "$ref": "/schemas/3.1.0/core/audience-selector.json"
      },
      "minItems": 1
    }
  },
  "minProperties": 1,
  "additionalProperties": false
} as const;

export const governance_CheckGovernanceRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/governance/check-governance-request.json",
  "title": "Check Governance Request",
  "description": "Universal governance check for campaign actions. The governance agent infers the check type from the fields present: tool+payload = intent check (proposed, orchestrator-side). planned_delivery = execution check (committed, seller-side). governance_context maintains lifecycle continuity across either check type — its presence alone does not determine binding. To check budget availability without a specific action, omit tool and payload.",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    }
  ],
  "x-status": "experimental",
  "properties": {
    "plan_id": {
      "type": "string",
      "description": "Campaign governance plan identifier. The plan uniquely scopes the account and operator; do not include a separate `account` field — the governance agent resolves account from the plan. Governance agents MUST treat any sibling `account` field as a contract violation and reject the request.",
      "x-entity": "governance_plan"
    },
    "caller": {
      "type": "string",
      "format": "uri",
      "description": "URL of the agent making the request."
    },
    "purchase_type": {
      "$ref": "/schemas/3.1.0/enums/purchase-type.json",
      "description": "The type of financial commitment being checked. Determines which budget allocation (if any) to validate against. Defaults to 'media_buy' when omitted.",
      "default": "media_buy"
    },
    "tool": {
      "type": "string",
      "description": "The AdCP tool being checked (e.g., 'create_media_buy', 'acquire_rights', 'activate_signal'). Present on intent checks (orchestrator). The governance agent uses the presence of tool+payload to identify an intent check."
    },
    "payload": {
      "type": "object",
      "description": "The full tool arguments as they would be sent to the seller. Present on intent checks. The governance agent can inspect any field to validate against the plan.",
      "x-adcp-open-payload": true,
      "additionalProperties": true
    },
    "governance_context": {
      "type": "string",
      "description": "Governance context token from a prior check_governance response. Pass this on subsequent checks for the same governed action so the governance agent can maintain continuity across the lifecycle. In 3.0 governance agents MUST emit a compact JWS per the AdCP JWS profile (see Security — Signed Governance Context); callers persist and forward the value verbatim.",
      "minLength": 1,
      "maxLength": 4096,
      "pattern": "^[\\x20-\\x7E]+$"
    },
    "phase": {
      "$ref": "/schemas/3.1.0/enums/governance-phase.json",
      "description": "The phase of the governed action's lifecycle. 'purchase': initial commitment (create_media_buy, acquire_rights, activate_signal). 'modification': update to existing commitment. 'delivery': periodic delivery or usage reporting. Defaults to 'purchase' if omitted.",
      "default": "purchase"
    },
    "planned_delivery": {
      "$ref": "/schemas/3.1.0/core/planned-delivery.json",
      "description": "What the seller will actually deliver. Present on execution checks."
    },
    "delivery_metrics": {
      "type": "object",
      "description": "Actual delivery performance data. MUST be present for 'delivery' phase. The governance agent compares these metrics against the planned delivery to detect drift.",
      "properties": {
        "reporting_period": {
          "type": "object",
          "description": "Start and end timestamps for the reporting window.",
          "properties": {
            "start": {
              "type": "string",
              "format": "date-time"
            },
            "end": {
              "type": "string",
              "format": "date-time"
            }
          },
          "required": [
            "start",
            "end"
          ],
          "additionalProperties": false
        },
        "spend": {
          "type": "number",
          "minimum": 0,
          "description": "Total spend during the reporting period."
        },
        "cumulative_spend": {
          "type": "number",
          "minimum": 0,
          "description": "Total spend since the governed action started."
        },
        "impressions": {
          "type": "integer",
          "minimum": 0,
          "description": "Impressions delivered during the reporting period."
        },
        "cumulative_impressions": {
          "type": "integer",
          "minimum": 0,
          "description": "Total impressions since the governed action started."
        },
        "geo_distribution": {
          "type": "object",
          "description": "Actual geographic distribution. Keys are ISO 3166-1 alpha-2 codes, values are percentages.",
          "additionalProperties": {
            "type": "number",
            "minimum": 0,
            "maximum": 100
          }
        },
        "channel_distribution": {
          "type": "object",
          "description": "Actual channel distribution. Keys are channel enum values, values are percentages.",
          "additionalProperties": {
            "type": "number",
            "minimum": 0,
            "maximum": 100
          }
        },
        "pacing": {
          "type": "string",
          "enum": [
            "ahead",
            "on_track",
            "behind"
          ],
          "description": "Whether delivery is ahead of, on track with, or behind the planned pace."
        },
        "audience_distribution": {
          "type": "object",
          "description": "Actual audience composition during the reporting period. Enables mid-flight drift detection when actual delivery skews from planned audience targeting.",
          "properties": {
            "baseline": {
              "type": "string",
              "enum": [
                "census",
                "platform",
                "custom"
              ],
              "description": "Population baseline used for index calculation. 'census': national census or equivalent population data. 'platform': the seller's active user base. 'custom': a custom baseline defined by the seller (describe in baseline_description)."
            },
            "baseline_description": {
              "type": "string",
              "description": "Description of the baseline when baseline is 'custom' (e.g., 'US adults 18+ with broadband access')."
            },
            "indices": {
              "type": "object",
              "description": "Audience index values for the current reporting period. Keys are seller-defined dimension:value strings (e.g., 'age:25-34', 'gender:female', 'income:high'). The protocol does not mandate a taxonomy — dimensions and value labels vary by seller. Values are index relative to the declared baseline (1.0 = at parity, >1.0 = over-indexed, <1.0 = under-indexed).",
              "propertyNames": {
                "pattern": "^[a-z_]+:.+$"
              },
              "additionalProperties": {
                "type": "number",
                "minimum": 0
              }
            },
            "cumulative_indices": {
              "type": "object",
              "description": "Cumulative audience index values since the governed action started. Same key format as indices (dimension:value). Use for detecting sustained bias drift that may not appear in a single reporting period.",
              "propertyNames": {
                "pattern": "^[a-z_]+:.+$"
              },
              "additionalProperties": {
                "type": "number",
                "minimum": 0
              }
            }
          },
          "required": [
            "baseline",
            "indices"
          ],
          "additionalProperties": false
        }
      },
      "required": [
        "reporting_period"
      ],
      "additionalProperties": false
    },
    "modification_summary": {
      "type": "string",
      "description": "Human-readable summary of what changed. SHOULD be present for 'modification' phase.",
      "maxLength": 1000
    },
    "invoice_recipient": {
      "$ref": "/schemas/3.1.0/core/business-entity.json",
      "description": "Invoice recipient from the purchase request. MUST be present when the tool payload includes invoice_recipient, so the governance agent can validate billing changes."
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "plan_id",
    "caller"
  ],
  "additionalProperties": true
} as const;

export const governance_CheckGovernanceResponse = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/governance/check-governance-response.json",
  "title": "Check Governance Response",
  "description": "Governance agent's response to a check request. Returns whether the action is approved under the governance plan.",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    },
    {
      "if": {
        "properties": {
          "verdict": {
            "const": "conditions"
          }
        },
        "required": [
          "verdict"
        ]
      },
      "then": {
        "required": [
          "conditions"
        ],
        "properties": {
          "conditions": {
            "minItems": 1
          }
        }
      }
    },
    {
      "if": {
        "properties": {
          "verdict": {
            "const": "denied"
          }
        },
        "required": [
          "verdict"
        ]
      },
      "then": {
        "required": [
          "findings"
        ],
        "properties": {
          "findings": {
            "minItems": 1
          }
        }
      }
    },
    {
      "if": {
        "properties": {
          "verdict": {
            "enum": [
              "approved",
              "conditions"
            ]
          }
        },
        "required": [
          "verdict"
        ]
      },
      "then": {
        "required": [
          "expires_at"
        ]
      }
    }
  ],
  "x-status": "experimental",
  "properties": {
    "check_id": {
      "type": "string",
      "description": "Unique identifier for this governance check record. Use in report_plan_outcome to link outcomes to the check that authorized them.",
      "x-entity": "governance_check"
    },
    "verdict": {
      "$ref": "/schemas/3.1.0/enums/governance-decision.json",
      "description": "Governance verdict: approved | denied | conditions. Renamed from `status` in 3.1 to free the top-level `status` key for the envelope task-status (TaskStatus) under MCP flat-on-the-wire serialization. The enum values are unchanged; only the property name moved."
    },
    "plan_id": {
      "type": "string",
      "description": "Echoed from request.",
      "x-entity": "governance_plan"
    },
    "explanation": {
      "type": "string",
      "description": "Human-readable explanation of the governance decision."
    },
    "findings": {
      "type": "array",
      "description": "Specific issues found during the governance check. Present when verdict is 'denied' or 'conditions'. MAY also be present on 'approved' for informational findings (e.g., budget approaching limit).",
      "items": {
        "type": "object",
        "properties": {
          "category_id": {
            "type": "string",
            "description": "Validation category that flagged the issue (e.g., 'budget_compliance', 'regulatory_compliance', 'brand_safety'). This is an **agent-internal** taxonomy: the string is defined by the governance agent's own policy model and is not constrained to any protocol-level enum. Sellers and buyers MUST NOT pattern-match `category_id` values against a fixed list — treat them as opaque labels with human-readable significance for audit but no machine-level contract. See the Campaign Governance specification for how an agent composes internal specialist review behind one endpoint."
          },
          "policy_id": {
            "type": "string",
            "description": "ID of the policy that triggered this finding. May reference a registry policy (with source: registry) or a bespoke inline policy (with source: inline). Bespoke policy_ids are unique within their authoring container; use source_plan_id when findings aggregate across multiple plans (e.g., portfolio evaluations). When the violation traces to a producer-tagged surface (feature-requirement, creative-feature-result, or validation-result feature) carrying policy_id, governance agents SHOULD echo that policy_id here for end-to-end traceability, and MUST NOT invent a policy_id that wasn't present on the originating surface. See /docs/governance/policy-attribution.",
            "$comment": "x-entity deliberately omitted — a finding's policy_id can reference EITHER a governance_registry_policy or a governance_inline_policy depending on which policy matched. Resolution requires a sibling source discriminator the lint can't see from this leaf. Storyboards that capture from findings must re-annotate at the consume site (see #2685 for the registry/inline split)."
          },
          "source_plan_id": {
            "type": "string",
            "description": "For portfolio or aggregated evaluations where findings draw on bespoke policies from multiple member plans: identifies the plan whose policy triggered this finding. Omit when the finding's policy_id is unambiguous within the response context (e.g., single-plan check_governance).",
            "x-entity": "governance_plan"
          },
          "severity": {
            "$ref": "/schemas/3.1.0/enums/escalation-severity.json"
          },
          "explanation": {
            "type": "string",
            "description": "Human-readable description of the issue."
          },
          "details": {
            "type": "object",
            "description": "Structured details for programmatic consumption.",
            "additionalProperties": true
          },
          "confidence": {
            "type": "number",
            "minimum": 0,
            "maximum": 1,
            "description": "Confidence score (0-1) in this finding. Distinguishes 'this definitely violates the policy' (0.95) from 'this might violate depending on how audience segments resolve' (0.6). When absent, the finding is presented without a confidence qualifier."
          },
          "uncertainty_reason": {
            "type": "string",
            "description": "Explanation of why confidence is below 1.0 (e.g., 'Targeting includes regions that partially overlap jurisdiction boundaries'). Present when confidence is below a governance-agent-defined threshold."
          }
        },
        "required": [
          "category_id",
          "severity",
          "explanation"
        ],
        "additionalProperties": false
      }
    },
    "conditions": {
      "type": "array",
      "description": "Present when verdict is 'conditions'. Specific adjustments the caller must make. After applying conditions, the caller MUST re-call check_governance with the adjusted parameters before proceeding.",
      "items": {
        "type": "object",
        "properties": {
          "field": {
            "type": "string",
            "description": "Dot-path to the field that needs adjustment (in payload for proposed, in planned_delivery for committed)."
          },
          "required_value": {
            "description": "The value the field must have for approval. When present, the condition is machine-actionable. When absent, the condition is advisory."
          },
          "reason": {
            "type": "string",
            "description": "Why this condition is required."
          }
        },
        "required": [
          "field",
          "reason"
        ],
        "additionalProperties": false
      }
    },
    "expires_at": {
      "type": "string",
      "format": "date-time",
      "description": "When this approval expires. Present when verdict is 'approved' or 'conditions'. The caller must act before this time or re-call check_governance. A lapsed approval is no approval."
    },
    "next_check": {
      "type": "string",
      "format": "date-time",
      "description": "When the seller should next call check_governance with delivery metrics. Present when the governance agent expects ongoing delivery reporting."
    },
    "categories_evaluated": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Governance categories evaluated during this check. Each value is an **agent-internal** label (e.g., `budget_authority`, `regulatory_compliance`, or any internal-reviewer key the agent's policy model defines) — not a protocol-level enum. Since one governance agent per account composes all specialist review behind its single endpoint, `categories_evaluated` is how that internal decomposition surfaces to auditors. Consumers MUST treat values as opaque labels for display and audit, not as a machine-level contract."
    },
    "policies_evaluated": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Policy IDs evaluated during this check. Includes registry policy IDs (resolved via the policy registry) and any inline `policy_id`s declared in the plan's `custom_policies`."
    },
    "mode": {
      "$ref": "/schemas/3.1.0/enums/governance-mode.json",
      "description": "Governance enforcement mode active when this check was evaluated. Allows counterparties, regulators, and auditors to distinguish whether a finding blocked execution (enforce) or was logged silently (audit)."
    },
    "governance_context": {
      "type": "string",
      "description": "Governance context token for this governed action. The buyer MUST attach this to the protocol envelope when sending the purchase request (media buy, rights acquisition, signal activation) to the seller. The seller MUST persist it and include it on all subsequent check_governance calls for this action's lifecycle.\n\nValue format: in 3.0 governance agents MUST emit a compact JWS per the AdCP JWS profile (see Security — Signed Governance Context). Sellers MAY verify; sellers that do not verify MUST persist and forward the token unchanged so auditors can verify downstream. In 3.1 all sellers MUST verify per the checklist. Non-JWS values from pre-3.0 governance agents are deprecated and will be rejected in 3.1.\n\nSellers that implement verification MUST verify signature, `aud`, `exp`, `jti` replay, and revocation per the profile before treating the request as governance-approved. This is the primary correlation key for audit and reporting across the governance lifecycle — the governance agent decodes its own signed token to look up internal plan state (buyer correlation IDs, policy decision log, etc.).",
      "minLength": 1,
      "maxLength": 4096,
      "pattern": "^[\\x20-\\x7E]+$"
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "check_id",
    "verdict",
    "plan_id",
    "explanation"
  ],
  "additionalProperties": true
} as const;

