export const property_BasePropertySource = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/property/base-property-source.json",
  "title": "Base Property Source",
  "description": "A source of properties for a property list. Supports three selection patterns: publisher with tags, publisher with property IDs, or direct identifiers.",
  "discriminator": {
    "propertyName": "selection_type"
  },
  "oneOf": [
    {
      "type": "object",
      "title": "Publisher Tags Source",
      "description": "Select properties from a publisher by tag membership",
      "properties": {
        "selection_type": {
          "type": "string",
          "const": "publisher_tags",
          "description": "Discriminator indicating selection by property tags within a publisher"
        },
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted (e.g., 'raptive.com')",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "tags": {
          "type": "array",
          "description": "Property tags from the publisher's adagents.json. Selects all properties with these tags.",
          "items": {
            "$ref": "/schemas/3.1.0/core/property-tag.json"
          },
          "minItems": 1
        }
      },
      "required": [
        "selection_type",
        "publisher_domain",
        "tags"
      ],
      "additionalProperties": false
    },
    {
      "type": "object",
      "title": "Publisher Property IDs Source",
      "description": "Select specific properties from a publisher by ID",
      "properties": {
        "selection_type": {
          "type": "string",
          "const": "publisher_ids",
          "description": "Discriminator indicating selection by specific property IDs within a publisher"
        },
        "publisher_domain": {
          "type": "string",
          "description": "Domain where publisher's adagents.json is hosted (e.g., 'raptive.com')",
          "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$"
        },
        "property_ids": {
          "type": "array",
          "description": "Specific property IDs from the publisher's adagents.json",
          "items": {
            "$ref": "/schemas/3.1.0/core/property-id.json"
          },
          "minItems": 1
        }
      },
      "required": [
        "selection_type",
        "publisher_domain",
        "property_ids"
      ],
      "additionalProperties": false
    },
    {
      "type": "object",
      "title": "Direct Identifiers Source",
      "description": "Select properties by direct identifiers (domains, app IDs, etc.) without publisher context",
      "properties": {
        "selection_type": {
          "type": "string",
          "const": "identifiers",
          "description": "Discriminator indicating selection by direct identifiers"
        },
        "identifiers": {
          "type": "array",
          "description": "Direct property identifiers (domains, app IDs, etc.)",
          "items": {
            "$ref": "/schemas/3.1.0/core/identifier.json"
          },
          "minItems": 1
        }
      },
      "required": [
        "selection_type",
        "identifiers"
      ],
      "additionalProperties": false
    }
  ]
} as const;

export const property_CreatePropertyListRequest = {
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "/schemas/3.1.0/property/create-property-list-request.json",
  "title": "Create Property List Request",
  "description": "Request parameters for creating a new property list",
  "type": "object",
  "allOf": [
    {
      "$ref": "/schemas/3.1.0/core/version-envelope.json"
    }
  ],
  "x-mutates-state": true,
  "properties": {
    "account": {
      "$ref": "/schemas/3.1.0/core/account-ref.json",
      "description": "Account that will own the list. Pass a natural key (brand, operator, optional sandbox) or a seller-assigned account_id from list_accounts. When omitted, this task applies its task-local single-account shortcut: if exactly one account is accessible to the authenticated caller, the seller may assign the list to that account; otherwise it MUST return an account-required or ambiguous-account error. Omission MUST NOT mean an undocumented credential-local default account."
    },
    "name": {
      "type": "string",
      "description": "Human-readable name for the list"
    },
    "description": {
      "type": "string",
      "description": "Description of the list's purpose"
    },
    "base_properties": {
      "type": "array",
      "description": "Array of property sources to evaluate. Each entry is a discriminated union: publisher_tags (publisher_domain + tags), publisher_ids (publisher_domain + property_ids), or identifiers (direct identifiers). If omitted, queries the agent's entire property database.",
      "items": {
        "$ref": "/schemas/3.1.0/property/base-property-source.json"
      },
      "minItems": 1
    },
    "filters": {
      "$ref": "/schemas/3.1.0/property/property-list-filters.json",
      "description": "Dynamic filters to apply when resolving the list"
    },
    "brand": {
      "$ref": "/schemas/3.1.0/core/brand-ref.json",
      "description": "Brand reference. When provided, the agent automatically applies appropriate rules based on brand characteristics (industry, target_audience, etc.). Resolved at execution time."
    },
    "idempotency_key": {
      "type": "string",
      "description": "Client-generated unique key for this request. Prevents duplicate property list creation on retries. MUST be unique per (seller, request) pair to prevent cross-seller correlation. Use a fresh UUID v4 for each request.",
      "minLength": 16,
      "maxLength": 255,
      "pattern": "^[A-Za-z0-9_.:-]{16,255}$"
    },
    "context": {
      "$ref": "/schemas/3.1.0/core/context.json"
    },
    "ext": {
      "$ref": "/schemas/3.1.0/core/ext.json"
    }
  },
  "required": [
    "idempotency_key",
    "name"
  ],
  "additionalProperties": true
} as const;

